                    <h4 className="text-xs font-bold text-emerald-700 uppercase mb-3 flex items-center gap-2">
                        <Plus size={14} className="bg-emerald-100 p-0.5 rounded-full"/> Added Steps
                    </h4>
                    <div className="space-y-2">
