// --- DELEGATION FORM ---
export const DelegationFormView = () => {
  const { navigateTo, createDelegation, users, currentUser } = useBPM();
  const [targetId, setTargetId] = useState('');
  const [scope, setScope] = useState<'All' | 'Critical Only'>('All');

