        <div className="p-6 space-y-6 h-full overflow-y-auto">
            <div className="flex justify-between border-b border-default pb-4"><input className="text-xl font-bold bg-transparent outline-none" value={localTable.name} onChange={e => updateTable(d => {d.name = e.target.value})} /><div className="flex gap-2"><NexButton variant="danger" onClick={() => onDelete(table.id)} icon={Trash2}>Delete</NexButton><NexButton variant="primary" onClick={() => onSave(localTable)} icon={Save}>Save</NexButton></div></div>
            <div className="overflow-x-auto border border-default rounded-base shadow-sm"><table className="w-full text-xs text-left"><thead className="bg-subtle border-b border-default"><tr><th className="w-10 p-2"></th>{localTable.inputs.map((c, i) => <th key={i} className="p-2 border-r bg-blue-50/50">{c} (IN)</th>)}{localTable.outputs.map((c, i) => <th key={i} className="p-2 border-r bg-emerald-50/50">{c} (OUT)</th>)}</tr></thead><tbody className="divide-y divide-subtle bg-panel">{localTable.rules.map((row, rIdx) => <tr key={rIdx}><td className="p-2 text-center">{rIdx + 1}</td>{row.map((cell, cIdx) => <td key={cIdx} className="p-0 border-r relative"><input className="w-full p-2 outline-none bg-transparent" value={cell} onChange={e => updateTable(d => {d.rules[rIdx][cIdx] = e.target.value})} /></td>)}</tr>)}</tbody></table></div>
            <NexButton variant="secondary" onClick={() => updateTable(d => {d.rules.push(new Array(d.inputs.length+d.outputs.length).fill(''))})} icon={Plus} className="w-full border-dashed">Add Row</NexButton>
        </div>
    );
};

