export const RulesEngineView: React.FC = () => {
    const { rules, decisionTables, saveRule, deleteRule, saveDecisionTable, deleteDecisionTable, reseedSystem, navigateTo, setToolbarConfig } = useBPM();
    const { gridConfig } = useTheme();
    const [selectedAsset, setSelectedAsset] = useState<{type: 'rule' | 'table', id: string} | null>(null);
    const [search, setSearch] = useState('');
    const [isEditable, setIsEditable] = useState(false);

    // Layouts
    const defaultLayouts = {
        lg: [
            { i: 'library', x: 0, y: 0, w: 3, h: 20 },
            { i: 'editor', x: 3, y: 0, w: 6, h: 20 },
            { i: 'test', x: 9, y: 0, w: 3, h: 20 }
        ],
        md: [
            { i: 'library', x: 0, y: 0, w: 4, h: 10 },
            { i: 'test', x: 0, y: 10, w: 4, h: 10 },
            { i: 'editor', x: 4, y: 0, w: 6, h: 20 }
        ]
    };
    const [layouts, setLayouts] = useState(defaultLayouts);

    useEffect(() => {
        setToolbarConfig({
            view: [
                { label: isEditable ? 'Lock Layout' : 'Edit Layout', action: () => setIsEditable(!isEditable), icon: Settings },
                { label: 'Reset Layout', action: () => setLayouts(defaultLayouts) }
            ]
        });
    }, [setToolbarConfig, isEditable]);

    const createNew = (type: 'rule' | 'table') => {
        const id = `${type}-${Date.now()}`;
        if (type === 'rule') {
            const newRule: BusinessRule = { id, name: 'New Rule', description: '', conditions: { id: `g-${Date.now()}`, type: 'AND', children: [] }, action: { type: 'SET_VARIABLE', params: {} }, priority: 1, version: 1, status: 'Draft', tags: [], lastModified: new Date().toISOString() };
            saveRule(newRule); setSelectedAsset({type, id});
        } else {
            const newTable: DecisionTable = { id, name: 'New Table', inputs: ['In'], outputs: ['Out'], rules: [['', '']], version: 1, status: 'Draft', tags: [], lastModified: new Date().toISOString() };
            saveDecisionTable(newTable); setSelectedAsset({type, id});
        }
    };

    const handleDelete = (id: string) => { if (selectedAsset?.type === 'rule') deleteRule(id); else deleteDecisionTable(id); setSelectedAsset(null); }
    const filteredRules = rules.filter(r => r.name.toLowerCase().includes(search.toLowerCase()));
    const filteredTables = decisionTables.filter(t => t.name.toLowerCase().includes(search.toLowerCase()));
    const currentAsset = selectedAsset ? (selectedAsset.type === 'rule' ? rules.find(r => r.id === selectedAsset.id) : decisionTables.find(t => t.id === selectedAsset.id)) : null;

    return (
        <div className="flex-1 overflow-y-auto overflow-x-hidden min-h-0 -mx-4 px-4 pb-10">
            <ResponsiveGridLayout className="layout" layouts={layouts} breakpoints={{ lg: 1200, md: 996, sm: 768, xs: 480, xxs: 0 }} cols={{ lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 }} rowHeight={gridConfig.rowHeight} margin={gridConfig.margin} isDraggable={isEditable} isResizable={isEditable} draggableHandle=".drag-handle" onLayoutChange={(curr, all) => setLayouts(all)}>
                <NexCard key="library" dragHandle={isEditable} className="p-0 flex flex-col h-full">
                    <div className="p-3 border-b border-default bg-panel">
                        <div className="flex items-center justify-between mb-2">
                            <h3 className="text-xs font-bold text-primary uppercase">Library</h3>
                            <div className="flex gap-1"><IconButton icon={Sparkles} onClick={() => navigateTo('ai-rule-gen')} tooltip="AI Generate" className="text-blue-600"/><IconButton icon={BrainCircuit} onClick={() => createNew('rule')} tooltip="New Rule"/><IconButton icon={Table} onClick={() => createNew('table')} tooltip="New Table"/></div>
                        </div>
                        <div className="relative"><Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-tertiary" size={12}/><input className="w-full pl-7 pr-2 py-1.5 bg-subtle border border-default rounded-base text-xs outline-none" placeholder="Search..." value={search} onChange={e => setSearch(e.target.value)}/></div>
                    </div>
                    <div className="overflow-y-auto flex-1 p-3 space-y-6">
                        {filteredRules.length > 0 && <section><h4 className="text-xs font-bold text-tertiary uppercase mb-2">Rules</h4>{filteredRules.map(r => <button key={r.id} onClick={() => setSelectedAsset({type: 'rule', id: r.id})} className={`w-full text-left px-3 py-2 rounded-base flex items-center gap-2 ${selectedAsset?.id === r.id ? 'bg-blue-50 text-blue-700 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}><BrainCircuit size={14} /> {r.name}</button>)}</section>}
                        {filteredTables.length > 0 && <section><h4 className="text-xs font-bold text-tertiary uppercase mb-2">Tables</h4>{filteredTables.map(t => <button key={t.id} onClick={() => setSelectedAsset({type: 'table', id: t.id})} className={`w-full text-left px-3 py-2 rounded-base flex items-center gap-2 ${selectedAsset?.id === t.id ? 'bg-emerald-50 text-emerald-700 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}><Table size={14} /> {t.name}</button>)}</section>}
                    </div>
                </NexCard>

                <NexCard key="editor" dragHandle={isEditable} className="p-0 flex flex-col h-full overflow-hidden">
                    {currentAsset ? (selectedAsset?.type === 'rule' ? <RuleBuilder rule={currentAsset as BusinessRule} onSave={saveRule} onDelete={handleDelete} /> : <TableBuilder table={currentAsset as DecisionTable} onSave={saveDecisionTable} onDelete={handleDelete} />) : <div className="flex-1 flex items-center justify-center text-slate-400 italic">Select an asset</div>}
                </NexCard>

                <NexCard key="test" dragHandle={isEditable} className="p-0 flex flex-col h-full overflow-hidden">
                    <LiveTestPanel ruleId={selectedAsset?.id || null} />
                </NexCard>
            </ResponsiveGridLayout>
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Task, TaskStatus, TaskPriority, ChecklistItem, SavedView } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { useTheme } from '../contexts/ThemeContext';
import { 
  Search, CheckSquare, Layers, Clock, AlertCircle, UserPlus, Settings,
  CheckCircle, XCircle, Paperclip, LayoutGrid, List as ListIcon, 
  User, Calendar, Star, PauseCircle, ArrowDown, ArrowUp, X,
  Table as TableIcon, Download, Plus, Send, ChevronLeft, FormInput, Sparkles, BrainCircuit, ListChecks, Award, Trash2, Printer,
  Filter, Save, Eye, GripVertical, MessageSquare, ListTodo
} from 'lucide-react';
import { NexBadge, NexButton, NexHistoryFeed, NexDebouncedInput, NexUserDisplay, NexVirtualList, NexCard } from './shared/NexUI';
import { FormRenderer } from './shared/FormRenderer';
import { validateForm, createFilterPredicate, calculateSLA } from '../utils';
import { summarizeTaskContext } from '../services/geminiService';
import { Responsive, WidthProvider } from 'react-grid-layout';

const ResponsiveGridLayout = WidthProvider(Responsive);

// --- SLA Visual Component ---
const SLACountdown = ({ dueDate }: { dueDate: string }) => {
    const [sla, setSla] = useState(calculateSLA(dueDate));

    useEffect(() => {
        const calculate = () => setSla(calculateSLA(dueDate));
        calculate();
        const interval = setInterval(calculate, 60000); // Update every minute
        return () => clearInterval(interval);
    }, [dueDate]);

    const colors = {
        safe: 'bg-emerald-100 text-emerald-700',
        warn: 'bg-amber-100 text-amber-700',
        breach: 'bg-rose-100 text-rose-700 animate-pulse'
    };

    return (
        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-sm uppercase ${colors[sla.status]}`}>
            {sla.timeLeft}
        </span>
    );
};

interface TaskListProps {
    task: Task;
    isSelected: boolean;
    isChecked: boolean;
    isCompact: boolean;
    onCheck: (id: string) => void;
    onClick: (task: Task) => void;
    onStar: (id: string) => void;
}

// --- Task List Item Component ---
const TaskListItem: React.FC<TaskListProps> = ({ task, isSelected, isChecked, isCompact, onCheck, onClick, onStar }) => {
  return (
    <div 
      onClick={() => onClick(task)}
      className={`border-b border-subtle cursor-pointer hover:bg-subtle transition-colors group flex items-start gap-3 relative ${isSelected ? 'bg-active border-l-4 border-l-blue-600 pl-2' : 'border-l-4 border-l-transparent pl-3'}`}
      style={{ padding: isCompact ? 'calc(var(--space-base) * 0.75)' : 'var(--space-base)', height: '80px' }}
    >
      <div className="pt-1 flex flex-col gap-2 items-center" onClick={e => e.stopPropagation()}>
          <input type="checkbox" checked={isChecked} onChange={() => onCheck(task.id)} className="rounded-base border-default text-blue-600 focus:ring-blue-500" />
          <button onClick={() => onStar(task.id)} className="opacity-0 group-hover:opacity-100 transition-opacity">
             <Star size={12} className={task.isStarred ? "fill-amber-400 text-amber-400 opacity-100" : "text-tertiary"} />
          </button>
      </div>

      <div className="flex-1 min-w-0">
        <div className="flex justify-between items-start mb-0.5">
            <div className="flex items-center gap-2">
                <span className={`font-bold truncate pr-2 ${isCompact ? 'text-base' : 'text-sm'} ${isSelected ? 'text-blue-800' : 'text-primary'}`}>
                    {task.title}
                </span>
                {task.isAdHoc && <span className="bg-amber-100 text-amber-700 text-xs px-1 rounded-base font-bold">ADHOC</span>}
                {task.tags?.map((t: string) => <span key={t} className="bg-subtle text-secondary text-xs px-1 rounded-base border border-default">{t}</span>)}
            </div>
            <div className="flex items-center gap-1">
               <SLACountdown dueDate={task.dueDate} />
               {(task.attachments?.length ?? 0) > 0 && <Paperclip size={12} className="text-tertiary"/>}
               {task.priority === TaskPriority.CRITICAL && <AlertCircle size={14} className="text-rose-600 shrink-0"/>}
            </div>
        </div>

        <div className="flex justify-between items-center text-xs text-secondary">
            <span className="truncate max-w-[150px] flex items-center gap-1"><Layers size={10}/> {task.processName}</span>
            <div className="flex items-center gap-2">
                <span className="bg-subtle px-1.5 py-0.5 rounded-base text-secondary font-medium border border-default">{task.status}</span>
            </div>
        </div>
      </div>
    </div>
  );
};

export const TaskInbox: React.FC = () => {
  const { 
      tasks, completeTask, claimTask, releaseTask, addTaskComment, bulkCompleteTasks, updateTaskChecklist,
      currentUser, delegations, navigateTo, openInstanceViewer, nav, 
      toggleTaskStar, snoozeTask, createAdHocTask, forms, addNotification,
      savedViews, saveView, deleteView, setToolbarConfig, auditLogs
  } = useBPM();
  const { gridConfig } = useTheme();

  // -- Selection State --
  const selectedTask = useMemo(() => tasks.find(t => t.id === nav.selectedId) || null, [tasks, nav.selectedId]);
  const setSelectedTask = (t: Task | null) => navigateTo('inbox', t?.id);

  // -- View State --
  const [viewMode, setViewMode] = useState<'list' | 'kanban'>('list');
  const [activeTab, setActiveTab] = useState<'my' | 'team' | 'starred' | 'snoozed'>('my');
  const [density, setDensity] = useState<'compact' | 'comfy'>('comfy');
  const [sortConfig, setSortConfig] = useState<{ key: keyof Task, dir: 'asc' | 'desc' }>({ key: 'dueDate', dir: 'asc' });
  const [localSearch, setLocalSearch] = useState('');
  const [isEditable, setIsEditable] = useState(false);

  // -- Layouts --
  const defaultLayouts = {
      lg: [
          { i: 'list', x: 0, y: 0, w: 4, h: 20 },
          { i: 'detail', x: 4, y: 0, w: 8, h: 20 },
          { i: 'stats', x: 0, y: 20, w: 12, h: 4 }
      ],
      md: [
          { i: 'list', x: 0, y: 0, w: 4, h: 20 },
          { i: 'detail', x: 4, y: 0, w: 6, h: 20 },
          { i: 'stats', x: 0, y: 20, w: 10, h: 4 }
      ]
  };
  const [layouts, setLayouts] = useState(defaultLayouts);

  useEffect(() => {
      setToolbarConfig({
          view: [
              { label: isEditable ? 'Lock Layout' : 'Edit Layout', action: () => setIsEditable(!isEditable), icon: Settings },
              { label: 'Reset Layout', action: () => setLayouts(defaultLayouts) }
          ]
      });
  }, [setToolbarConfig, isEditable]);

  // -- Saved View State --
  const [activeSavedView, setActiveSavedView] = useState<string | null>(null);
  const [showSaveViewInput, setShowSaveViewInput] = useState(false);
  const [newViewName, setNewViewName] = useState('');

  // -- Filters --
  const [quickFilter, setQuickFilter] = useState<string | null>(null); // 'Critical', 'Overdue'

  // -- Bulk State --
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // -- Ad-Hoc Creation --
  const [quickTaskTitle, setQuickTaskTitle] = useState('');

  // -- Comment Input --
  const [commentText, setCommentText] = useState('');

  // -- Form Data & Validation --
  const [formData, setFormData] = useState<Record<string, any>>({});
  const [formErrors, setFormErrors] = useState<Record<string, string>>({});

  // -- AI Insight State --
  const [aiInsight, setAiInsight] = useState<{summary: string, sentiment: string, nextAction: string} | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
      if (selectedTask) {
          setFormData(selectedTask.data || {});
          setFormErrors({});
          setAiInsight(null);
          handleAiSummary(selectedTask);
      }
  }, [selectedTask]);

  const handleApplySavedView = (view: SavedView) => {
      setActiveSavedView(view.id);
      if (view.filters.status) setQuickFilter(view.filters.status); // Simplified mapping
      if (view.filters.search) setLocalSearch(view.filters.search);
  };

  const handleSaveCurrentView = async () => {
      if (!newViewName) return;
      await saveView({
          id: '',
          name: newViewName,
          type: 'Task',
          filters: { search: localSearch, priority: quickFilter || undefined }
      });
      setNewViewName('');
      setShowSaveViewInput(false);
  };

  // --- Derived Data & Filtering (Rule 24 Applied) ---
  const delegateRules = delegations.filter(d => d.toUserId === currentUser?.id && d.isActive);

  const filteredTasks = useMemo(() => {
      // Base Filter based on Tab
      const baseFilter = (t: Task) => {
          if (activeTab === 'snoozed') return !!t.snoozeUntil && new Date(t.snoozeUntil) > new Date();
          if (t.snoozeUntil && new Date(t.snoozeUntil) > new Date()) return false;

          if (activeTab === 'my') return t.assignee === currentUser?.id;
          if (activeTab === 'starred') return t.isStarred;
          if (activeTab === 'team') return t.assignee === 'Unassigned' || delegateRules.some(d => d.fromUserId === t.assignee);
          return true;
      };

      // Create Predicate from Config
      const predicate = createFilterPredicate<Task>({
          priority: quickFilter === 'Critical' ? TaskPriority.CRITICAL : undefined,
      }, localSearch, ['title', 'processName']);

      // Overdue Custom Check
      const overdueFilter = (t: Task) => quickFilter === 'Overdue' ? new Date(t.dueDate) < new Date() : true;

      return tasks.filter(t => baseFilter(t) && predicate(t) && overdueFilter(t)).sort((a, b) => {
          const valA = a[sortConfig.key];
          const valB = b[sortConfig.key];
          if (valA === undefined || valB === undefined) return 0;
          if (valA < valB) return sortConfig.dir === 'asc' ? -1 : 1;
          if (valA > valB) return sortConfig.dir === 'asc' ? 1 : -1;
          return 0;
      });
  }, [tasks, activeTab, localSearch, quickFilter, sortConfig, currentUser, delegateRules]);

  const toggleSelection = (id: string) => {
      const newSet = new Set(selectedIds);
      if (newSet.has(id)) newSet.delete(id); else newSet.add(id);
      setSelectedIds(newSet);
  };

  const handleQuickCreate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!quickTaskTitle.trim()) return;
      await createAdHocTask(quickTaskTitle);
      setQuickTaskTitle('');
  };

  const handleAiSummary = async (task: Task) => {
      setLoadingAi(true);
      try {
          const result = await summarizeTaskContext(task);
          setAiInsight(result);
      } catch (e) { console.error(e); } finally { setLoadingAi(false); }
  };

  const activeForm = selectedTask?.formId ? forms.find(f => f.id === selectedTask.formId) : null;

  const handleSubmit = async () => { 
      if (!selectedTask) return;
      if (activeForm) {
          const errors = validateForm(activeForm, formData);
          if (Object.keys(errors).length > 0) {
              setFormErrors(errors);
              addNotification('error', 'Please fix form errors before completing.');
              return;
          }
      }
      await completeTask(selectedTask.id, 'completed', commentText, formData);
      addNotification('success', 'Task completed successfully');
      setSelectedTask(null);
  };

  const handlePostComment = async () => {
      if (!selectedTask || !commentText.trim()) return;
      await addTaskComment(selectedTask.id, commentText);
      setCommentText('');
  };

  const handleToggleCheck = async (itemId: string, checked: boolean) => {
      if (!selectedTask?.checklist) return;
      const updated = selectedTask.checklist.map(i => i.id === itemId ? { ...i, completed: checked } : i);
      await updateTaskChecklist(selectedTask.id, updated);
  };

  return (
    <div className="h-full flex flex-col animate-fade-in overflow-hidden">
        <div className="flex-1 overflow-y-auto overflow-x-hidden min-h-0 -mx-4 px-4 pb-10">
            <ResponsiveGridLayout
                className="layout"
                layouts={layouts}
                breakpoints={{ lg: 1200, md: 996, sm: 768, xs: 480, xxs: 0 }}
                cols={{ lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 }}
                rowHeight={gridConfig.rowHeight}
                margin={gridConfig.margin}
                isDraggable={isEditable}
                isResizable={isEditable}
                draggableHandle=".drag-handle"
                onLayoutChange={(curr, all) => setLayouts(all)}
            >
                {/* --- TASK LIST WIDGET --- */}
                <NexCard key="list" dragHandle={isEditable} className="flex flex-col h-full p-0">
                    <div className="pt-3 px-3 bg-panel border-b border-subtle">
                        <div className="flex items-center justify-between mb-3">
                            <h2 className="text-lg font-bold text-primary flex items-center gap-2"><CheckSquare size={18} className="text-blue-600"/> Task Inbox</h2>
                            <div className="flex gap-1">
                                <button onClick={() => setViewMode('list')} className={`p-1.5 rounded-base ${viewMode === 'list' ? 'bg-active text-blue-600' : 'text-tertiary hover:text-secondary'}`}><ListIcon size={16}/></button>
                                <button onClick={() => setViewMode('kanban')} className={`p-1.5 rounded-base ${viewMode === 'kanban' ? 'bg-active text-blue-600' : 'text-tertiary hover:text-secondary'}`}><LayoutGrid size={16}/></button>
                            </div>
                        </div>
                        <div className="flex gap-4 text-xs font-bold text-secondary uppercase tracking-wide overflow-x-auto no-scrollbar">
                            {[ { id: 'my', label: 'My Work' }, { id: 'team', label: 'Team' }, { id: 'starred', label: 'Starred' } ].map(tab => (
                                <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-2 border-b-2 whitespace-nowrap transition-colors ${activeTab === tab.id ? 'border-active text-blue-600' : 'border-transparent hover:text-primary'}`}>{tab.label}</button>
                            ))}
                        </div>
                    </div>

                    <div className="p-2 bg-subtle border-b border-subtle space-y-2">
                        <form onSubmit={handleQuickCreate} className="relative">
                            <Plus size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-tertiary"/>
                            <input className="w-full pl-8 pr-3 py-1.5 text-xs border border-default rounded-base focus:ring-1 focus:ring-blue-500 outline-none" placeholder="Quick add..." value={quickTaskTitle} onChange={e => setQuickTaskTitle(e.target.value)} />
                        </form>
                        <NexDebouncedInput value={localSearch} onChange={setLocalSearch} placeholder="Search..." className="w-full pr-3 py-1.5 bg-panel border border-default rounded-base outline-none text-xs" icon={Search} />
                    </div>

                    <div className="flex-1 overflow-y-auto bg-panel min-h-0">
                        <NexVirtualList 
                            items={filteredTasks}
                            itemHeight={80} 
                            renderItem={(t: Task, idx) => (
                                <TaskListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} isChecked={selectedIds.has(t.id)} isCompact={density === 'compact'} onCheck={toggleSelection} onClick={setSelectedTask} onStar={toggleTaskStar} />
                            )}
                        />
                    </div>
                </NexCard>

                {/* --- TASK DETAIL WIDGET --- */}
                <NexCard key="detail" dragHandle={isEditable} className="flex flex-col h-full p-0">
                    {selectedTask ? (
                        <>
                            <div className="h-12 bg-panel border-b border-subtle flex items-center justify-between px-4 shadow-sm shrink-0">
                                <div className="flex items-center gap-2">
                                    <button onClick={() => setSelectedTask(null)} className="xl:hidden mr-2"><ChevronLeft size={18}/></button>
                                    <NexBadge variant={selectedTask.priority === 'Critical' ? 'rose' : 'blue'}>{selectedTask.priority}</NexBadge>
                                    <span className="text-xs text-tertiary font-mono">{selectedTask.id}</span>
                                </div>
                                <button onClick={() => setSelectedTask(null)} className="p-1.5 hover:bg-subtle rounded-base text-secondary"><X size={16}/></button>
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 md:p-6 bg-slate-50/50">
                                <div className="bg-panel rounded-base border border-default shadow-sm p-6 mb-4">
                                    <h2 className="text-lg font-bold text-primary mb-2 leading-tight">{selectedTask.title}</h2>
                                    <div className="flex items-center gap-4 text-xs text-secondary mb-4 pb-4 border-b border-subtle">
                                        <span className="flex items-center gap-1"><Layers size={12}/> {selectedTask.processName}</span>
                                        <span className="flex items-center gap-1"><NexUserDisplay userId={selectedTask.assignee} size="sm" showEmail={false} /></span>
                                    </div>
                                    <p className="text-base text-primary leading-relaxed mb-4">{selectedTask.description || "No description provided."}</p>

                                    {/* Checklist */}
                                    {selectedTask.checklist && selectedTask.checklist.length > 0 && (
                                        <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-sm">
                                            <h4 className="text-xs font-bold text-amber-800 uppercase mb-2 flex items-center gap-2"><ListTodo size={14}/> Sub-tasks</h4>
                                            <div className="space-y-1">
                                                {selectedTask.checklist.map(item => (
                                                    <label key={item.id} className="flex items-center gap-2 cursor-pointer hover:bg-amber-100/50 p-1 rounded-sm">
                                                        <input 
                                                            type="checkbox" 
                                                            checked={item.completed} 
                                                            onChange={e => handleToggleCheck(item.id, e.target.checked)} 
                                                            className="rounded-sm text-amber-600 focus:ring-amber-500" 
                                                        />
                                                        <span className={`text-xs ${item.completed ? 'line-through text-slate-400' : 'text-slate-700'}`}>{item.text}</span>
                                                    </label>
                                                ))}
                                            </div>
                                        </div>
                                    )}

                                    {activeForm && selectedTask.status !== TaskStatus.COMPLETED && (
                                        <div className="mb-6 p-4 bg-slate-50 border border-blue-200 rounded-sm">
                                            <div className="flex items-center gap-2 mb-4 text-blue-700">
                                                <FormInput size={16}/>
                                                <h4 className="text-sm font-bold uppercase">{activeForm.name}</h4>
                                            </div>
                                            <FormRenderer form={activeForm} data={formData} onChange={(k, v) => setFormData(prev => ({ ...prev, [k]: v }))} errors={formErrors} />
                                        </div>
                                    )}

                                    <div className="flex gap-2 mb-6">
                                        <NexButton variant="primary" onClick={handleSubmit} icon={CheckCircle}>Complete Task</NexButton>
                                    </div>

                                    {/* Comments & History */}
                                    <div className="border-t border-subtle pt-6">
                                        <h4 className="text-xs font-bold text-secondary uppercase mb-4 flex items-center gap-2"><MessageSquare size={14}/> Collaboration</h4>
                                        <div className="bg-subtle p-3 rounded-sm border border-default mb-4">
                                            <div className="flex gap-2">
                                                <input 
                                                    className="flex-1 bg-transparent text-sm outline-none placeholder:text-tertiary" 
                                                    placeholder="Write a comment..." 
                                                    value={commentText}
                                                    onChange={e => setCommentText(e.target.value)}
                                                    onKeyDown={e => e.key === 'Enter' && handlePostComment()}
                                                />
                                                <button onClick={handlePostComment} disabled={!commentText.trim()} className="text-blue-600 font-bold text-xs hover:text-blue-800 disabled:opacity-50">Post</button>
                                            </div>
                                        </div>
                                        <NexHistoryFeed history={[...(selectedTask.comments || []).map(c => ({...c, description: c.text})), ...(auditLogs.filter(l => l.entityId === selectedTask.id).map(l => ({...l, author: l.userId, description: `${l.action}: ${l.details}`})))].sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())} />
                                    </div>
                                </div>
                            </div>
                        </>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-tertiary p-8 text-center bg-slate-50/50">
                            <LayoutGrid size={48} className="opacity-20 mb-4"/>
                            <p className="text-sm font-medium">Select a task to view details</p>
                        </div>
                    )}
                </NexCard>

                {/* --- STATS WIDGET --- */}
                <NexCard key="stats" dragHandle={isEditable} className="flex flex-row items-center justify-between p-4 h-full">
                    <div className="flex items-center gap-4">
                        <div>
                            <div className="text-xs text-slate-500 uppercase font-bold">Total</div>
                            <div className="text-xl font-black text-slate-800">{tasks.length}</div>
                        </div>
                        <div className="w-px h-8 bg-slate-200"></div>
                        <div>
                            <div className="text-xs text-slate-500 uppercase font-bold">My Open</div>
                            <div className="text-xl font-black text-blue-600">{tasks.filter(t => t.assignee === currentUser?.id && t.status !== 'Completed').length}</div>
                        </div>
                        <div className="w-px h-8 bg-slate-200"></div>
                        <div>
                            <div className="text-xs text-slate-500 uppercase font-bold">Critical</div>
                            <div className="text-xl font-black text-rose-600">{tasks.filter(t => t.priority === TaskPriority.CRITICAL).length}</div>
                        </div>
                    </div>
                    {!isEditable && (
                        <NexButton variant="secondary" size="sm" onClick={() => addNotification('info', 'Refreshing task queue...')}>Sync</NexButton>
                    )}
                </NexCard>
            </ResponsiveGridLayout>
        </div>
    </div>
  );
};

import React, { createContext, useContext, useState, ReactNode, useCallback, useEffect, useMemo, useRef } from 'react';
import { produce } from 'immer';
import { 
  ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, 
  ViewState, AuditLog, Comment, User, UserRole, UserGroup, Permission, 
  Delegation, BusinessRule, DecisionTable, Case, CaseEvent, CasePolicy, CaseStakeholder,
  Condition, RuleAction, ProcessStep, ProcessLink, FormDefinition, ProcessVersionSnapshot, ChecklistItem,
  Integration, ApiClient, SystemSettings, SavedView, ToolbarConfig, TaskHistory
} from '../types';
import { dbService, DEFAULT_SETTINGS } from '../services/dbService';

interface Notification {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
  action?: () => void;
  deepLink?: { view: ViewState; id?: string };
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  cases: Case[];
  auditLogs: AuditLog[];
  users: User[];
  roles: UserRole[];
  groups: UserGroup[];
  notifications: Notification[];
  currentUser: User | null;
  loading: boolean;
  globalSearch: string;
  setGlobalSearch: (s: string) => void;

  nav: { view: ViewState; selectedId?: string; filter?: string; data?: any };
  delegations: Delegation[];
  rules: BusinessRule[];
  decisionTables: DecisionTable[];
  forms: FormDefinition[];
  integrations: Integration[]; 
  apiClients: ApiClient[]; 
  settings: SystemSettings;
  savedViews: SavedView[];

  viewingInstanceId: string | null;

  toolbarConfig: ToolbarConfig;
  setToolbarConfig: (config: ToolbarConfig) => void;

  designerDraft: { steps: ProcessStep[], links: ProcessLink[] } | null;
  setDesignerDraft: (draft: { steps: ProcessStep[], links: ProcessLink[] } | null) => void;

  navigateTo: (view: ViewState, id?: string, filter?: string, data?: any) => void;
  openInstanceViewer: (id: string) => void;
  closeInstanceViewer: () => void;
  switchUser: (userId: string) => void;
  addNotification: (type: 'success' | 'error' | 'info', message: string, deepLink?: { view: ViewState; id?: string }) => void;
  removeNotification: (id: string) => void;

  executeRules: (ruleId: string, fact: any) => Promise<any>;

  deployProcess: (process: Partial<ProcessDefinition>) => Promise<void>;
  updateProcess: (id: string, updates: Partial<ProcessDefinition>) => Promise<void>;
  deleteProcess: (id: string) => Promise<void>;
  toggleProcessState: (id: string) => Promise<void>;
  getStepStatistics: (defId: string, stepName: string) => { avgDuration: number, errorRate: number, totalExecutions: number };

  startProcess: (definitionId: string, inputData: any, caseId?: string) => Promise<string>;
  suspendInstance: (id: string) => Promise<void>;
  terminateInstance: (id: string) => Promise<void>;
  addInstanceComment: (instanceId: string, text: string) => Promise<void>;

  completeTask: (taskId: string, action: string, comments: string, formData?: any) => Promise<void>;
  claimTask: (taskId: string) => Promise<void>;
  releaseTask: (taskId: string) => Promise<void>;
  reassignTask: (taskId: string, userId: string) => Promise<void>;
  updateTaskMetadata: (taskId: string, updates: Partial<Task>) => Promise<void>;
  addTaskComment: (taskId: string, text: string) => Promise<void>;
  updateTaskChecklist: (taskId: string, items: ChecklistItem[]) => Promise<void>;
  bulkCompleteTasks: (taskIds: string[], action: 'approve' | 'reject') => Promise<void>;
  toggleTaskStar: (taskId: string) => Promise<void>;
  snoozeTask: (taskId: string, until: string) => Promise<void>;
  createAdHocTask: (title: string, priority?: TaskPriority) => Promise<void>;
  updateTaskLocation: (taskId: string, lat: number, lng: number) => Promise<void>; 

  createCase: (title: string, description: string, options?: { priority?: TaskPriority, data?: any, ownerId?: string }) => Promise<string>;
  updateCase: (id: string, updates: Partial<Case>) => Promise<void>;
  deleteCase: (id: string) => Promise<void>;
  addCaseEvent: (caseId: string, description: string) => Promise<void>;
  removeCaseEvent: (caseId: string, eventId: string) => Promise<void>;
  addCasePolicy: (caseId: string, policy: string) => Promise<void>;
  removeCasePolicy: (caseId: string, policyId: string) => Promise<void>;
  addCaseStakeholder: (caseId: string, userId: string, role: string) => Promise<void>;
  removeCaseStakeholder: (caseId: string, userId: string) => Promise<void>;

  saveRule: (rule: BusinessRule) => Promise<void>;
  deleteRule: (id: string) => Promise<void>;
  cloneRule: (id: string) => Promise<void>;
  saveDecisionTable: (table: DecisionTable) => Promise<void>;
  deleteDecisionTable: (id: string) => Promise<void>;

  saveForm: (form: FormDefinition) => Promise<void>;
  deleteForm: (id: string) => Promise<void>;

  createUser: (user: Omit<User, 'id'>) => Promise<void>;
  updateUser: (id: string, updates: Partial<User>) => Promise<void>;
  deleteUser: (id: string) => Promise<void>;
  createRole: (role: Omit<UserRole, 'id'>) => Promise<void>;
  updateRole: (id: string, updates: Partial<UserRole>) => Promise<void>;
  deleteRole: (id: string) => Promise<void>;
  createGroup: (group: Omit<UserGroup, 'id'>) => Promise<void>;
  updateGroup: (id: string, updates: Partial<UserGroup>) => Promise<void>;
  deleteGroup: (id: string) => Promise<void>;

  createDelegation: (toUserId: string, scope: 'All' | 'Critical Only') => Promise<void>;
  revokeDelegation: (id: string) => Promise<void>;

  installIntegration: (id: string, config: Record<string, string>) => Promise<void>;
  uninstallIntegration: (id: string) => Promise<void>;

  toggleApiClient: (id: string) => Promise<void>;

  saveView: (view: SavedView) => Promise<void>;
  deleteView: (id: string) => Promise<void>;

  updateSystemSettings: (updates: Partial<SystemSettings>) => Promise<void>;
  hasPermission: (perm: Permission) => boolean;
  reseedSystem: () => Promise<void>;
  resetSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;

  getActiveUsersOnRecord: (recordId: string) => User[];
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState({
    processes: [] as ProcessDefinition[],
    instances: [] as ProcessInstance[],
    tasks: [] as Task[],
    cases: [] as Case[],
    auditLogs: [] as AuditLog[],
    users: [] as User[],
    roles: [] as UserRole[],
    groups: [] as UserGroup[],
    delegations: [] as Delegation[],
    rules: [] as BusinessRule[],
    decisionTables: [] as DecisionTable[],
    forms: [] as FormDefinition[],
    integrations: [] as Integration[],
    apiClients: [] as ApiClient[],
    settings: DEFAULT_SETTINGS,
    savedViews: [] as SavedView[],
    notifications: [] as Notification[],
    globalSearch: '',
    nav: { view: 'dashboard' } as { view: ViewState; selectedId?: string; filter?: string; data?: any },
    viewingInstanceId: null as string | null,
    currentUser: null as User | null,
    loading: true,
    designerDraft: null as { steps: ProcessStep[], links: ProcessLink[] } | null
  });

  const [toolbarConfig, setToolbarConfigState] = useState<ToolbarConfig>({});
  const setToolbarConfig = useCallback((config: ToolbarConfig) => { setToolbarConfigState(config); }, []);
  const [activePresence, setActivePresence] = useState<Record<string, string[]>>({}); 

  // --- REFS for Engine Access to Latest State ---
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  const loadData = useCallback(async () => {
    try {
      const [p, inst, t, c, logs, u, r, g, d, bRules, tables, f, ints, apis, setts, views] = await Promise.all([
        dbService.getAll<ProcessDefinition>('processes'),
        dbService.getAll<ProcessInstance>('instances'),
        dbService.getAll<Task>('tasks'),
        dbService.getAll<Case>('cases'),
        dbService.getAll<AuditLog>('auditLogs'),
        dbService.getAll<User>('users'),
        dbService.getAll<UserRole>('roles'),
        dbService.getAll<UserGroup>('groups'),
        dbService.getAll<Delegation>('delegations'),
        dbService.getAll<BusinessRule>('rules'),
        dbService.getAll<DecisionTable>('decisionTables'),
        dbService.getAll<FormDefinition>('forms'),
        dbService.getAll<Integration>('integrations'),
        dbService.getAll<ApiClient>('apiClients'),
        dbService.getAll<SystemSettings>('systemSettings'),
        dbService.getAll<SavedView>('savedViews')
      ]);

      setState(prev => ({
        ...prev,
        processes: p, instances: inst, tasks: t, cases: c,
        auditLogs: logs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()),
        users: u, roles: r, groups: g, delegations: d,
        rules: bRules, decisionTables: tables, forms: f,
        integrations: ints, apiClients: apis, settings: setts[0] || DEFAULT_SETTINGS, savedViews: views,
        currentUser: prev.currentUser || u[0] || null,
        loading: false
      }));
    } catch (e) {
      console.error("Context Load Failure:", e);
      setState(prev => ({ ...prev, loading: false }));
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // --- HELPERS ---
  const addAudit = useCallback(async (action: string, type: AuditLog['entityType'], id: string, details: string, severity: AuditLog['severity'] = 'Info') => {
    const log: AuditLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      timestamp: new Date().toISOString(),
      userId: stateRef.current.currentUser?.name || 'System',
      action, entityType: type, entityId: id, details, severity
    };
    await dbService.add('auditLogs', log);
    setState(produce(draft => { draft.auditLogs.unshift(log); }));
  }, []);

  const addNotification = useCallback((type: 'success' | 'error' | 'info', message: string, deepLink?: { view: ViewState; id?: string }) => {
    const n: Notification = { id: `n-${Date.now()}`, type, message, deepLink };
    setState(produce(draft => { draft.notifications.push(n); }));
    setTimeout(() => setState(produce(draft => { draft.notifications = draft.notifications.filter(x => x.id !== n.id); })), 5000);
  }, []);

  const navigateTo = useCallback((view: ViewState, id?: string, filter?: string, data?: any) => {
    setState(produce(draft => { draft.nav = { view, selectedId: id, filter, data }; draft.globalSearch = ''; }));
    setToolbarConfig({});
  }, [setToolbarConfig]);

  // --- WORKFLOW ENGINE ---

  const evaluateCondition = (condition: string, variables: any) => {
      try {
          // Rudimentary safe eval replacement for demo. 
          // Supports "amount > 100", "status == 'Approved'"
          // Replace variable names with values
          let expr = condition;
          Object.keys(variables).forEach(key => {
              const val = typeof variables[key] === 'string' ? `'${variables[key]}'` : variables[key];
              expr = expr.replace(new RegExp(`\\b${key}\\b`, 'g'), String(val));
          });
          // eslint-disable-next-line no-eval
          return eval(expr); 
      } catch (e) {
          console.warn('Condition Eval Failed:', condition, e);
          return false;
      }
  };

  const proceedWorkflow = async (instanceId: string, currentStepId: string) => {
      const instance = stateRef.current.instances.find(i => i.id === instanceId);
      if (!instance) return;
      const def = stateRef.current.processes.find(p => p.id === instance.definitionId);
      if (!def) return;

      const currentStep = def.steps.find(s => s.id === currentStepId);

      // 1. Log Step Completion
      const historyEntry: TaskHistory = {
          id: `h-${Date.now()}`, stepName: currentStep?.name || 'Unknown', stepId: currentStepId,
          action: 'Completed', performer: 'System', timestamp: new Date().toISOString()
      };

      // 2. Determine Next Step(s)
      const outgoingLinks = def.links?.filter(l => l.sourceId === currentStepId) || [];
      let nextStepIds: string[] = [];

      if (currentStep?.type === 'exclusive-gateway') {
          const match = outgoingLinks.find(l => l.condition && evaluateCondition(l.condition, instance.variables));
          if (match) nextStepIds.push(match.targetId);
          else {
              const defaultLink = outgoingLinks.find(l => l.isDefault) || outgoingLinks[0];
              if (defaultLink) nextStepIds.push(defaultLink.targetId);
          }
      } else if (currentStep?.type === 'parallel-gateway') {
          nextStepIds = outgoingLinks.map(l => l.targetId);
      } else {
          // Standard / Implicit Parallel
          nextStepIds = outgoingLinks.map(l => l.targetId);
      }

      // 3. Update Instance
      const updates: Partial<ProcessInstance> = {
          activeStepIds: nextStepIds,
          history: [...instance.history, historyEntry]
      };

      // 4. Process Next Nodes
      for (const nextId of nextStepIds) {
          const nextStep = def.steps.find(s => s.id === nextId);
          if (!nextStep) continue;

          if (nextStep.type === 'user-task') {
              const newTask: Task = {
                  id: `task-${Date.now()}-${Math.random().toString(36).substr(2,4)}`,
                  title: nextStep.name, processName: def.name, processInstanceId: instanceId,
                  assignee: nextStep.role ? '' : (stateRef.current.currentUser?.id || ''), // Auto-assign to current user if no role for demo, else unassigned
                  candidateRoles: nextStep.role ? [nextStep.role] : [],
                  candidateGroups: nextStep.groupId ? [nextStep.groupId] : [],
                  requiredSkills: nextStep.requiredSkills || [],
                  dueDate: new Date(Date.now() + (nextStep.slaDays || 3) * 86400000).toISOString(),
                  status: TaskStatus.PENDING, priority: TaskPriority.MEDIUM,
                  description: nextStep.description, stepId: nextId, data: {}, comments: [], attachments: [], isAdHoc: false, formId: nextStep.formId
              };
              await dbService.add('tasks', newTask);
              setState(produce(draft => { draft.tasks.unshift(newTask); }));
              addNotification('info', `New Task Assigned: ${newTask.title}`);
          } else if (nextStep.type === 'end') {
              updates.status = 'Completed';
              updates.endDate = new Date().toISOString();
              updates.activeStepIds = []; // Clear active steps
              addNotification('success', `Process Completed: ${def.name}`);
          } else if (['service-task', 'script-task', 'start', 'exclusive-gateway', 'parallel-gateway'].includes(nextStep.type)) {
              // Auto-execute system tasks/gateways
              setTimeout(() => proceedWorkflow(instanceId, nextId), 500); 
          }
      }

      await dbService.add('instances', { ...instance, ...updates });
      setState(produce(draft => { 
          const idx = draft.instances.findIndex(i => i.id === instanceId);
          if (idx !== -1) draft.instances[idx] = { ...draft.instances[idx], ...updates };
      }));
  };

  const startProcess = useCallback(async (definitionId: string, inputData: any, caseId?: string) => {
      const def = stateRef.current.processes.find(p => p.id === definitionId);
      if(!def) throw new Error('Process definition not found');

      const startNode = def.steps.find(s => s.type === 'start');
      if (!startNode) { addNotification('error', 'Process has no start event'); return ''; }

      const newInstance: ProcessInstance = {
          id: `inst-${Date.now()}`,
          definitionId: def.id,
          definitionName: def.name,
          status: 'Active',
          startDate: new Date().toISOString(),
          activeStepIds: [startNode.id],
          variables: { ...inputData, sys_startedBy: stateRef.current.currentUser?.id, sys_caseId: caseId },
          priority: TaskPriority.MEDIUM,
          history: [], comments: [], complianceVerified: false, domainId: def.domainId
      };

      await dbService.add('instances', newInstance);
      setState(produce(draft => { draft.instances.unshift(newInstance); }));
      addNotification('success', `Started ${def.name}`);
      addAudit('PROCESS_START', 'Instance', newInstance.id, `Started process ${def.name}`);

      // Kick off the engine
      proceedWorkflow(newInstance.id, startNode.id);

      return newInstance.id;
  }, [addNotification, addAudit]);

  const completeTask = useCallback(async (taskId: string, action: string, comments: string, formData?: any) => {
      const task = stateRef.current.tasks.find(t => t.id === taskId);
      if (!task) return;

      // 1. Update Task
      const updates: Partial<Task> = { status: TaskStatus.COMPLETED, data: { ...task.data, ...formData } };
      await dbService.add('tasks', { ...task, ...updates });
      setState(produce(draft => {
          const t = draft.tasks.find(x => x.id === taskId);
          if (t) { t.status = TaskStatus.COMPLETED; t.data = { ...t.data, ...formData }; }
      }));

      // 2. Update Instance & Move Token
      if (task.processInstanceId) {
          const instance = stateRef.current.instances.find(i => i.id === task.processInstanceId);
          if (instance) {
              // Merge form data into instance variables
              const updatedVariables = { ...instance.variables, ...formData };
              await dbService.add('instances', { ...instance, variables: updatedVariables });
              setState(produce(draft => {
                  const i = draft.instances.find(x => x.id === task.processInstanceId);
                  if (i) i.variables = updatedVariables;
              }));

              // Proceed
              proceedWorkflow(task.processInstanceId, task.stepId);
          }
      }

      addAudit('TASK_COMPLETE', 'Task', taskId, `Completed task ${task.title} with action: ${action}`);
  }, [addAudit]);

  // --- CRUD WRAPPERS ---
  const deployProcess = useCallback(async (p: Partial<ProcessDefinition>) => { 
    const newDef = { ...p, id: p.id || `proc-${Date.now()}`, createdAt: new Date().toISOString(), deployedBy: stateRef.current.currentUser?.name || 'System', version: (p.version || 0) + 1, history: [] } as ProcessDefinition;
    await dbService.add('processes', newDef); 
    setState(produce(draft => { 
        const idx = draft.processes.findIndex(x => x.id === newDef.id);
        if (idx !== -1) draft.processes[idx] = newDef; else draft.processes.push(newDef);
    }));
    addAudit('PROCESS_DEPLOY', 'Process', newDef.id, `Deployed model: ${newDef.name} v${newDef.version}`);
  }, [addAudit]);

  const updateProcess = useCallback(async (id: string, updates: Partial<ProcessDefinition>) => {
    const p = stateRef.current.processes.find(x => x.id === id);
    if(p) {
        const up = { ...p, ...updates };
        await dbService.add('processes', up);
        setState(produce(draft => { draft.processes = draft.processes.map(x => x.id === id ? up : x); }));
    }
  }, []);

  const deleteProcess = useCallback(async (id: string) => {
      await dbService.delete('processes', id);
      setState(produce(draft => { draft.processes = draft.processes.filter(x => x.id !== id); }));
      addAudit('PROCESS_DELETE', 'Process', id, 'Removed process definition', 'Warning');
  }, [addAudit]);

  const createCase = useCallback(async (title: string, description: string, options: any = {}) => {
      const newCase: Case = {
          id: `case-${Date.now()}`, title, description,
          status: 'Open', priority: options.priority || TaskPriority.MEDIUM,
          createdAt: new Date().toISOString(), stakeholders: [],
          data: options.data || {}, timeline: [], policies: [], attachments: [],
          domainId: stateRef.current.currentUser?.domainId || 'GLOBAL'
      };
      if (options.ownerId) newCase.stakeholders.push({ userId: options.ownerId, role: 'Owner' });

      await dbService.add('cases', newCase);
      setState(produce(draft => { draft.cases.unshift(newCase); }));
      addAudit('CASE_CREATE', 'Case', newCase.id, `Created case: ${title}`);
      return newCase.id;
  }, [addAudit]);

  // ... Other simple CRUDs (users, roles, etc) omitted for brevity but would follow same pattern using stateRef for current data access

  // --- CONTEXT EXPORT ---
  const contextValue: BPMContextType = useMemo(() => ({
    ...state,
    setGlobalSearch: (s) => setState(prev => ({ ...prev, globalSearch: s })),
    setDesignerDraft: (draft) => setState(prev => ({ ...prev, designerDraft: draft })),
    setToolbarConfig, toolbarConfig,
    navigateTo, openInstanceViewer: (id) => setState(prev => ({ ...prev, viewingInstanceId: id })),
    closeInstanceViewer: () => setState(prev => ({ ...prev, viewingInstanceId: null })),
    switchUser: (id) => { const u = state.users.find(u => u.id === id); if (u) { setState(prev => ({ ...prev, currentUser: u })); navigateTo('dashboard'); } },
    addNotification, removeNotification,

    startProcess, completeTask,

    executeRules: async (ruleId, fact) => { return { matched: false }; }, // Placeholder for Phase 4
    deployProcess, updateProcess, deleteProcess,
    toggleProcessState: async (id) => {},

    // Stubbed CRUDs to satisfy interface
    suspendInstance: async () => {}, terminateInstance: async () => {}, addInstanceComment: async (id, txt) => {
        const inst = stateRef.current.instances.find(i => i.id === id);
        if(inst) {
            const comment = { id: `c-${Date.now()}`, userId: stateRef.current.currentUser?.id || '', userName: stateRef.current.currentUser?.name || 'User', text: txt, timestamp: new Date().toISOString() };
            const up = { ...inst, comments: [...inst.comments, comment] };
            await dbService.add('instances', up);
            setState(produce(draft => { const idx = draft.instances.findIndex(x => x.id === id); if(idx !== -1) draft.instances[idx].comments.push(comment); }));
        }
    },
    claimTask: async () => {}, releaseTask: async () => {}, reassignTask: async () => {}, updateTaskMetadata: async () => {},
    addTaskComment: async (id, txt) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            const c = { id: `c-${Date.now()}`, userId: stateRef.current.currentUser?.id || '', userName: stateRef.current.currentUser?.name || 'User', text: txt, timestamp: new Date().toISOString() };
            await dbService.add('tasks', { ...t, comments: [...t.comments, c] });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].comments.push(c); }));
        }
    },
    updateTaskChecklist: async (id, items) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            await dbService.add('tasks', { ...t, checklist: items });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].checklist = items; }));
        }
    },
    bulkCompleteTasks: async () => {}, toggleTaskStar: async (id) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            await dbService.add('tasks', { ...t, isStarred: !t.isStarred });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].isStarred = !draft.tasks[idx].isStarred; }));
        }
    },
    snoozeTask: async () => {}, 
    createAdHocTask: async (title) => {
        const t: Task = {
            id: `task-${Date.now()}`, title, processName: 'Ad-Hoc', processInstanceId: '', assignee: stateRef.current.currentUser?.id || '', candidateRoles: [], candidateGroups: [], requiredSkills: [],
            dueDate: new Date().toISOString(), status: TaskStatus.PENDING, priority: TaskPriority.MEDIUM, stepId: 'adhoc', data: {}, comments: [], attachments: [], isAdHoc: true
        };
        await dbService.add('tasks', t);
        setState(produce(draft => { draft.tasks.unshift(t); }));
    },
    updateTaskLocation: async () => {},
    createCase, updateCase: async (id, up) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) { await dbService.add('cases', { ...c, ...up }); setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) Object.assign(draft.cases[idx], up); })); }
    }, deleteCase: async () => {}, 
    addCaseEvent: async (id, desc) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const ev = { id: `evt-${Date.now()}`, timestamp: new Date().toISOString(), type: 'Manual' as const, description: desc, author: stateRef.current.currentUser?.name || 'System' };
            await dbService.add('cases', { ...c, timeline: [ev, ...c.timeline] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].timeline.unshift(ev); }));
        }
    },
    removeCaseEvent: async () => {}, addCasePolicy: async (id, txt) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const p = { id: `pol-${Date.now()}`, description: txt, isEnforced: true };
            await dbService.add('cases', { ...c, policies: [...c.policies, p] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].policies.push(p); }));
        }
    },
    removeCasePolicy: async () => {}, addCaseStakeholder: async (id, uid, role) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const sh = { userId: uid, role: role as any };
            await dbService.add('cases', { ...c, stakeholders: [...c.stakeholders, sh] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].stakeholders.push(sh); }));
        }
    },
    removeCaseStakeholder: async () => {},
    saveRule: async (r) => { await dbService.add('rules', r); setState(produce(draft => { const idx = draft.rules.findIndex(x => x.id === r.id); if(idx!==-1) draft.rules[idx] = r; else draft.rules.push(r); })); },
    deleteRule: async (id) => { await dbService.delete('rules', id); setState(produce(draft => { draft.rules = draft.rules.filter(x => x.id !== id); })); },
    cloneRule: async () => {},
    saveDecisionTable: async (t) => { await dbService.add('decisionTables', t); setState(produce(draft => { const idx = draft.decisionTables.findIndex(x => x.id === t.id); if(idx!==-1) draft.decisionTables[idx] = t; else draft.decisionTables.push(t); })); },
    deleteDecisionTable: async (id) => { await dbService.delete('decisionTables', id); setState(produce(draft => { draft.decisionTables = draft.decisionTables.filter(x => x.id !== id); })); },
    saveForm: async (f) => { await dbService.add('forms', f); setState(produce(draft => { const idx = draft.forms.findIndex(x => x.id === f.id); if(idx!==-1) draft.forms[idx] = f; else draft.forms.push(f); })); },
    deleteForm: async (id) => { await dbService.delete('forms', id); setState(produce(draft => { draft.forms = draft.forms.filter(x => x.id !== id); })); },

    createUser: async (u) => { const nu = { ...u, id: `u-${Date.now()}` }; await dbService.add('users', nu); setState(produce(draft => { draft.users.push(nu); })); },
    updateUser: async (id, up) => { const u = stateRef.current.users.find(x => x.id === id); if(u) { await dbService.add('users', { ...u, ...up }); setState(produce(draft => { const idx = draft.users.findIndex(x => x.id === id); if(idx!==-1) Object.assign(draft.users[idx], up); })); } },
    deleteUser: async (id) => { await dbService.delete('users', id); setState(produce(draft => { draft.users = draft.users.filter(x => x.id !== id); })); },
    createRole: async () => {}, updateRole: async () => {}, deleteRole: async () => {},
    createGroup: async () => {}, updateGroup: async () => {}, deleteGroup: async () => {},
    createDelegation: async (uid, scope) => {
        const d: Delegation = { id: `del-${Date.now()}`, fromUserId: stateRef.current.currentUser?.id || '', toUserId: uid, scope, startDate: new Date().toISOString(), endDate: new Date(Date.now()+86400000).toISOString(), isActive: true };
        await dbService.add('delegations', d);
        setState(produce(draft => { draft.delegations.push(d); }));
    },
    revokeDelegation: async (id) => { await dbService.delete('delegations', id); setState(produce(draft => { draft.delegations = draft.delegations.filter(x => x.id !== id); })); },
    installIntegration: async () => {}, uninstallIntegration: async () => {}, toggleApiClient: async () => {},
    saveView: async (v) => { const nv = { ...v, id: v.id || `view-${Date.now()}` }; await dbService.add('savedViews', nv); setState(produce(draft => { draft.savedViews.push(nv); })); },
    deleteView: async () => {},
    updateSystemSettings: async (up) => { const ns = { ...stateRef.current.settings, ...up }; await dbService.add('systemSettings', ns); setState(prev => ({ ...prev, settings: ns })); },
    hasPermission: (perm) => {
        if (!stateRef.current.currentUser) return false;
        return stateRef.current.currentUser.roleIds.some(rId => {
            const role = stateRef.current.roles.find(r => r.id === rId);
            return role?.permissions.includes(perm) || role?.permissions.includes(Permission.ADMIN_ACCESS);
        });
    },
    getStepStatistics: (defId, stepName) => {
        // Simple implementation
        const instances = stateRef.current.instances.filter(i => i.definitionId === defId);
        let count = 0;
        instances.forEach(i => i.history.forEach(h => { if(h.stepName === stepName) count++; }));
        return { avgDuration: 5, errorRate: 0, totalExecutions: count };
    },
    reseedSystem: async () => { await dbService.reseed(); loadData(); },
    resetSystem: async () => { await dbService.resetDB(); window.location.reload(); },
    exportData: async () => { return dbService.exportData(); },
    importData: async (f) => {},
    getActiveUsersOnRecord: (id) => { const uids = activePresence[id] || []; return stateRef.current.users.filter(u => uids.includes(u.id)); }
  }), [state, navigateTo, addNotification, removeNotification, startProcess, completeTask, createCase, deployProcess, updateProcess, deleteProcess, loadData, setToolbarConfig, activePresence]);

  return <BPMContext.Provider value={contextValue}>{children}</BPMContext.Provider>;
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { createContext, useContext, useState, ReactNode, useCallback, useEffect, useMemo, useRef } from 'react';
import { produce } from 'immer';
import { 
  ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, 
  ViewState, AuditLog, Comment, User, UserRole, UserGroup, Permission, 
  Delegation, BusinessRule, DecisionTable, Case, CaseEvent, CasePolicy, CaseStakeholder,
  Condition, RuleAction, ProcessStep, ProcessLink, FormDefinition, ProcessVersionSnapshot, ChecklistItem,
  Integration, ApiClient, SystemSettings, SavedView, ToolbarConfig, TaskHistory
} from '../types';
import { dbService, DEFAULT_SETTINGS } from '../services/dbService';

interface Notification {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
  action?: () => void;
  deepLink?: { view: ViewState; id?: string };
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  cases: Case[];
  auditLogs: AuditLog[];
  users: User[];
  roles: UserRole[];
  groups: UserGroup[];
  notifications: Notification[];
  currentUser: User | null;
  loading: boolean;
  globalSearch: string;
  setGlobalSearch: (s: string) => void;

  nav: { view: ViewState; selectedId?: string; filter?: string; data?: any };
  delegations: Delegation[];
  rules: BusinessRule[];
  decisionTables: DecisionTable[];
  forms: FormDefinition[];
  integrations: Integration[]; 
  apiClients: ApiClient[]; 
  settings: SystemSettings;
  savedViews: SavedView[];

  viewingInstanceId: string | null;

  toolbarConfig: ToolbarConfig;
  setToolbarConfig: (config: ToolbarConfig) => void;

  designerDraft: { steps: ProcessStep[], links: ProcessLink[] } | null;
  setDesignerDraft: (draft: { steps: ProcessStep[], links: ProcessLink[] } | null) => void;

  navigateTo: (view: ViewState, id?: string, filter?: string, data?: any) => void;
  openInstanceViewer: (id: string) => void;
  closeInstanceViewer: () => void;
  switchUser: (userId: string) => void;
  addNotification: (type: 'success' | 'error' | 'info', message: string, deepLink?: { view: ViewState; id?: string }) => void;
  removeNotification: (id: string) => void;

  executeRules: (ruleId: string, fact: any) => Promise<any>;

  deployProcess: (process: Partial<ProcessDefinition>) => Promise<void>;
  updateProcess: (id: string, updates: Partial<ProcessDefinition>) => Promise<void>;
  deleteProcess: (id: string) => Promise<void>;
  toggleProcessState: (id: string) => Promise<void>;
  getStepStatistics: (defId: string, stepName: string) => { avgDuration: number, errorRate: number, totalExecutions: number };

  startProcess: (definitionId: string, inputData: any, caseId?: string) => Promise<string>;
  suspendInstance: (id: string) => Promise<void>;
  terminateInstance: (id: string) => Promise<void>;
  addInstanceComment: (instanceId: string, text: string) => Promise<void>;

  completeTask: (taskId: string, action: string, comments: string, formData?: any) => Promise<void>;
  claimTask: (taskId: string) => Promise<void>;
  releaseTask: (taskId: string) => Promise<void>;
  reassignTask: (taskId: string, userId: string) => Promise<void>;
  updateTaskMetadata: (taskId: string, updates: Partial<Task>) => Promise<void>;
  addTaskComment: (taskId: string, text: string) => Promise<void>;
  updateTaskChecklist: (taskId: string, items: ChecklistItem[]) => Promise<void>;
  bulkCompleteTasks: (taskIds: string[], action: 'approve' | 'reject') => Promise<void>;
  toggleTaskStar: (taskId: string) => Promise<void>;
  snoozeTask: (taskId: string, until: string) => Promise<void>;
  createAdHocTask: (title: string, priority?: TaskPriority) => Promise<void>;
  updateTaskLocation: (taskId: string, lat: number, lng: number) => Promise<void>; 

  createCase: (title: string, description: string, options?: { priority?: TaskPriority, data?: any, ownerId?: string }) => Promise<string>;
  updateCase: (id: string, updates: Partial<Case>) => Promise<void>;
  deleteCase: (id: string) => Promise<void>;
  addCaseEvent: (caseId: string, description: string) => Promise<void>;
  removeCaseEvent: (caseId: string, eventId: string) => Promise<void>;
  addCasePolicy: (caseId: string, policy: string) => Promise<void>;
  removeCasePolicy: (caseId: string, policyId: string) => Promise<void>;
  addCaseStakeholder: (caseId: string, userId: string, role: string) => Promise<void>;
  removeCaseStakeholder: (caseId: string, userId: string) => Promise<void>;

  saveRule: (rule: BusinessRule) => Promise<void>;
  deleteRule: (id: string) => Promise<void>;
  cloneRule: (id: string) => Promise<void>;
  saveDecisionTable: (table: DecisionTable) => Promise<void>;
  deleteDecisionTable: (id: string) => Promise<void>;

  saveForm: (form: FormDefinition) => Promise<void>;
  deleteForm: (id: string) => Promise<void>;

  createUser: (user: Omit<User, 'id'>) => Promise<void>;
  updateUser: (id: string, updates: Partial<User>) => Promise<void>;
  deleteUser: (id: string) => Promise<void>;
  createRole: (role: Omit<UserRole, 'id'>) => Promise<void>;
  updateRole: (id: string, updates: Partial<UserRole>) => Promise<void>;
  deleteRole: (id: string) => Promise<void>;
  createGroup: (group: Omit<UserGroup, 'id'>) => Promise<void>;
  updateGroup: (id: string, updates: Partial<UserGroup>) => Promise<void>;
  deleteGroup: (id: string) => Promise<void>;

  createDelegation: (toUserId: string, scope: 'All' | 'Critical Only') => Promise<void>;
  revokeDelegation: (id: string) => Promise<void>;

  installIntegration: (id: string, config: Record<string, string>) => Promise<void>;
  uninstallIntegration: (id: string) => Promise<void>;

  toggleApiClient: (id: string) => Promise<void>;

  saveView: (view: SavedView) => Promise<void>;
  deleteView: (id: string) => Promise<void>;

  updateSystemSettings: (updates: Partial<SystemSettings>) => Promise<void>;
  hasPermission: (perm: Permission) => boolean;
  reseedSystem: () => Promise<void>;
  resetSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;

  getActiveUsersOnRecord: (recordId: string) => User[];
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState({
    processes: [] as ProcessDefinition[],
    instances: [] as ProcessInstance[],
    tasks: [] as Task[],
    cases: [] as Case[],
    auditLogs: [] as AuditLog[],
    users: [] as User[],
    roles: [] as UserRole[],
    groups: [] as UserGroup[],
    delegations: [] as Delegation[],
    rules: [] as BusinessRule[],
    decisionTables: [] as DecisionTable[],
    forms: [] as FormDefinition[],
    integrations: [] as Integration[],
    apiClients: [] as ApiClient[],
    settings: DEFAULT_SETTINGS,
    savedViews: [] as SavedView[],
    notifications: [] as Notification[],
    globalSearch: '',
    nav: { view: 'dashboard' } as { view: ViewState; selectedId?: string; filter?: string; data?: any },
    viewingInstanceId: null as string | null,
    currentUser: null as User | null,
    loading: true,
    designerDraft: null as { steps: ProcessStep[], links: ProcessLink[] } | null
  });

  const [toolbarConfig, setToolbarConfigState] = useState<ToolbarConfig>({});
  const setToolbarConfig = useCallback((config: ToolbarConfig) => { setToolbarConfigState(config); }, []);
  const [activePresence, setActivePresence] = useState<Record<string, string[]>>({}); 

  // --- REFS for Engine Access to Latest State ---
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  const loadData = useCallback(async () => {
    try {
      const [p, inst, t, c, logs, u, r, g, d, bRules, tables, f, ints, apis, setts, views] = await Promise.all([
        dbService.getAll<ProcessDefinition>('processes'),
        dbService.getAll<ProcessInstance>('instances'),
        dbService.getAll<Task>('tasks'),
        dbService.getAll<Case>('cases'),
        dbService.getAll<AuditLog>('auditLogs'),
        dbService.getAll<User>('users'),
        dbService.getAll<UserRole>('roles'),
        dbService.getAll<UserGroup>('groups'),
        dbService.getAll<Delegation>('delegations'),
        dbService.getAll<BusinessRule>('rules'),
        dbService.getAll<DecisionTable>('decisionTables'),
        dbService.getAll<FormDefinition>('forms'),
        dbService.getAll<Integration>('integrations'),
        dbService.getAll<ApiClient>('apiClients'),
        dbService.getAll<SystemSettings>('systemSettings'),
        dbService.getAll<SavedView>('savedViews')
      ]);

      setState(prev => ({
        ...prev,
        processes: p, instances: inst, tasks: t, cases: c,
        auditLogs: logs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()),
        users: u, roles: r, groups: g, delegations: d,
        rules: bRules, decisionTables: tables, forms: f,
        integrations: ints, apiClients: apis, settings: setts[0] || DEFAULT_SETTINGS, savedViews: views,
        currentUser: prev.currentUser || u[0] || null,
        loading: false
      }));
    } catch (e) {
      console.error("Context Load Failure:", e);
      setState(prev => ({ ...prev, loading: false }));
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // --- HELPERS ---
  const addAudit = useCallback(async (action: string, type: AuditLog['entityType'], id: string, details: string, severity: AuditLog['severity'] = 'Info') => {
    const log: AuditLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      timestamp: new Date().toISOString(),
      userId: stateRef.current.currentUser?.name || 'System',
      action, entityType: type, entityId: id, details, severity
    };
    await dbService.add('auditLogs', log);
    setState(produce(draft => { draft.auditLogs.unshift(log); }));
  }, []);

  const addNotification = useCallback((type: 'success' | 'error' | 'info', message: string, deepLink?: { view: ViewState; id?: string }) => {
    const n: Notification = { id: `n-${Date.now()}`, type, message, deepLink };
    setState(produce(draft => { draft.notifications.push(n); }));
    setTimeout(() => setState(produce(draft => { draft.notifications = draft.notifications.filter(x => x.id !== n.id); })), 5000);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setState(produce(draft => { draft.notifications = draft.notifications.filter(x => x.id !== id); }));
  }, []);

  const navigateTo = useCallback((view: ViewState, id?: string, filter?: string, data?: any) => {
    setState(produce(draft => { draft.nav = { view, selectedId: id, filter, data }; draft.globalSearch = ''; }));
    setToolbarConfig({});
  }, [setToolbarConfig]);

  // --- WORKFLOW ENGINE ---

  const evaluateCondition = (condition: string, variables: any) => {
      try {
          // Rudimentary safe eval replacement for demo. 
          // Supports "amount > 100", "status == 'Approved'"
          // Replace variable names with values
          let expr = condition;
          Object.keys(variables).forEach(key => {
              const val = typeof variables[key] === 'string' ? `'${variables[key]}'` : variables[key];
              expr = expr.replace(new RegExp(`\\b${key}\\b`, 'g'), String(val));
          });
          // eslint-disable-next-line no-eval
          return eval(expr); 
      } catch (e) {
          console.warn('Condition Eval Failed:', condition, e);
          return false;
      }
  };

  const proceedWorkflow = async (instanceId: string, currentStepId: string) => {
      const instance = stateRef.current.instances.find(i => i.id === instanceId);
      if (!instance) return;
      const def = stateRef.current.processes.find(p => p.id === instance.definitionId);
      if (!def) return;

      const currentStep = def.steps.find(s => s.id === currentStepId);

      // 1. Log Step Completion
      const historyEntry: TaskHistory = {
          id: `h-${Date.now()}`, stepName: currentStep?.name || 'Unknown', stepId: currentStepId,
          action: 'Completed', performer: 'System', timestamp: new Date().toISOString()
      };

      // 2. Determine Next Step(s)
      const outgoingLinks = def.links?.filter(l => l.sourceId === currentStepId) || [];
      let nextStepIds: string[] = [];

      if (currentStep?.type === 'exclusive-gateway') {
          const match = outgoingLinks.find(l => l.condition && evaluateCondition(l.condition, instance.variables));
          if (match) nextStepIds.push(match.targetId);
          else {
              const defaultLink = outgoingLinks.find(l => l.isDefault) || outgoingLinks[0];
              if (defaultLink) nextStepIds.push(defaultLink.targetId);
          }
      } else if (currentStep?.type === 'parallel-gateway') {
          nextStepIds = outgoingLinks.map(l => l.targetId);
      } else {
          // Standard / Implicit Parallel
          nextStepIds = outgoingLinks.map(l => l.targetId);
      }

      // 3. Update Instance
      const updates: Partial<ProcessInstance> = {
          activeStepIds: nextStepIds,
          history: [...instance.history, historyEntry]
      };

      // 4. Process Next Nodes
      for (const nextId of nextStepIds) {
          const nextStep = def.steps.find(s => s.id === nextId);
          if (!nextStep) continue;

          if (nextStep.type === 'user-task') {
              const newTask: Task = {
                  id: `task-${Date.now()}-${Math.random().toString(36).substr(2,4)}`,
                  title: nextStep.name, processName: def.name, processInstanceId: instanceId,
                  assignee: nextStep.role ? '' : (stateRef.current.currentUser?.id || ''), // Auto-assign to current user if no role for demo, else unassigned
                  candidateRoles: nextStep.role ? [nextStep.role] : [],
                  candidateGroups: nextStep.groupId ? [nextStep.groupId] : [],
                  requiredSkills: nextStep.requiredSkills || [],
                  dueDate: new Date(Date.now() + (nextStep.slaDays || 3) * 86400000).toISOString(),
                  status: TaskStatus.PENDING, priority: TaskPriority.MEDIUM,
                  description: nextStep.description, stepId: nextId, data: {}, comments: [], attachments: [], isAdHoc: false, formId: nextStep.formId
              };
              await dbService.add('tasks', newTask);
              setState(produce(draft => { draft.tasks.unshift(newTask); }));
              addNotification('info', `New Task Assigned: ${newTask.title}`);
          } else if (nextStep.type === 'end') {
              updates.status = 'Completed';
              updates.endDate = new Date().toISOString();
              updates.activeStepIds = []; // Clear active steps
              addNotification('success', `Process Completed: ${def.name}`);
          } else if (['service-task', 'script-task', 'start', 'exclusive-gateway', 'parallel-gateway'].includes(nextStep.type)) {
              // Auto-execute system tasks/gateways
              setTimeout(() => proceedWorkflow(instanceId, nextId), 500); 
          }
      }

      await dbService.add('instances', { ...instance, ...updates });
      setState(produce(draft => { 
          const idx = draft.instances.findIndex(i => i.id === instanceId);
          if (idx !== -1) draft.instances[idx] = { ...draft.instances[idx], ...updates };
      }));
  };

  const startProcess = useCallback(async (definitionId: string, inputData: any, caseId?: string) => {
      const def = stateRef.current.processes.find(p => p.id === definitionId);
      if(!def) throw new Error('Process definition not found');

      const startNode = def.steps.find(s => s.type === 'start');
      if (!startNode) { addNotification('error', 'Process has no start event'); return ''; }

      const newInstance: ProcessInstance = {
          id: `inst-${Date.now()}`,
          definitionId: def.id,
          definitionName: def.name,
          status: 'Active',
          startDate: new Date().toISOString(),
          activeStepIds: [startNode.id],
          variables: { ...inputData, sys_startedBy: stateRef.current.currentUser?.id, sys_caseId: caseId },
          priority: TaskPriority.MEDIUM,
          history: [], comments: [], complianceVerified: false, domainId: def.domainId
      };

      await dbService.add('instances', newInstance);
      setState(produce(draft => { draft.instances.unshift(newInstance); }));
      addNotification('success', `Started ${def.name}`);
      addAudit('PROCESS_START', 'Instance', newInstance.id, `Started process ${def.name}`);

      // Kick off the engine
      proceedWorkflow(newInstance.id, startNode.id);

      return newInstance.id;
  }, [addNotification, addAudit]);

  const completeTask = useCallback(async (taskId: string, action: string, comments: string, formData?: any) => {
      const task = stateRef.current.tasks.find(t => t.id === taskId);
      if (!task) return;

      // 1. Update Task
      const updates: Partial<Task> = { status: TaskStatus.COMPLETED, data: { ...task.data, ...formData } };
      await dbService.add('tasks', { ...task, ...updates });
      setState(produce(draft => {
          const t = draft.tasks.find(x => x.id === taskId);
          if (t) { t.status = TaskStatus.COMPLETED; t.data = { ...t.data, ...formData }; }
      }));

      // 2. Update Instance & Move Token
      if (task.processInstanceId) {
          const instance = stateRef.current.instances.find(i => i.id === task.processInstanceId);
          if (instance) {
              // Merge form data into instance variables
              const updatedVariables = { ...instance.variables, ...formData };
              await dbService.add('instances', { ...instance, variables: updatedVariables });
              setState(produce(draft => {
                  const i = draft.instances.find(x => x.id === task.processInstanceId);
                  if (i) i.variables = updatedVariables;
              }));

              // Proceed
              proceedWorkflow(task.processInstanceId, task.stepId);
          }
      }

      addAudit('TASK_COMPLETE', 'Task', taskId, `Completed task ${task.title} with action: ${action}`);
  }, [addAudit]);

  // --- CRUD WRAPPERS ---
  const deployProcess = useCallback(async (p: Partial<ProcessDefinition>) => { 
    const newDef = { ...p, id: p.id || `proc-${Date.now()}`, createdAt: new Date().toISOString(), deployedBy: stateRef.current.currentUser?.name || 'System', version: (p.version || 0) + 1, history: [] } as ProcessDefinition;
    await dbService.add('processes', newDef); 
    setState(produce(draft => { 
        const idx = draft.processes.findIndex(x => x.id === newDef.id);
        if (idx !== -1) draft.processes[idx] = newDef; else draft.processes.push(newDef);
    }));
    addAudit('PROCESS_DEPLOY', 'Process', newDef.id, `Deployed model: ${newDef.name} v${newDef.version}`);
  }, [addAudit]);

  const updateProcess = useCallback(async (id: string, updates: Partial<ProcessDefinition>) => {
    const p = stateRef.current.processes.find(x => x.id === id);
    if(p) {
        const up = { ...p, ...updates };
        await dbService.add('processes', up);
        setState(produce(draft => { draft.processes = draft.processes.map(x => x.id === id ? up : x); }));
    }
  }, []);

  const deleteProcess = useCallback(async (id: string) => {
      await dbService.delete('processes', id);
      setState(produce(draft => { draft.processes = draft.processes.filter(x => x.id !== id); }));
      addAudit('PROCESS_DELETE', 'Process', id, 'Removed process definition', 'Warning');
  }, [addAudit]);

  const createCase = useCallback(async (title: string, description: string, options: any = {}) => {
      const newCase: Case = {
          id: `case-${Date.now()}`, title, description,
          status: 'Open', priority: options.priority || TaskPriority.MEDIUM,
          createdAt: new Date().toISOString(), stakeholders: [],
          data: options.data || {}, timeline: [], policies: [], attachments: [],
          domainId: stateRef.current.currentUser?.domainId || 'GLOBAL'
      };
      if (options.ownerId) newCase.stakeholders.push({ userId: options.ownerId, role: 'Owner' });

      await dbService.add('cases', newCase);
      setState(produce(draft => { draft.cases.unshift(newCase); }));
      addAudit('CASE_CREATE', 'Case', newCase.id, `Created case: ${title}`);
      return newCase.id;
  }, [addAudit]);

  // ... Other simple CRUDs (users, roles, etc) omitted for brevity but would follow same pattern using stateRef for current data access

  // --- CONTEXT EXPORT ---
  const contextValue: BPMContextType = useMemo(() => ({
    ...state,
    setGlobalSearch: (s) => setState(prev => ({ ...prev, globalSearch: s })),
    setDesignerDraft: (draft) => setState(prev => ({ ...prev, designerDraft: draft })),
    setToolbarConfig, toolbarConfig,
    navigateTo, openInstanceViewer: (id) => setState(prev => ({ ...prev, viewingInstanceId: id })),
    closeInstanceViewer: () => setState(prev => ({ ...prev, viewingInstanceId: null })),
    switchUser: (id) => { const u = state.users.find(u => u.id === id); if (u) { setState(prev => ({ ...prev, currentUser: u })); navigateTo('dashboard'); } },
    addNotification, removeNotification,

    startProcess, completeTask,

    executeRules: async (ruleId, fact) => { return { matched: false }; }, // Placeholder for Phase 4
    deployProcess, updateProcess, deleteProcess,
    toggleProcessState: async (id) => {},

    // Stubbed CRUDs to satisfy interface
    suspendInstance: async () => {}, terminateInstance: async () => {}, addInstanceComment: async (id, txt) => {
        const inst = stateRef.current.instances.find(i => i.id === id);
        if(inst) {
            const comment = { id: `c-${Date.now()}`, userId: stateRef.current.currentUser?.id || '', userName: stateRef.current.currentUser?.name || 'User', text: txt, timestamp: new Date().toISOString() };
            const up = { ...inst, comments: [...inst.comments, comment] };
            await dbService.add('instances', up);
            setState(produce(draft => { const idx = draft.instances.findIndex(x => x.id === id); if(idx !== -1) draft.instances[idx].comments.push(comment); }));
        }
    },
    claimTask: async () => {}, releaseTask: async () => {}, reassignTask: async () => {}, updateTaskMetadata: async () => {},
    addTaskComment: async (id, txt) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            const c = { id: `c-${Date.now()}`, userId: stateRef.current.currentUser?.id || '', userName: stateRef.current.currentUser?.name || 'User', text: txt, timestamp: new Date().toISOString() };
            await dbService.add('tasks', { ...t, comments: [...t.comments, c] });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].comments.push(c); }));
        }
    },
    updateTaskChecklist: async (id, items) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            await dbService.add('tasks', { ...t, checklist: items });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].checklist = items; }));
        }
    },
    bulkCompleteTasks: async () => {}, toggleTaskStar: async (id) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            await dbService.add('tasks', { ...t, isStarred: !t.isStarred });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].isStarred = !draft.tasks[idx].isStarred; }));
        }
    },
    snoozeTask: async () => {}, 
    createAdHocTask: async (title) => {
        const t: Task = {
            id: `task-${Date.now()}`, title, processName: 'Ad-Hoc', processInstanceId: '', assignee: stateRef.current.currentUser?.id || '', candidateRoles: [], candidateGroups: [], requiredSkills: [],
            dueDate: new Date().toISOString(), status: TaskStatus.PENDING, priority: TaskPriority.MEDIUM, stepId: 'adhoc', data: {}, comments: [], attachments: [], isAdHoc: true
        };
        await dbService.add('tasks', t);
        setState(produce(draft => { draft.tasks.unshift(t); }));
    },
    updateTaskLocation: async () => {},
    createCase, updateCase: async (id, up) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) { await dbService.add('cases', { ...c, ...up }); setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) Object.assign(draft.cases[idx], up); })); }
    }, deleteCase: async () => {}, 
    addCaseEvent: async (id, desc) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const ev = { id: `evt-${Date.now()}`, timestamp: new Date().toISOString(), type: 'Manual' as const, description: desc, author: stateRef.current.currentUser?.name || 'System' };
            await dbService.add('cases', { ...c, timeline: [ev, ...c.timeline] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].timeline.unshift(ev); }));
        }
    },
    removeCaseEvent: async () => {}, addCasePolicy: async (id, txt) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const p = { id: `pol-${Date.now()}`, description: txt, isEnforced: true };
            await dbService.add('cases', { ...c, policies: [...c.policies, p] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].policies.push(p); }));
        }
    },
    removeCasePolicy: async () => {}, addCaseStakeholder: async (id, uid, role) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const sh = { userId: uid, role: role as any };
            await dbService.add('cases', { ...c, stakeholders: [...c.stakeholders, sh] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].stakeholders.push(sh); }));
        }
    },
    removeCaseStakeholder: async () => {},
    saveRule: async (r) => { await dbService.add('rules', r); setState(produce(draft => { const idx = draft.rules.findIndex(x => x.id === r.id); if(idx!==-1) draft.rules[idx] = r; else draft.rules.push(r); })); },
    deleteRule: async (id) => { await dbService.delete('rules', id); setState(produce(draft => { draft.rules = draft.rules.filter(x => x.id !== id); })); },
    cloneRule: async () => {},
    saveDecisionTable: async (t) => { await dbService.add('decisionTables', t); setState(produce(draft => { const idx = draft.decisionTables.findIndex(x => x.id === t.id); if(idx!==-1) draft.decisionTables[idx] = t; else draft.decisionTables.push(t); })); },
    deleteDecisionTable: async (id) => { await dbService.delete('decisionTables', id); setState(produce(draft => { draft.decisionTables = draft.decisionTables.filter(x => x.id !== id); })); },
    saveForm: async (f) => { await dbService.add('forms', f); setState(produce(draft => { const idx = draft.forms.findIndex(x => x.id === f.id); if(idx!==-1) draft.forms[idx] = f; else draft.forms.push(f); })); },
    deleteForm: async (id) => { await dbService.delete('forms', id); setState(produce(draft => { draft.forms = draft.forms.filter(x => x.id !== id); })); },

    createUser: async (u) => { const nu = { ...u, id: `u-${Date.now()}` }; await dbService.add('users', nu); setState(produce(draft => { draft.users.push(nu); })); },
    updateUser: async (id, up) => { const u = stateRef.current.users.find(x => x.id === id); if(u) { await dbService.add('users', { ...u, ...up }); setState(produce(draft => { const idx = draft.users.findIndex(x => x.id === id); if(idx!==-1) Object.assign(draft.users[idx], up); })); } },
    deleteUser: async (id) => { await dbService.delete('users', id); setState(produce(draft => { draft.users = draft.users.filter(x => x.id !== id); })); },
    createRole: async () => {}, updateRole: async () => {}, deleteRole: async () => {},
    createGroup: async () => {}, updateGroup: async () => {}, deleteGroup: async () => {},
    createDelegation: async (uid, scope) => {
        const d: Delegation = { id: `del-${Date.now()}`, fromUserId: stateRef.current.currentUser?.id || '', toUserId: uid, scope, startDate: new Date().toISOString(), endDate: new Date(Date.now()+86400000).toISOString(), isActive: true };
        await dbService.add('delegations', d);
        setState(produce(draft => { draft.delegations.push(d); }));
    },
    revokeDelegation: async (id) => { await dbService.delete('delegations', id); setState(produce(draft => { draft.delegations = draft.delegations.filter(x => x.id !== id); })); },
    installIntegration: async () => {}, uninstallIntegration: async () => {}, toggleApiClient: async () => {},
    saveView: async (v) => { const nv = { ...v, id: v.id || `view-${Date.now()}` }; await dbService.add('savedViews', nv); setState(produce(draft => { draft.savedViews.push(nv); })); },
    deleteView: async () => {},
    updateSystemSettings: async (up) => { const ns = { ...stateRef.current.settings, ...up }; await dbService.add('systemSettings', ns); setState(prev => ({ ...prev, settings: ns })); },
    hasPermission: (perm) => {
        if (!stateRef.current.currentUser) return false;
        return stateRef.current.currentUser.roleIds.some(rId => {
            const role = stateRef.current.roles.find(r => r.id === rId);
            return role?.permissions.includes(perm) || role?.permissions.includes(Permission.ADMIN_ACCESS);
        });
    },
    getStepStatistics: (defId, stepName) => {
        // Simple implementation
        const instances = stateRef.current.instances.filter(i => i.definitionId === defId);
        let count = 0;
        instances.forEach(i => i.history.forEach(h => { if(h.stepName === stepName) count++; }));
        return { avgDuration: 5, errorRate: 0, totalExecutions: count };
    },
    reseedSystem: async () => { await dbService.reseed(); loadData(); },
    resetSystem: async () => { await dbService.resetDB(); window.location.reload(); },
    exportData: async () => { return dbService.exportData(); },
    importData: async (f) => {},
    getActiveUsersOnRecord: (id) => { const uids = activePresence[id] || []; return stateRef.current.users.filter(u => uids.includes(u.id)); }
  }), [state, navigateTo, addNotification, removeNotification, startProcess, completeTask, createCase, deployProcess, updateProcess, deleteProcess, loadData, setToolbarConfig, activePresence]);

  return <BPMContext.Provider value={contextValue}>{children}</BPMContext.Provider>;
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

import React, { createContext, useContext, useState, ReactNode, useCallback, useEffect, useMemo, useRef } from 'react';
import { produce } from 'immer';
import { 
  ProcessDefinition, ProcessInstance, Task, TaskStatus, TaskPriority, 
  ViewState, AuditLog, Comment, User, UserRole, UserGroup, Permission, 
  Delegation, BusinessRule, DecisionTable, Case, CaseEvent, CasePolicy, CaseStakeholder,
  Condition, RuleAction, ProcessStep, ProcessLink, FormDefinition, ProcessVersionSnapshot, ChecklistItem,
  Integration, ApiClient, SystemSettings, SavedView, ToolbarConfig, TaskHistory
} from '../types';
import { dbService, DEFAULT_SETTINGS } from '../services/dbService';

interface Notification {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
  action?: () => void;
  deepLink?: { view: ViewState; id?: string };
}

interface BPMContextType {
  processes: ProcessDefinition[];
  instances: ProcessInstance[];
  tasks: Task[];
  cases: Case[];
  auditLogs: AuditLog[];
  users: User[];
  roles: UserRole[];
  groups: UserGroup[];
  notifications: Notification[];
  currentUser: User | null;
  loading: boolean;
  globalSearch: string;
  setGlobalSearch: (s: string) => void;

  nav: { view: ViewState; selectedId?: string; filter?: string; data?: any };
  delegations: Delegation[];
  rules: BusinessRule[];
  decisionTables: DecisionTable[];
  forms: FormDefinition[];
  integrations: Integration[]; 
  apiClients: ApiClient[]; 
  settings: SystemSettings;
  savedViews: SavedView[];

  viewingInstanceId: string | null;

  toolbarConfig: ToolbarConfig;
  setToolbarConfig: (config: ToolbarConfig) => void;

  designerDraft: { steps: ProcessStep[], links: ProcessLink[] } | null;
  setDesignerDraft: (draft: { steps: ProcessStep[], links: ProcessLink[] } | null) => void;

  navigateTo: (view: ViewState, id?: string, filter?: string, data?: any) => void;
  openInstanceViewer: (id: string) => void;
  closeInstanceViewer: () => void;
  switchUser: (userId: string) => void;
  addNotification: (type: 'success' | 'error' | 'info', message: string, deepLink?: { view: ViewState; id?: string }) => void;
  removeNotification: (id: string) => void;

  executeRules: (ruleId: string, fact: any) => Promise<any>;

  deployProcess: (process: Partial<ProcessDefinition>) => Promise<void>;
  updateProcess: (id: string, updates: Partial<ProcessDefinition>) => Promise<void>;
  deleteProcess: (id: string) => Promise<void>;
  toggleProcessState: (id: string) => Promise<void>;
  getStepStatistics: (defId: string, stepName: string) => { avgDuration: number, errorRate: number, totalExecutions: number };

  startProcess: (definitionId: string, inputData: any, caseId?: string) => Promise<string>;
  suspendInstance: (id: string) => Promise<void>;
  terminateInstance: (id: string) => Promise<void>;
  addInstanceComment: (instanceId: string, text: string) => Promise<void>;

  completeTask: (taskId: string, action: string, comments: string, formData?: any) => Promise<void>;
  claimTask: (taskId: string) => Promise<void>;
  releaseTask: (taskId: string) => Promise<void>;
  reassignTask: (taskId: string, userId: string) => Promise<void>;
  updateTaskMetadata: (taskId: string, updates: Partial<Task>) => Promise<void>;
  addTaskComment: (taskId: string, text: string) => Promise<void>;
  updateTaskChecklist: (taskId: string, items: ChecklistItem[]) => Promise<void>;
  bulkCompleteTasks: (taskIds: string[], action: 'approve' | 'reject') => Promise<void>;
  toggleTaskStar: (taskId: string) => Promise<void>;
  snoozeTask: (taskId: string, until: string) => Promise<void>;
  createAdHocTask: (title: string, priority?: TaskPriority) => Promise<void>;
  updateTaskLocation: (taskId: string, lat: number, lng: number) => Promise<void>; 

  createCase: (title: string, description: string, options?: { priority?: TaskPriority, data?: any, ownerId?: string }) => Promise<string>;
  updateCase: (id: string, updates: Partial<Case>) => Promise<void>;
  deleteCase: (id: string) => Promise<void>;
  addCaseEvent: (caseId: string, description: string) => Promise<void>;
  removeCaseEvent: (caseId: string, eventId: string) => Promise<void>;
  addCasePolicy: (caseId: string, policy: string) => Promise<void>;
  removeCasePolicy: (caseId: string, policyId: string) => Promise<void>;
  addCaseStakeholder: (caseId: string, userId: string, role: string) => Promise<void>;
  removeCaseStakeholder: (caseId: string, userId: string) => Promise<void>;

  saveRule: (rule: BusinessRule) => Promise<void>;
  deleteRule: (id: string) => Promise<void>;
  cloneRule: (id: string) => Promise<void>;
  saveDecisionTable: (table: DecisionTable) => Promise<void>;
  deleteDecisionTable: (id: string) => Promise<void>;

  saveForm: (form: FormDefinition) => Promise<void>;
  deleteForm: (id: string) => Promise<void>;

  createUser: (user: Omit<User, 'id'>) => Promise<void>;
  updateUser: (id: string, updates: Partial<User>) => Promise<void>;
  deleteUser: (id: string) => Promise<void>;
  createRole: (role: Omit<UserRole, 'id'>) => Promise<void>;
  updateRole: (id: string, updates: Partial<UserRole>) => Promise<void>;
  deleteRole: (id: string) => Promise<void>;
  createGroup: (group: Omit<UserGroup, 'id'>) => Promise<void>;
  updateGroup: (id: string, updates: Partial<UserGroup>) => Promise<void>;
  deleteGroup: (id: string) => Promise<void>;

  createDelegation: (toUserId: string, scope: 'All' | 'Critical Only') => Promise<void>;
  revokeDelegation: (id: string) => Promise<void>;

  installIntegration: (id: string, config: Record<string, string>) => Promise<void>;
  uninstallIntegration: (id: string) => Promise<void>;

  toggleApiClient: (id: string) => Promise<void>;

  saveView: (view: SavedView) => Promise<void>;
  deleteView: (id: string) => Promise<void>;

  updateSystemSettings: (updates: Partial<SystemSettings>) => Promise<void>;
  hasPermission: (perm: Permission) => boolean;
  reseedSystem: () => Promise<void>;
  resetSystem: () => Promise<void>;
  exportData: () => Promise<void>;
  importData: (file: File) => Promise<void>;

  getActiveUsersOnRecord: (recordId: string) => User[];
}

const BPMContext = createContext<BPMContextType | undefined>(undefined);

export const BPMProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState({
    processes: [] as ProcessDefinition[],
    instances: [] as ProcessInstance[],
    tasks: [] as Task[],
    cases: [] as Case[],
    auditLogs: [] as AuditLog[],
    users: [] as User[],
    roles: [] as UserRole[],
    groups: [] as UserGroup[],
    delegations: [] as Delegation[],
    rules: [] as BusinessRule[],
    decisionTables: [] as DecisionTable[],
    forms: [] as FormDefinition[],
    integrations: [] as Integration[],
    apiClients: [] as ApiClient[],
    settings: DEFAULT_SETTINGS,
    savedViews: [] as SavedView[],
    notifications: [] as Notification[],
    globalSearch: '',
    nav: { view: 'dashboard' } as { view: ViewState; selectedId?: string; filter?: string; data?: any },
    viewingInstanceId: null as string | null,
    currentUser: null as User | null,
    loading: true,
    designerDraft: null as { steps: ProcessStep[], links: ProcessLink[] } | null
  });

  const [toolbarConfig, setToolbarConfigState] = useState<ToolbarConfig>({});
  const setToolbarConfig = useCallback((config: ToolbarConfig) => { setToolbarConfigState(config); }, []);
  const [activePresence, setActivePresence] = useState<Record<string, string[]>>({}); 

  // --- REFS for Engine Access to Latest State (Simulates Backend DB Access) ---
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  const loadData = useCallback(async () => {
    try {
      const [p, inst, t, c, logs, u, r, g, d, bRules, tables, f, ints, apis, setts, views] = await Promise.all([
        dbService.getAll<ProcessDefinition>('processes'),
        dbService.getAll<ProcessInstance>('instances'),
        dbService.getAll<Task>('tasks'),
        dbService.getAll<Case>('cases'),
        dbService.getAll<AuditLog>('auditLogs'),
        dbService.getAll<User>('users'),
        dbService.getAll<UserRole>('roles'),
        dbService.getAll<UserGroup>('groups'),
        dbService.getAll<Delegation>('delegations'),
        dbService.getAll<BusinessRule>('rules'),
        dbService.getAll<DecisionTable>('decisionTables'),
        dbService.getAll<FormDefinition>('forms'),
        dbService.getAll<Integration>('integrations'),
        dbService.getAll<ApiClient>('apiClients'),
        dbService.getAll<SystemSettings>('systemSettings'),
        dbService.getAll<SavedView>('savedViews')
      ]);

      setState(prev => ({
        ...prev,
        processes: p, instances: inst, tasks: t, cases: c,
        auditLogs: logs.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()),
        users: u, roles: r, groups: g, delegations: d,
        rules: bRules, decisionTables: tables, forms: f,
        integrations: ints, apiClients: apis, settings: setts[0] || DEFAULT_SETTINGS, savedViews: views,
        currentUser: prev.currentUser || u[0] || null,
        loading: false
      }));
    } catch (e) {
      console.error("Context Load Failure:", e);
      setState(prev => ({ ...prev, loading: false }));
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  // --- HELPERS ---
  const addAudit = useCallback(async (action: string, type: AuditLog['entityType'], id: string, details: string, severity: AuditLog['severity'] = 'Info') => {
    const log: AuditLog = {
      id: `log-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      timestamp: new Date().toISOString(),
      userId: stateRef.current.currentUser?.name || 'System',
      action, entityType: type, entityId: id, details, severity
    };
    await dbService.add('auditLogs', log);
    setState(produce(draft => { draft.auditLogs.unshift(log); }));
  }, []);

  const addNotification = useCallback((type: 'success' | 'error' | 'info', message: string, deepLink?: { view: ViewState; id?: string }) => {
    const n: Notification = { id: `n-${Date.now()}`, type, message, deepLink };
    setState(produce(draft => { draft.notifications.push(n); }));
    setTimeout(() => setState(produce(draft => { draft.notifications = draft.notifications.filter(x => x.id !== n.id); })), 5000);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setState(produce(draft => { draft.notifications = draft.notifications.filter(x => x.id !== id); }));
  }, []);

  const navigateTo = useCallback((view: ViewState, id?: string, filter?: string, data?: any) => {
    setState(produce(draft => { draft.nav = { view, selectedId: id, filter, data }; draft.globalSearch = ''; }));
    setToolbarConfig({});
  }, [setToolbarConfig]);

  // --- ORACLE BPM ENGINE SIMULATION ---

  const evaluateCondition = (condition: string, variables: any) => {
      try {
          // Simple safe eval for demo purposes. 
          // Replaces variable names with values from instance payload
          let expr = condition;
          Object.keys(variables).forEach(key => {
              const val = typeof variables[key] === 'string' ? `'${variables[key]}'` : variables[key];
              // Basic regex replace for whole words matching variable keys
              expr = expr.replace(new RegExp(`\\b${key}\\b`, 'g'), String(val));
          });
          // eslint-disable-next-line no-eval
          return eval(expr); 
      } catch (e) {
          console.warn('Condition Eval Failed:', condition, e);
          return false;
      }
  };

  const proceedWorkflow = async (instanceId: string, currentStepId: string) => {
      const instance = stateRef.current.instances.find(i => i.id === instanceId);
      if (!instance) return;
      const def = stateRef.current.processes.find(p => p.id === instance.definitionId);
      if (!def) return;

      const currentStep = def.steps.find(s => s.id === currentStepId);

      // 1. Audit / Flow Trace
      const historyEntry: TaskHistory = {
          id: `h-${Date.now()}`, stepName: currentStep?.name || 'Unknown', stepId: currentStepId,
          action: 'Completed', performer: 'System', timestamp: new Date().toISOString()
      };

      // 2. Token Navigation Logic
      const outgoingLinks = def.links?.filter(l => l.sourceId === currentStepId) || [];
      let nextStepIds: string[] = [];

      if (currentStep?.type === 'exclusive-gateway') {
          // XOR Gateway: Find first true condition
          const match = outgoingLinks.find(l => l.condition && evaluateCondition(l.condition, instance.variables));
          if (match) nextStepIds.push(match.targetId);
          else {
              // Default path
              const defaultLink = outgoingLinks.find(l => l.isDefault) || outgoingLinks[0];
              if (defaultLink) nextStepIds.push(defaultLink.targetId);
          }
      } else if (currentStep?.type === 'parallel-gateway') {
          // AND Gateway: Split token
          nextStepIds = outgoingLinks.map(l => l.targetId);
      } else {
          // Standard Sequence Flow
          nextStepIds = outgoingLinks.map(l => l.targetId);
      }

      // 3. Update Instance State
      const updates: Partial<ProcessInstance> = {
          activeStepIds: nextStepIds,
          history: [...instance.history, historyEntry]
      };

      // 4. Activate Next Nodes
      for (const nextId of nextStepIds) {
          const nextStep = def.steps.find(s => s.id === nextId);
          if (!nextStep) continue;

          if (nextStep.type === 'user-task') {
              // Human Workflow: Create Task
              const newTask: Task = {
                  id: `task-${Date.now()}-${Math.random().toString(36).substr(2,4)}`,
                  title: nextStep.name, processName: def.name, processInstanceId: instanceId,
                  assignee: nextStep.role ? '' : (stateRef.current.currentUser?.id || ''), // Auto-assign if no role
                  candidateRoles: nextStep.role ? [nextStep.role] : [],
                  candidateGroups: nextStep.groupId ? [nextStep.groupId] : [],
                  requiredSkills: nextStep.requiredSkills || [],
                  dueDate: new Date(Date.now() + (nextStep.slaDays || 3) * 86400000).toISOString(),
                  status: TaskStatus.PENDING, priority: TaskPriority.MEDIUM,
                  description: nextStep.description, stepId: nextId, data: {}, comments: [], attachments: [], isAdHoc: false, formId: nextStep.formId
              };
              await dbService.add('tasks', newTask);
              setState(produce(draft => { draft.tasks.unshift(newTask); }));
              addNotification('info', `New Task Assigned: ${newTask.title}`);
          } else if (nextStep.type === 'end') {
              updates.status = 'Completed';
              updates.endDate = new Date().toISOString();
              updates.activeStepIds = []; // Clear active steps
              addNotification('success', `Process Completed: ${def.name}`);
          } else if (['service-task', 'script-task', 'start', 'exclusive-gateway', 'parallel-gateway'].includes(nextStep.type)) {
              // Service Integration / System Tasks: Auto-execute
              // Simulating OSB/BPEL execution latency
              setTimeout(() => proceedWorkflow(instanceId, nextId), 500); 
          }
      }

      await dbService.add('instances', { ...instance, ...updates });
      setState(produce(draft => { 
          const idx = draft.instances.findIndex(i => i.id === instanceId);
          if (idx !== -1) draft.instances[idx] = { ...draft.instances[idx], ...updates };
      }));
  };

  const startProcess = useCallback(async (definitionId: string, inputData: any, caseId?: string) => {
      const def = stateRef.current.processes.find(p => p.id === definitionId);
      if(!def) throw new Error('Process definition not found');

      const startNode = def.steps.find(s => s.type === 'start');
      if (!startNode) { addNotification('error', 'Process has no start event'); return ''; }

      const newInstance: ProcessInstance = {
          id: `inst-${Date.now()}`,
          definitionId: def.id,
          definitionName: def.name,
          status: 'Active',
          startDate: new Date().toISOString(),
          activeStepIds: [startNode.id],
          variables: { ...inputData, sys_startedBy: stateRef.current.currentUser?.id, sys_caseId: caseId },
          priority: TaskPriority.MEDIUM,
          history: [], comments: [], complianceVerified: false, domainId: def.domainId
      };

      await dbService.add('instances', newInstance);
      setState(produce(draft => { draft.instances.unshift(newInstance); }));
      addNotification('success', `Started ${def.name}`);
      addAudit('PROCESS_START', 'Instance', newInstance.id, `Started process ${def.name}`);

      // Kick off the engine
      proceedWorkflow(newInstance.id, startNode.id);

      return newInstance.id;
  }, [addNotification, addAudit]);

  const completeTask = useCallback(async (taskId: string, action: string, comments: string, formData?: any) => {
      const task = stateRef.current.tasks.find(t => t.id === taskId);
      if (!task) return;

      // 1. Update Task Status
      const updates: Partial<Task> = { status: TaskStatus.COMPLETED, data: { ...task.data, ...formData } };
      await dbService.add('tasks', { ...task, ...updates });
      setState(produce(draft => {
          const t = draft.tasks.find(x => x.id === taskId);
          if (t) { t.status = TaskStatus.COMPLETED; t.data = { ...t.data, ...formData }; }
      }));

      // 2. Update Instance Payload (Form Data Merging)
      if (task.processInstanceId) {
          const instance = stateRef.current.instances.find(i => i.id === task.processInstanceId);
          if (instance) {
              const updatedVariables = { ...instance.variables, ...formData };
              await dbService.add('instances', { ...instance, variables: updatedVariables });
              setState(produce(draft => {
                  const i = draft.instances.find(x => x.id === task.processInstanceId);
                  if (i) i.variables = updatedVariables;
              }));

              // 3. Move Token Forward
              proceedWorkflow(task.processInstanceId, task.stepId);
          }
      }

      addAudit('TASK_COMPLETE', 'Task', taskId, `Completed task ${task.title} with action: ${action}`);
  }, [addAudit]);

  // --- CRUD WRAPPERS ---
  const deployProcess = useCallback(async (p: Partial<ProcessDefinition>) => { 
    const newDef = { ...p, id: p.id || `proc-${Date.now()}`, createdAt: new Date().toISOString(), deployedBy: stateRef.current.currentUser?.name || 'System', version: (p.version || 0) + 1, history: [] } as ProcessDefinition;
    await dbService.add('processes', newDef); 
    setState(produce(draft => { 
        const idx = draft.processes.findIndex(x => x.id === newDef.id);
        if (idx !== -1) draft.processes[idx] = newDef; else draft.processes.push(newDef);
    }));
    addAudit('PROCESS_DEPLOY', 'Process', newDef.id, `Deployed model: ${newDef.name} v${newDef.version}`);
  }, [addAudit]);

  const updateProcess = useCallback(async (id: string, updates: Partial<ProcessDefinition>) => {
    const p = stateRef.current.processes.find(x => x.id === id);
    if(p) {
        const up = { ...p, ...updates };
        await dbService.add('processes', up);
        setState(produce(draft => { draft.processes = draft.processes.map(x => x.id === id ? up : x); }));
    }
  }, []);

  const deleteProcess = useCallback(async (id: string) => {
      await dbService.delete('processes', id);
      setState(produce(draft => { draft.processes = draft.processes.filter(x => x.id !== id); }));
      addAudit('PROCESS_DELETE', 'Process', id, 'Removed process definition', 'Warning');
  }, [addAudit]);

  const createCase = useCallback(async (title: string, description: string, options: any = {}) => {
      const newCase: Case = {
          id: `case-${Date.now()}`, title, description,
          status: 'Open', priority: options.priority || TaskPriority.MEDIUM,
          createdAt: new Date().toISOString(), stakeholders: [],
          data: options.data || {}, timeline: [], policies: [], attachments: [],
          domainId: stateRef.current.currentUser?.domainId || 'GLOBAL'
      };
      if (options.ownerId) newCase.stakeholders.push({ userId: options.ownerId, role: 'Owner' });

      await dbService.add('cases', newCase);
      setState(produce(draft => { draft.cases.unshift(newCase); }));
      addAudit('CASE_CREATE', 'Case', newCase.id, `Created case: ${title}`);
      return newCase.id;
  }, [addAudit]);

  // ... Other simple CRUDs
  const createUser = useCallback(async (u: Omit<User, 'id'>) => { const nu = { ...u, id: `u-${Date.now()}` }; await dbService.add('users', nu); setState(produce(draft => { draft.users.push(nu); })); }, []);
  const updateUser = useCallback(async (id: string, up: Partial<User>) => { const u = stateRef.current.users.find(x => x.id === id); if(u) { await dbService.add('users', { ...u, ...up }); setState(produce(draft => { const idx = draft.users.findIndex(x => x.id === id); if(idx!==-1) Object.assign(draft.users[idx], up); })); } }, []);
  const deleteUser = useCallback(async (id: string) => { await dbService.delete('users', id); setState(produce(draft => { draft.users = draft.users.filter(x => x.id !== id); })); }, []);

  // --- CONTEXT EXPORT ---
  const contextValue: BPMContextType = useMemo(() => ({
    ...state,
    setGlobalSearch: (s) => setState(prev => ({ ...prev, globalSearch: s })),
    setDesignerDraft: (draft) => setState(prev => ({ ...prev, designerDraft: draft })),
    setToolbarConfig, toolbarConfig,
    navigateTo, openInstanceViewer: (id) => setState(prev => ({ ...prev, viewingInstanceId: id })),
    closeInstanceViewer: () => setState(prev => ({ ...prev, viewingInstanceId: null })),
    switchUser: (id) => { const u = state.users.find(u => u.id === id); if (u) { setState(prev => ({ ...prev, currentUser: u })); navigateTo('dashboard'); } },
    addNotification, removeNotification,

    startProcess, completeTask,

    executeRules: async (ruleId, fact) => { return { matched: false }; }, 
    deployProcess, updateProcess, deleteProcess,
    toggleProcessState: async (id) => {},

    suspendInstance: async () => {}, terminateInstance: async () => {}, addInstanceComment: async (id, txt) => {
        const inst = stateRef.current.instances.find(i => i.id === id);
        if(inst) {
            const comment = { id: `c-${Date.now()}`, userId: stateRef.current.currentUser?.id || '', userName: stateRef.current.currentUser?.name || 'User', text: txt, timestamp: new Date().toISOString() };
            const up = { ...inst, comments: [...inst.comments, comment] };
            await dbService.add('instances', up);
            setState(produce(draft => { const idx = draft.instances.findIndex(x => x.id === id); if(idx !== -1) draft.instances[idx].comments.push(comment); }));
        }
    },
    claimTask: async () => {}, releaseTask: async () => {}, reassignTask: async () => {}, updateTaskMetadata: async () => {},
    addTaskComment: async (id, txt) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            const c = { id: `c-${Date.now()}`, userId: stateRef.current.currentUser?.id || '', userName: stateRef.current.currentUser?.name || 'User', text: txt, timestamp: new Date().toISOString() };
            await dbService.add('tasks', { ...t, comments: [...t.comments, c] });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].comments.push(c); }));
        }
    },
    updateTaskChecklist: async (id, items) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            await dbService.add('tasks', { ...t, checklist: items });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].checklist = items; }));
        }
    },
    bulkCompleteTasks: async () => {}, toggleTaskStar: async (id) => {
        const t = stateRef.current.tasks.find(x => x.id === id);
        if(t) {
            await dbService.add('tasks', { ...t, isStarred: !t.isStarred });
            setState(produce(draft => { const idx = draft.tasks.findIndex(x => x.id === id); if(idx!==-1) draft.tasks[idx].isStarred = !draft.tasks[idx].isStarred; }));
        }
    },
    snoozeTask: async () => {}, 
    createAdHocTask: async (title) => {
        const t: Task = {
            id: `task-${Date.now()}`, title, processName: 'Ad-Hoc', processInstanceId: '', assignee: stateRef.current.currentUser?.id || '', candidateRoles: [], candidateGroups: [], requiredSkills: [],
            dueDate: new Date().toISOString(), status: TaskStatus.PENDING, priority: TaskPriority.MEDIUM, stepId: 'adhoc', data: {}, comments: [], attachments: [], isAdHoc: true
        };
        await dbService.add('tasks', t);
        setState(produce(draft => { draft.tasks.unshift(t); }));
    },
    updateTaskLocation: async () => {},
    createCase, updateCase: async (id, up) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) { await dbService.add('cases', { ...c, ...up }); setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) Object.assign(draft.cases[idx], up); })); }
    }, deleteCase: async () => {}, 
    addCaseEvent: async (id, desc) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const ev = { id: `evt-${Date.now()}`, timestamp: new Date().toISOString(), type: 'Manual' as const, description: desc, author: stateRef.current.currentUser?.name || 'System' };
            await dbService.add('cases', { ...c, timeline: [ev, ...c.timeline] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].timeline.unshift(ev); }));
        }
    },
    removeCaseEvent: async () => {}, addCasePolicy: async (id, txt) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const p = { id: `pol-${Date.now()}`, description: txt, isEnforced: true };
            await dbService.add('cases', { ...c, policies: [...c.policies, p] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].policies.push(p); }));
        }
    },
    removeCasePolicy: async () => {}, addCaseStakeholder: async (id, uid, role) => {
        const c = stateRef.current.cases.find(x => x.id === id);
        if(c) {
            const sh = { userId: uid, role: role as any };
            await dbService.add('cases', { ...c, stakeholders: [...c.stakeholders, sh] });
            setState(produce(draft => { const idx = draft.cases.findIndex(x => x.id === id); if(idx!==-1) draft.cases[idx].stakeholders.push(sh); }));
        }
    },
    removeCaseStakeholder: async () => {},
    saveRule: async (r) => { await dbService.add('rules', r); setState(produce(draft => { const idx = draft.rules.findIndex(x => x.id === r.id); if(idx!==-1) draft.rules[idx] = r; else draft.rules.push(r); })); },
    deleteRule: async (id) => { await dbService.delete('rules', id); setState(produce(draft => { draft.rules = draft.rules.filter(x => x.id !== id); })); },
    cloneRule: async () => {},
    saveDecisionTable: async (t) => { await dbService.add('decisionTables', t); setState(produce(draft => { const idx = draft.decisionTables.findIndex(x => x.id === t.id); if(idx!==-1) draft.decisionTables[idx] = t; else draft.decisionTables.push(t); })); },
    deleteDecisionTable: async (id) => { await dbService.delete('decisionTables', id); setState(produce(draft => { draft.decisionTables = draft.decisionTables.filter(x => x.id !== id); })); },
    saveForm: async (f) => { await dbService.add('forms', f); setState(produce(draft => { const idx = draft.forms.findIndex(x => x.id === f.id); if(idx!==-1) draft.forms[idx] = f; else draft.forms.push(f); })); },
    deleteForm: async (id) => { await dbService.delete('forms', id); setState(produce(draft => { draft.forms = draft.forms.filter(x => x.id !== id); })); },

    createUser, updateUser, deleteUser,
    createRole: async () => {}, updateRole: async () => {}, deleteRole: async () => {},
    createGroup: async () => {}, updateGroup: async () => {}, deleteGroup: async () => {},
    createDelegation: async (uid, scope) => {
        const d: Delegation = { id: `del-${Date.now()}`, fromUserId: stateRef.current.currentUser?.id || '', toUserId: uid, scope, startDate: new Date().toISOString(), endDate: new Date(Date.now()+86400000).toISOString(), isActive: true };
        await dbService.add('delegations', d);
        setState(produce(draft => { draft.delegations.push(d); }));
    },
    revokeDelegation: async (id) => { await dbService.delete('delegations', id); setState(produce(draft => { draft.delegations = draft.delegations.filter(x => x.id !== id); })); },
    installIntegration: async () => {}, uninstallIntegration: async () => {}, toggleApiClient: async () => {},
    saveView: async (v) => { const nv = { ...v, id: v.id || `view-${Date.now()}` }; await dbService.add('savedViews', nv); setState(produce(draft => { draft.savedViews.push(nv); })); },
    deleteView: async () => {},
    updateSystemSettings: async (up) => { const ns = { ...stateRef.current.settings, ...up }; await dbService.add('systemSettings', ns); setState(prev => ({ ...prev, settings: ns })); },
    hasPermission: (perm) => {
        if (!stateRef.current.currentUser) return false;
        return stateRef.current.currentUser.roleIds.some(rId => {
            const role = stateRef.current.roles.find(r => r.id === rId);
            return role?.permissions.includes(perm) || role?.permissions.includes(Permission.ADMIN_ACCESS);
        });
    },
    getStepStatistics: (defId, stepName) => {
        const instances = stateRef.current.instances.filter(i => i.definitionId === defId);
        let count = 0;
        instances.forEach(i => i.history.forEach(h => { if(h.stepName === stepName) count++; }));
        return { avgDuration: 5, errorRate: 0, totalExecutions: count };
    },
    reseedSystem: async () => { await dbService.reseed(); loadData(); },
    resetSystem: async () => { await dbService.resetDB(); window.location.reload(); },
    exportData: async () => { return dbService.exportData(); },
    importData: async (f) => {},
    getActiveUsersOnRecord: (id) => { const uids = activePresence[id] || []; return stateRef.current.users.filter(u => uids.includes(u.id)); }
  }), [state, navigateTo, addNotification, removeNotification, startProcess, completeTask, createCase, deployProcess, updateProcess, deleteProcess, loadData, setToolbarConfig, activePresence]);

  return <BPMContext.Provider value={contextValue}>{children}</BPMContext.Provider>;
};

export const useBPM = () => {
  const context = useContext(BPMContext);
  if (!context) throw new Error('useBPM must be used within a BPMProvider');
  return context;
};

