            </div>
            <div className="p-4 space-y-6 flex-1 flex flex-col min-h-0 overflow-y-auto">
                <div className="space-y-2">
                    <h4 className="text-xs font-bold text-secondary uppercase">Test Suite Library</h4>
                    <div className="space-y-1">
                        {testCases.map(tc => (
