export interface ToolbarAction {
  label: string;
  action?: () => void;
  shortcut?: string;
  disabled?: boolean;
  divider?: boolean;
}

export interface ToolbarConfig {
  file?: ToolbarAction[];
  edit?: ToolbarAction[];
