    const parentMap: Record<string, ViewState> = {
        'case-viewer': 'cases',
        'create-case': 'cases',
        'edit-case': 'cases',
        'form-designer': 'forms',
        'edit-user': 'identity',
        'create-user': 'identity',
        'create-role': 'identity',
