import { FormDefinition, FormField, FormFieldType, FormValidation, FormFieldLayout, FormFieldAppearance, FormDataSource, FormBehavior, FieldPermission } from '../types';
import { FormPageLayout } from './shared/PageTemplates';
import { NexFormGroup } from './shared/NexUI';
import { 
  Type, Hash, Calendar, CheckSquare, List, AlignLeft, FileText, 
  Trash2, GripVertical, Settings, Info, Upload, PenTool, EyeOff, AlertTriangle,
  PanelLeft, PanelRight, Smartphone, Monitor, Star, Sliders, Tag, Palette, Lock, Clock, Minus, LayoutGrid, Globe, Calculator,
  Columns, Forward, Copy, MousePointerClick, Shield, Undo, Redo
} from 'lucide-react';
import { produce } from 'immer';
import useUndoRedo from './hooks/useUndoRedo';
import { useMediaQuery, BREAKPOINTS } from './hooks/useMediaQuery';

const FIELD_TYPES: { type: FormFieldType; icon: React.ElementType; label: string; category: string }[] = [
  { type: 'text', icon: Type, label: 'Text Field', category: 'Basic' },
  { type: 'textarea', icon: AlignLeft, label: 'Text Area', category: 'Basic' },
  { type: 'number', icon: Hash, label: 'Number', category: 'Basic' },
  { type: 'email', icon: FileText, label: 'Email', category: 'Basic' },
  { type: 'password', icon: Lock, label: 'Password', category: 'Basic' },
  { type: 'select', icon: List, label: 'Dropdown', category: 'Selection' },
  { type: 'checkbox', icon: CheckSquare, label: 'Checkbox', category: 'Selection' },
  { type: 'tags', icon: Tag, label: 'Tags Input', category: 'Selection' },
  { type: 'slider', icon: Sliders, label: 'Range Slider', category: 'Selection' },
  { type: 'rating', icon: Star, label: 'Star Rating', category: 'Selection' },
  { type: 'color', icon: Palette, label: 'Color Picker', category: 'Selection' },
  { type: 'date', icon: Calendar, label: 'Date Picker', category: 'Date & Time' },
  { type: 'time', icon: Clock, label: 'Time Picker', category: 'Date & Time' },
  { type: 'file', icon: Upload, label: 'File Upload', category: 'Advanced' },
  { type: 'signature', icon: PenTool, label: 'Signature', category: 'Advanced' },
  { type: 'divider', icon: Minus, label: 'Section Divider', category: 'Layout' },
  { type: 'rich-text', icon: FileText, label: 'Rich Text Info', category: 'Layout' },
];

export const FormDesigner: React.FC = () => {
  const { navigateTo, saveForm, forms, nav, addNotification, roles } = useBPM();
  const isMobile = useMediaQuery(BREAKPOINTS.mobile);

  // Use Undo/Redo Hook for Form Definition
  const { state: formDef, set: setFormDef, undo, redo, canUndo, canRedo } = useUndoRedo<FormDefinition>({ 
      id: `form-${Date.now()}`, name: 'New Form', description: '', fields: [], version: 1, lastModified: new Date().toISOString(), layoutMode: 'single' 
  });

  const [selectedFieldId, setSelectedFieldId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'general' | 'appearance' | 'data' | 'validation' | 'logic' | 'permissions'>('general');
  const [leftOpen, setLeftOpen] = useState(true);
  const [rightOpen, setRightOpen] = useState(true);
  const [previewMode, setPreviewMode] = useState<'desktop' | 'mobile'>('desktop');
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number, fieldId: string } | null>(null);
  const [dragInfo, setDragInfo] = useState<{ type: 'library' | 'field', id?: string, fieldType?: FormFieldType } | null>(null);
  const [dropIndex, setDropIndex] = useState<number | null>(null);
  const [isCopyMode, setIsCopyMode] = useState(false);
  const canvasRef = useRef<HTMLDivElement>(null);

  useEffect(() => { 
      if (nav.selectedId) { 
          const existing = forms.find(f => f.id === nav.selectedId); 
          if (existing) setFormDef(existing); 
      } 
  }, [nav.selectedId, forms, setFormDef]);

  useEffect(() => {
      if (isMobile) {
          setPreviewMode('mobile');
          setLeftOpen(false);
          setRightOpen(false);
      } else {
          setPreviewMode('desktop');
          setLeftOpen(true);
          setRightOpen(true);
      }
  }, [isMobile]);

  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') { e.preventDefault(); undo(); }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') { e.preventDefault(); redo(); }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo]);

  const addField = (type: FormFieldType, index?: number) => {
    if (formDef.fields.length >= 50) { addNotification('error', 'Maximum field limit (50) reached.'); return; }
    const newField: FormField = { id: `f-${Date.now()}`, type, label: type === 'divider' ? 'Section Break' : `New ${type}`, key: `field_${Date.now()}`, required: false, placeholder: '', options: type === 'select' || type === 'tags' ? ['Option 1', 'Option 2'] : undefined, layout: { width: '100%' } };
    setFormDef(produce(formDef, draft => { if (typeof index === 'number') draft.fields.splice(index, 0, newField); else draft.fields.push(newField); }));
    setSelectedFieldId(newField.id); setActiveTab('general'); if(!rightOpen) setRightOpen(true);
  };

  const moveField = (fromId: string, toIndex: number, isCopy: boolean) => {
      setFormDef(produce(formDef, draft => {
          const fromIndex = draft.fields.findIndex(f => f.id === fromId);
          if (fromIndex === -1) return;
          const itemToMove = draft.fields[fromIndex];
          if (!isCopy && (toIndex === fromIndex || toIndex === fromIndex + 1)) return;
          let target = toIndex;
          if (isCopy) { const clone = { ...itemToMove, id: `f-${Date.now()}`, key: `${itemToMove.key}_copy`, label: `${itemToMove.label} (Copy)` }; draft.fields.splice(target, 0, clone); setSelectedFieldId(clone.id); } else { draft.fields.splice(fromIndex, 1); if (fromIndex < toIndex) target -= 1; draft.fields.splice(target, 0, itemToMove); }
      }));
  };

  const deleteField = (id: string) => { setFormDef(produce(formDef, draft => { draft.fields = draft.fields.filter(f => f.id !== id); })); setSelectedFieldId(null); setContextMenu(null); };
  const handleSave = async () => { if (!formDef.name.trim()) { addNotification('error', 'Please provide a form title.'); return; } await saveForm({ ...formDef, lastModified: new Date().toISOString() }); navigateTo('forms'); };
  const selectedField = formDef.fields.find(f => f.id === selectedFieldId);
  const updateField = (id: string, updates: Partial<FormField>) => { setFormDef(produce(formDef, draft => { const field = draft.fields.find(f => f.id === id); if (field) Object.assign(field, updates); })); };

  const updatePermission = (roleId: string, access: FieldPermission['access']) => {
      if (!selectedField) return;
      const currentPerms = selectedField.permissions || [];
      const exists = currentPerms.find(p => p.roleId === roleId);
      let newPerms;

      if (exists) {
          newPerms = currentPerms.map(p => p.roleId === roleId ? { ...p, access } : p);
      } else {
          newPerms = [...currentPerms, { roleId, access }];
      }

      updateField(selectedField.id, { permissions: newPerms });
  };

  const handleDragStartLibrary = (e: React.DragEvent, type: FormFieldType) => { setDragInfo({ type: 'library', fieldType: type }); e.dataTransfer.effectAllowed = 'copy'; if (rightOpen) setRightOpen(false); };
  const handleDragStartField = (e: React.DragEvent, id: string) => { e.stopPropagation(); setDragInfo({ type: 'field', id }); e.dataTransfer.effectAllowed = e.ctrlKey ? 'copy' : 'move'; setSelectedFieldId(id); };
  const handleDragOver = useCallback((e: React.DragEvent, index: number) => { e.preventDefault(); e.stopPropagation(); if (!dragInfo) return; if (dropIndex !== index) setDropIndex(index); if (e.ctrlKey !== isCopyMode) setIsCopyMode(e.ctrlKey); }, [dropIndex, dragInfo, isCopyMode]);
  const handleDrop = (e: React.DragEvent, index: number) => { e.preventDefault(); e.stopPropagation(); if (!dragInfo) return; if (dragInfo.type === 'library' && dragInfo.fieldType) addField(dragInfo.fieldType, index); else if (dragInfo.type === 'field' && dragInfo.id) moveField(dragInfo.id, index, e.ctrlKey || e.metaKey); setDragInfo(null); setDropIndex(null); setIsCopyMode(false); };

  const renderDropZone = (index: number) => {
      const isActive = dropIndex === index && dragInfo !== null;
      return <div key={`drop-${index}`} className={`w-full transition-all duration-200 rounded-sm ${isActive ? 'h-12 my-2 border-2 border-dashed flex items-center justify-center' : 'h-3 hover:h-5'}`} style={{ borderColor: isActive ? (isCopyMode ? '#10b981' : '#3b82f6') : 'transparent', backgroundColor: isActive ? (isCopyMode ? '#ecfdf5' : '#eff6ff') : 'transparent' }} onDragOver={(e) => handleDragOver(e, index)} onDrop={(e) => handleDrop(e, index)} >{isActive && <span className={`text-[10px] font-bold uppercase tracking-widest pointer-events-none flex items-center gap-2 ${isCopyMode ? 'text-emerald-600' : 'text-blue-500'}`}>{isCopyMode ? <Copy size={12}/> : <MousePointerClick size={12}/>}{isCopyMode ? 'Copy Here' : 'Move Here'}</span>}</div>;
  };

  const categories = Array.from(new Set(FIELD_TYPES.map(f => f.category)));

  return (
    <FormPageLayout 
        title={formDef.name || "Form Designer"} 
        onBack={() => navigateTo('forms')} 
        onSave={handleSave} 
        saveLabel="Publish Form" 
        fullWidth
        actions={
            <div className="flex items-center gap-1 bg-subtle p-1 rounded-sm mr-2 border border-default">
                <button onClick={undo} disabled={!canUndo} className="p-1.5 text-secondary hover:text-primary disabled:opacity-30 rounded-sm"><Undo size={16}/></button>
                <button onClick={redo} disabled={!canRedo} className="p-1.5 text-secondary hover:text-primary disabled:opacity-30 rounded-sm"><Redo size={16}/></button>
            </div>
        }
    >
      <div className="flex h-full relative overflow-hidden" onClick={() => setContextMenu(null)}>

        <div className={`border-r border-default bg-subtle flex flex-col transition-all duration-300 ${leftOpen ? 'w-[260px]' : 'w-0 overflow-hidden'}`}>
           <div className="border-b border-default flex items-center justify-between shrink-0" style={{ padding: 'var(--space-base)' }}>
              <h3 className="text-xs font-bold text-secondary uppercase">Field Library</h3>
              <button onClick={() => setLeftOpen(false)} className="text-tertiary hover:text-primary"><PanelLeft size={14}/></button>
           </div>
           <div className="flex-1 overflow-y-auto p-4 space-y-6 select-none">
             {categories.map(cat => (
               <div key={cat}>
                 <h4 className="text-[10px] font-bold text-tertiary uppercase tracking-wider mb-2">{cat}</h4>
                 <div className="grid grid-cols-2 gap-2">
                   {FIELD_TYPES.filter(ft => ft.category === cat).map(ft => (
                     <div key={ft.type} draggable onDragStart={(e) => handleDragStartLibrary(e, ft.type)} onClick={() => addField(ft.type)} className="flex flex-col items-center justify-center gap-2 p-3 bg-panel border border-default rounded-sm hover:border-active hover:shadow-sm transition-all text-center group h-20 cursor-grab active:cursor-grabbing" title={`Drag to add ${ft.label}`}>
                       <ft.icon size={20} className="text-secondary group-hover:text-blue-600"/>
                       <span className="text-[10px] font-bold text-primary leading-tight">{ft.label}</span>
                     </div>
                   ))}
                 </div>
               </div>
             ))}
           </div>
        </div>

        <div className="flex-1 bg-canvas flex flex-col min-w-0 relative">
           <div className="h-10 bg-panel border-b border-default flex items-center justify-between px-4 shrink-0 z-10">
              <div className="flex items-center gap-2">{!leftOpen && <button onClick={() => setLeftOpen(true)} className="p-1.5 hover:bg-subtle rounded text-secondary"><PanelLeft size={16}/></button>}</div>
              <div className="flex items-center gap-4 bg-subtle p-1 rounded-sm border border-default">
                 <div className="flex items-center gap-2 border-r border-default pr-2 mr-2">
                    <button onClick={() => setPreviewMode('desktop')} className={`p-1.5 rounded-sm ${previewMode === 'desktop' ? 'bg-panel shadow-sm text-blue-600' : 'text-tertiary hover:text-secondary'}`}><Monitor size={14}/></button>
                    <button onClick={() => setPreviewMode('mobile')} className={`p-1.5 rounded-sm ${previewMode === 'mobile' ? 'bg-panel shadow-sm text-blue-600' : 'text-tertiary hover:text-secondary'}`}><Smartphone size={14}/></button>
                 </div>
                 <button onClick={() => setFormDef(produce(formDef, d => { d.layoutMode = d.layoutMode === 'wizard' ? 'single' : 'wizard'; }))} className={`flex items-center gap-2 px-3 py-1 rounded-sm text-xs font-bold ${formDef.layoutMode === 'wizard' ? 'bg-blue-50 text-blue-700 border border-blue-200' : 'text-secondary hover:text-primary'}`}><Forward size={14}/> Wizard Mode</button>
              </div>
              <div className="flex items-center gap-2">{!rightOpen && <button onClick={() => setRightOpen(true)} className="p-1.5 hover:bg-subtle rounded text-secondary"><PanelRight size={16}/></button>}</div>
           </div>

           <div ref={canvasRef} className="flex-1 overflow-y-auto relative scroll-smooth" style={{ padding: 'var(--layout-padding)' }} onDragOver={(e) => { e.preventDefault(); }} onClick={() => setSelectedFieldId(null)}>
              <div className={`bg-panel shadow-sm min-h-[800px] mx-auto rounded-sm border border-default flex flex-col transition-all duration-300 relative ${previewMode === 'mobile' ? 'max-w-[375px] border-x-4 border-x-slate-800 my-4 shadow-xl' : 'w-full max-w-4xl p-8'}`}>
                 <div className={`mb-8 border-b border-default pb-6 ${previewMode === 'mobile' ? 'p-6' : ''}`}>
                    <input className="text-2xl font-bold text-primary w-full outline-none bg-transparent placeholder:text-tertiary" value={formDef.name} onChange={e => setFormDef(produce(formDef, d => { d.name = e.target.value }))} placeholder="Form Title" />
                    <input className="text-sm text-secondary w-full outline-none mt-2 bg-transparent placeholder:text-tertiary" value={formDef.description} onChange={e => setFormDef(produce(formDef, d => { d.description = e.target.value }))} placeholder="Enter form description..." />
                 </div>
                 <div className={`flex flex-wrap content-start ${previewMode === 'mobile' ? 'px-4 pb-4' : 'gap-y-0'}`}>
                    {renderDropZone(0)}
                    {formDef.fields.map((field, idx) => (
                    <React.Fragment key={field.id}>
                        <div className={`relative group p-1 transition-all ${dragInfo?.id === field.id ? 'opacity-50 scale-95' : 'opacity-100'}`} style={{ width: previewMode === 'mobile' ? '100%' : (field.layout?.width || '100%') }} onClick={(e) => { e.stopPropagation(); setSelectedFieldId(field.id); if(!rightOpen) setRightOpen(true); }} draggable onDragStart={(e) => handleDragStartField(e, field.id)}>
                            <div className={`relative rounded-sm border p-3 cursor-pointer ${selectedFieldId === field.id ? 'border-active bg-active/10 ring-1 ring-blue-500/20 z-10' : 'border-transparent hover:border-default hover:bg-subtle'}`}>
                                <div className="flex items-center justify-between mb-2 select-none">
                                    <label className="text-sm font-bold text-primary flex items-center gap-2 cursor-grab active:cursor-grabbing">
                                        <GripVertical size={14} className="text-tertiary hover:text-secondary"/> {field.label} {field.required && <span className="text-rose-500">*</span>}
                                    </label>
                                    <button onClick={(e) => { e.stopPropagation(); deleteField(field.id); }} className="text-rose-500 hover:bg-rose-100 p-1.5 rounded opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={14}/></button>
                                </div>
                                <div className="w-full pointer-events-none opacity-80 h-9 bg-subtle border border-default rounded-sm"></div>
                            </div>
                        </div>
                        {renderDropZone(idx + 1)}
                    </React.Fragment>
                    ))}
                 </div>
              </div>
           </div>
        </div>

        <div className={`border-l border-default bg-panel flex flex-col shadow-xl z-10 shrink-0 transition-all duration-300 ${rightOpen ? 'w-[320px]' : 'w-0 overflow-hidden'}`}>
           <div className="border-b border-default bg-subtle flex items-center justify-between shrink-0" style={{ padding: 'var(--space-base)' }}>
              <h3 className="text-xs font-bold text-secondary uppercase flex items-center gap-2"><Settings size={14}/> Properties</h3>
              <button onClick={() => setRightOpen(false)} className="text-tertiary hover:text-secondary"><PanelRight size={14}/></button>
           </div>
           {selectedField ? (
             <div className="flex flex-col h-full overflow-hidden">
                <div className="flex border-b border-default overflow-x-auto no-scrollbar">
                    {['general', 'appearance', 'data', 'validation', 'permissions'].map(t => (
                        <button key={t} onClick={() => setActiveTab(t as any)} className={`px-3 py-3 text-[10px] font-bold uppercase transition-all whitespace-nowrap ${activeTab === t ? 'text-blue-600 border-b-2 border-blue-600 bg-panel' : 'text-secondary bg-subtle hover:text-primary'}`}>{t}</button>
                    ))}
                </div>
                <div className="space-y-5 overflow-y-auto flex-1" style={{ padding: 'var(--card-padding)' }}>
                    {activeTab === 'general' && (
                        <>
                            <NexFormGroup label="Field Label"><input className="prop-input font-bold" value={selectedField.label} onChange={e => updateField(selectedField.id, { label: e.target.value })} /></NexFormGroup>
                            <NexFormGroup label="Variable Key"><input className="prop-input font-mono text-xs" value={selectedField.key} onChange={e => updateField(selectedField.id, { key: e.target.value })} /></NexFormGroup>
                        </>
                    )}

                    {activeTab === 'permissions' && (
                        <div className="space-y-4">
                            <div className="p-3 bg-indigo-50 border border-indigo-100 rounded-sm text-xs text-indigo-800 flex gap-2">
                                <Shield size={16} className="shrink-0"/>
                                Field-Level Security (FLS) overrides visibility rules.
                            </div>
                            {roles.map(role => {
                                const current = selectedField.permissions?.find(p => p.roleId === role.id)?.access || 'read_write';
                                return (
                                    <div key={role.id} className="flex items-center justify-between border-b border-default pb-2">
                                        <span className="text-xs font-bold text-secondary">{role.name}</span>
                                        <select 
                                            className="text-xs border border-default rounded-sm p-1 bg-panel text-primary outline-none"
                                            value={current}
                                            onChange={e => updatePermission(role.id, e.target.value as any)}
                                        >
                                            <option value="read_write">Read/Write</option>
                                            <option value="read_only">Read Only</option>
                                            <option value="hidden">Hidden</option>
                                        </select>
                                    </div>
                                )
                            })}
                        </div>
                    )}
                </div>
             </div>
           ) : <div className="flex-1 flex flex-col items-center justify-center text-tertiary p-8 text-center bg-subtle"><Settings size={32} className="mb-3 opacity-20"/><p className="text-xs font-bold uppercase">Select a field</p></div>}
        </div>
      </div>
    </FormPageLayout>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Task, TaskStatus, TaskPriority, ChecklistItem, SavedView } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { useTheme } from '../contexts/ThemeContext';
import { 
  Search, CheckSquare, Layers, Clock, AlertCircle, UserPlus, Settings,
  CheckCircle, XCircle, Paperclip, LayoutGrid, List as ListIcon, 
  User, Calendar, Star, PauseCircle, ArrowDown, ArrowUp, X,
  Table as TableIcon, Download, Plus, Send, ChevronLeft, FormInput, Sparkles, BrainCircuit, ListChecks, Award, Trash2, Printer,
  Filter, Save, Eye, GripVertical, MessageSquare, ListTodo
} from 'lucide-react';
import { NexBadge, NexButton, NexHistoryFeed, NexDebouncedInput, NexUserDisplay, NexVirtualList, NexCard } from './shared/NexUI';
import { FormRenderer } from './shared/FormRenderer';
import { validateForm, createFilterPredicate, calculateSLA } from '../utils';
import { summarizeTaskContext } from '../services/geminiService';
import { Responsive, WidthProvider } from 'react-grid-layout';

const ResponsiveGridLayout = WidthProvider(Responsive);

// --- SLA Visual Component ---
const SLACountdown = ({ dueDate }: { dueDate: string }) => {
    const [sla, setSla] = useState(calculateSLA(dueDate));

    useEffect(() => {
        const calculate = () => setSla(calculateSLA(dueDate));
        calculate();
        const interval = setInterval(calculate, 60000); // Update every minute
        return () => clearInterval(interval);
    }, [dueDate]);

    const colors = {
        safe: 'bg-emerald-100 text-emerald-700',
        warn: 'bg-amber-100 text-amber-700',
        breach: 'bg-rose-100 text-rose-700 animate-pulse'
    };

    return (
        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-sm uppercase ${colors[sla.status]}`}>
            {sla.timeLeft}
        </span>
    );
};

interface TaskListProps {
    task: Task;
    isSelected: boolean;
    isChecked: boolean;
    isCompact: boolean;
    onCheck: (id: string) => void;
    onClick: (task: Task) => void;
    onStar: (id: string) => void;
}

// --- Task List Item Component ---
const TaskListItem: React.FC<TaskListProps> = ({ task, isSelected, isChecked, isCompact, onCheck, onClick, onStar }) => {
  return (
    <div 
      onClick={() => onClick(task)}
      className={`border-b border-default cursor-pointer hover:bg-subtle transition-colors group flex items-start gap-3 relative ${isSelected ? 'bg-active border-l-4 border-l-blue-600 pl-2' : 'border-l-4 border-l-transparent pl-3 bg-panel'}`}
      style={{ padding: isCompact ? 'calc(var(--space-base) * 0.75)' : 'var(--space-base)', height: '80px' }}
    >
      <div className="pt-1 flex flex-col gap-2 items-center" onClick={e => e.stopPropagation()}>
          <input type="checkbox" checked={isChecked} onChange={() => onCheck(task.id)} className="rounded-base border-default text-blue-600 focus:ring-blue-500" />
          <button onClick={() => onStar(task.id)} className="opacity-0 group-hover:opacity-100 transition-opacity">
             <Star size={12} className={task.isStarred ? "fill-amber-400 text-amber-400 opacity-100" : "text-tertiary"} />
          </button>
      </div>

      <div className="flex-1 min-w-0">
        <div className="flex justify-between items-start mb-0.5">
            <div className="flex items-center gap-2">
                <span className={`font-bold truncate pr-2 ${isCompact ? 'text-base' : 'text-sm'} ${isSelected ? 'text-blue-800' : 'text-primary'}`}>
                    {task.title}
                </span>
                {task.isAdHoc && <span className="bg-amber-100 text-amber-700 text-xs px-1 rounded-base font-bold">ADHOC</span>}
                {task.tags?.map((t: string) => <span key={t} className="bg-subtle text-secondary text-xs px-1 rounded-base border border-default">{t}</span>)}
            </div>
            <div className="flex items-center gap-1">
               <SLACountdown dueDate={task.dueDate} />
               {(task.attachments?.length ?? 0) > 0 && <Paperclip size={12} className="text-tertiary"/>}
               {task.priority === TaskPriority.CRITICAL && <AlertCircle size={14} className="text-rose-600 shrink-0"/>}
            </div>
        </div>

        <div className="flex justify-between items-center text-xs text-secondary">
            <span className="truncate max-w-[150px] flex items-center gap-1"><Layers size={10}/> {task.processName}</span>
            <div className="flex items-center gap-2">
                <span className="bg-subtle px-1.5 py-0.5 rounded-base text-secondary font-medium border border-default">{task.status}</span>
            </div>
        </div>
      </div>
    </div>
  );
};

export const TaskInbox: React.FC = () => {
  const { 
      tasks, completeTask, claimTask, releaseTask, addTaskComment, bulkCompleteTasks, updateTaskChecklist,
      currentUser, delegations, navigateTo, openInstanceViewer, nav, 
      toggleTaskStar, snoozeTask, createAdHocTask, forms, addNotification,
      savedViews, saveView, deleteView, setToolbarConfig, auditLogs
  } = useBPM();
  const { gridConfig, layoutBreakpoints, layoutCols } = useTheme();

  // -- Selection State --
  const selectedTask = useMemo(() => tasks.find(t => t.id === nav.selectedId) || null, [tasks, nav.selectedId]);
  const setSelectedTask = (t: Task | null) => navigateTo('inbox', t?.id);

  // -- View State --
  const [viewMode, setViewMode] = useState<'list' | 'kanban'>('list');
  const [activeTab, setActiveTab] = useState<'my' | 'team' | 'starred' | 'snoozed'>('my');
  const [density, setDensity] = useState<'compact' | 'comfy'>('comfy');
  const [sortConfig, setSortConfig] = useState<{ key: keyof Task, dir: 'asc' | 'desc' }>({ key: 'dueDate', dir: 'asc' });
  const [localSearch, setLocalSearch] = useState('');
  const [isEditable, setIsEditable] = useState(false);

  // -- Layouts --
  const defaultLayouts = {
      lg: [
          { i: 'list', x: 0, y: 0, w: 4, h: 20 },
          { i: 'detail', x: 4, y: 0, w: 8, h: 20 },
          { i: 'stats', x: 0, y: 20, w: 12, h: 4 }
      ],
      md: [
          { i: 'list', x: 0, y: 0, w: 4, h: 20 },
          { i: 'detail', x: 4, y: 0, w: 6, h: 20 },
          { i: 'stats', x: 0, y: 20, w: 10, h: 4 }
      ]
  };
  const [layouts, setLayouts] = useState(defaultLayouts);

  useEffect(() => {
      setToolbarConfig({
          view: [
              { label: isEditable ? 'Lock Layout' : 'Edit Layout', action: () => setIsEditable(!isEditable), icon: Settings },
              { label: 'Reset Layout', action: () => setLayouts(defaultLayouts) }
          ]
      });
  }, [setToolbarConfig, isEditable]);

  // -- Saved View State --
  const [activeSavedView, setActiveSavedView] = useState<string | null>(null);
  const [showSaveViewInput, setShowSaveViewInput] = useState(false);
  const [newViewName, setNewViewName] = useState('');

  // -- Filters --
  const [quickFilter, setQuickFilter] = useState<string | null>(null); // 'Critical', 'Overdue'

  // -- Bulk State --
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // -- Ad-Hoc Creation --
  const [quickTaskTitle, setQuickTaskTitle] = useState('');

  // -- Comment Input --
  const [commentText, setCommentText] = useState('');

  // -- Form Data & Validation --
  const [formData, setFormData] = useState<Record<string, any>>({});
  const [formErrors, setFormErrors] = useState<Record<string, string>>({});

  // -- AI Insight State --
  const [aiInsight, setAiInsight] = useState<{summary: string, sentiment: string, nextAction: string} | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  useEffect(() => {
      if (selectedTask) {
          setFormData(selectedTask.data || {});
          setFormErrors({});
          setAiInsight(null);
          handleAiSummary(selectedTask);
      }
  }, [selectedTask]);

  const handleApplySavedView = (view: SavedView) => {
      setActiveSavedView(view.id);
      if (view.filters.status) setQuickFilter(view.filters.status); // Simplified mapping
      if (view.filters.search) setLocalSearch(view.filters.search);
  };

  const handleSaveCurrentView = async () => {
      if (!newViewName) return;
      await saveView({
          id: '',
          name: newViewName,
          type: 'Task',
          filters: { search: localSearch, priority: quickFilter || undefined }
      });
      setNewViewName('');
      setShowSaveViewInput(false);
  };

  // --- Derived Data & Filtering (Rule 24 Applied) ---
  const delegateRules = delegations.filter(d => d.toUserId === currentUser?.id && d.isActive);

  const filteredTasks = useMemo(() => {
      // Base Filter based on Tab
      const baseFilter = (t: Task) => {
          if (activeTab === 'snoozed') return !!t.snoozeUntil && new Date(t.snoozeUntil) > new Date();
          if (t.snoozeUntil && new Date(t.snoozeUntil) > new Date()) return false;

          if (activeTab === 'my') return t.assignee === currentUser?.id;
          if (activeTab === 'starred') return t.isStarred;
          if (activeTab === 'team') return t.assignee === 'Unassigned' || delegateRules.some(d => d.fromUserId === t.assignee);
          return true;
      };

      // Create Predicate from Config
      const predicate = createFilterPredicate<Task>({
          priority: quickFilter === 'Critical' ? TaskPriority.CRITICAL : undefined,
      }, localSearch, ['title', 'processName']);

      // Overdue Custom Check
      const overdueFilter = (t: Task) => quickFilter === 'Overdue' ? new Date(t.dueDate) < new Date() : true;

      return tasks.filter(t => baseFilter(t) && predicate(t) && overdueFilter(t)).sort((a, b) => {
          const valA = a[sortConfig.key];
          const valB = b[sortConfig.key];
          if (valA === undefined || valB === undefined) return 0;
          if (valA < valB) return sortConfig.dir === 'asc' ? -1 : 1;
          if (valA > valB) return sortConfig.dir === 'asc' ? 1 : -1;
          return 0;
      });
  }, [tasks, activeTab, localSearch, quickFilter, sortConfig, currentUser, delegateRules]);

  const toggleSelection = (id: string) => {
      const newSet = new Set(selectedIds);
      if (newSet.has(id)) newSet.delete(id); else newSet.add(id);
      setSelectedIds(newSet);
  };

  const handleQuickCreate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!quickTaskTitle.trim()) return;
      await createAdHocTask(quickTaskTitle);
      setQuickTaskTitle('');
  };

  const handleAiSummary = async (task: Task) => {
      setLoadingAi(true);
      try {
          const result = await summarizeTaskContext(task);
          setAiInsight(result);
      } catch (e) { console.error(e); } finally { setLoadingAi(false); }
  };

  const activeForm = selectedTask?.formId ? forms.find(f => f.id === selectedTask.formId) : null;

  const handleSubmit = async () => { 
      if (!selectedTask) return;
      if (activeForm) {
          const errors = validateForm(activeForm, formData);
          if (Object.keys(errors).length > 0) {
              setFormErrors(errors);
              addNotification('error', 'Please fix form errors before completing.');
              return;
          }
      }
      await completeTask(selectedTask.id, 'completed', commentText, formData);
      addNotification('success', 'Task completed successfully');
      setSelectedTask(null);
  };

  const handlePostComment = async () => {
      if (!selectedTask || !commentText.trim()) return;
      await addTaskComment(selectedTask.id, commentText);
      setCommentText('');
  };

  const handleToggleCheck = async (itemId: string, checked: boolean) => {
      if (!selectedTask?.checklist) return;
      const updated = selectedTask.checklist.map(i => i.id === itemId ? { ...i, completed: checked } : i);
      await updateTaskChecklist(selectedTask.id, updated);
  };

  return (
    <div className="h-full flex flex-col animate-fade-in overflow-hidden">
        <div className="flex-1 overflow-y-auto overflow-x-hidden min-h-0 -mx-4 px-4 pb-10">
            <ResponsiveGridLayout
                className="layout"
                layouts={layouts}
                breakpoints={layoutBreakpoints}
                cols={layoutCols}
                rowHeight={gridConfig.rowHeight}
                margin={gridConfig.margin}
                isDraggable={isEditable}
                isResizable={isEditable}
                draggableHandle=".drag-handle"
                onLayoutChange={(curr, all) => setLayouts(all)}
            >
                {/* --- TASK LIST WIDGET --- */}
                <NexCard key="list" dragHandle={isEditable} className="flex flex-col h-full p-0">
                    <div className="pt-3 px-3 bg-panel border-b border-default">
                        <div className="flex items-center justify-between mb-3">
                            <h2 className="text-lg font-bold text-primary flex items-center gap-2"><CheckSquare size={18} className="text-blue-600"/> Task Inbox</h2>
                            <div className="flex gap-1">
                                <button onClick={() => setViewMode('list')} className={`p-1.5 rounded-base ${viewMode === 'list' ? 'bg-active text-blue-600' : 'text-tertiary hover:text-secondary'}`}><ListIcon size={16}/></button>
                                <button onClick={() => setViewMode('kanban')} className={`p-1.5 rounded-base ${viewMode === 'kanban' ? 'bg-active text-blue-600' : 'text-tertiary hover:text-secondary'}`}><LayoutGrid size={16}/></button>
                            </div>
                        </div>
                        <div className="flex gap-4 text-xs font-bold text-secondary uppercase tracking-wide overflow-x-auto no-scrollbar">
                            {[ { id: 'my', label: 'My Work' }, { id: 'team', label: 'Team' }, { id: 'starred', label: 'Starred' } ].map(tab => (
                                <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`pb-2 border-b-2 whitespace-nowrap transition-colors ${activeTab === tab.id ? 'border-active text-blue-600' : 'border-transparent hover:text-primary'}`}>{tab.label}</button>
                            ))}
                        </div>
                    </div>

                    <div className="p-2 bg-subtle border-b border-default space-y-2">
                        <form onSubmit={handleQuickCreate} className="relative">
                            <Plus size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-tertiary"/>
                            <input className="w-full pl-8 pr-3 py-1.5 text-xs border border-default rounded-base focus:ring-1 focus:ring-blue-500 outline-none bg-panel text-primary" placeholder="Quick add..." value={quickTaskTitle} onChange={e => setQuickTaskTitle(e.target.value)} />
                        </form>
                        <NexDebouncedInput value={localSearch} onChange={setLocalSearch} placeholder="Search..." className="w-full pr-3 py-1.5 bg-panel border border-default rounded-base outline-none text-xs text-primary" icon={Search} />
                    </div>

                    <div className="flex-1 overflow-y-auto bg-panel min-h-0">
                        <NexVirtualList 
                            items={filteredTasks}
                            itemHeight={80} 
                            renderItem={(t: Task, idx) => (
                                <TaskListItem key={t.id} task={t} isSelected={selectedTask?.id === t.id} isChecked={selectedIds.has(t.id)} isCompact={density === 'compact'} onCheck={toggleSelection} onClick={setSelectedTask} onStar={toggleTaskStar} />
                            )}
                        />
                    </div>
                </NexCard>

                {/* --- TASK DETAIL WIDGET --- */}
                <NexCard key="detail" dragHandle={isEditable} className="flex flex-col h-full p-0">
                    {selectedTask ? (
                        <>
                            <div className="h-12 bg-panel border-b border-default flex items-center justify-between px-4 shadow-sm shrink-0">
                                <div className="flex items-center gap-2">
                                    <button onClick={() => setSelectedTask(null)} className="xl:hidden mr-2 text-secondary"><ChevronLeft size={18}/></button>
                                    <NexBadge variant={selectedTask.priority === 'Critical' ? 'rose' : 'blue'}>{selectedTask.priority}</NexBadge>
                                    <span className="text-xs text-tertiary font-mono">{selectedTask.id}</span>
                                </div>
                                <button onClick={() => setSelectedTask(null)} className="p-1.5 hover:bg-subtle rounded-base text-secondary"><X size={16}/></button>
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 md:p-6 bg-canvas">
                                <div className="bg-panel rounded-base border border-default shadow-sm p-6 mb-4">
                                    <h2 className="text-lg font-bold text-primary mb-2 leading-tight">{selectedTask.title}</h2>
                                    <div className="flex items-center gap-4 text-xs text-secondary mb-4 pb-4 border-b border-default">
                                        <span className="flex items-center gap-1"><Layers size={12}/> {selectedTask.processName}</span>
                                        <span className="flex items-center gap-1"><NexUserDisplay userId={selectedTask.assignee} size="sm" showEmail={false} /></span>
                                    </div>
                                    <p className="text-base text-primary leading-relaxed mb-4">{selectedTask.description || "No description provided."}</p>

                                    {/* Checklist */}
                                    {selectedTask.checklist && selectedTask.checklist.length > 0 && (
                                        <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-sm">
                                            <h4 className="text-xs font-bold text-amber-800 uppercase mb-2 flex items-center gap-2"><ListTodo size={14}/> Sub-tasks</h4>
                                            <div className="space-y-1">
                                                {selectedTask.checklist.map(item => (
                                                    <label key={item.id} className="flex items-center gap-2 cursor-pointer hover:bg-amber-100/50 p-1 rounded-sm">
                                                        <input 
                                                            type="checkbox" 
                                                            checked={item.completed} 
                                                            onChange={e => handleToggleCheck(item.id, e.target.checked)} 
                                                            className="rounded-sm text-amber-600 focus:ring-amber-500" 
                                                        />
                                                        <span className={`text-xs ${item.completed ? 'line-through text-slate-400' : 'text-slate-700'}`}>{item.text}</span>
                                                    </label>
                                                ))}
                                            </div>
                                        </div>
                                    )}

                                    {activeForm && selectedTask.status !== TaskStatus.COMPLETED && (
                                        <div className="mb-6 p-4 bg-subtle border border-blue-200 rounded-sm">
                                            <div className="flex items-center gap-2 mb-4 text-blue-700">
                                                <FormInput size={16}/>
                                                <h4 className="text-sm font-bold uppercase">{activeForm.name}</h4>
                                            </div>
                                            <FormRenderer form={activeForm} data={formData} onChange={(k, v) => setFormData(prev => ({ ...prev, [k]: v }))} errors={formErrors} />
                                        </div>
                                    )}

                                    <div className="flex gap-2 mb-6">
                                        <NexButton variant="primary" onClick={handleSubmit} icon={CheckCircle}>Complete Task</NexButton>
                                    </div>

                                    {/* Comments & History */}
                                    <div className="border-t border-default pt-6">
                                        <h4 className="text-xs font-bold text-secondary uppercase mb-4 flex items-center gap-2"><MessageSquare size={14}/> Collaboration</h4>
                                        <div className="bg-subtle p-3 rounded-sm border border-default mb-4">
                                            <div className="flex gap-2">
                                                <input 
                                                    className="flex-1 bg-transparent text-sm outline-none placeholder:text-tertiary text-primary" 
                                                    placeholder="Write a comment..." 
                                                    value={commentText}
                                                    onChange={e => setCommentText(e.target.value)}
                                                    onKeyDown={e => e.key === 'Enter' && handlePostComment()}
                                                />
                                                <button onClick={handlePostComment} disabled={!commentText.trim()} className="text-blue-600 font-bold text-xs hover:text-blue-800 disabled:opacity-50">Post</button>
                                            </div>
                                        </div>
                                        <NexHistoryFeed history={[...(selectedTask.comments || []).map(c => ({...c, description: c.text})), ...(auditLogs.filter(l => l.entityId === selectedTask.id).map(l => ({...l, author: l.userId, description: `${l.action}: ${l.details}`})))].sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())} />
                                    </div>
                                </div>
                            </div>
                        </>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-tertiary p-8 text-center bg-subtle">
                            <LayoutGrid size={48} className="opacity-20 mb-4"/>
                            <p className="text-sm font-medium">Select a task to view details</p>
                        </div>
                    )}
                </NexCard>

                {/* --- STATS WIDGET --- */}
                <NexCard key="stats" dragHandle={isEditable} className="flex flex-row items-center justify-between p-4 h-full">
                    <div className="flex items-center gap-4">
                        <div>
                            <div className="text-xs text-secondary uppercase font-bold">Total</div>
                            <div className="text-xl font-black text-primary">{tasks.length}</div>
                        </div>
                        <div className="w-px h-8 bg-default"></div>
                        <div>
                            <div className="text-xs text-secondary uppercase font-bold">My Open</div>
                            <div className="text-xl font-black text-blue-600">{tasks.filter(t => t.assignee === currentUser?.id && t.status !== 'Completed').length}</div>
                        </div>
                        <div className="w-px h-8 bg-default"></div>
                        <div>
                            <div className="text-xs text-secondary uppercase font-bold">Critical</div>
                            <div className="text-xl font-black text-rose-600">{tasks.filter(t => t.priority === TaskPriority.CRITICAL).length}</div>
                        </div>
                    </div>
                    {!isEditable && (
                        <NexButton variant="secondary" size="sm" onClick={() => addNotification('info', 'Refreshing task queue...')}>Sync</NexButton>
                    )}
                </NexCard>
            </ResponsiveGridLayout>
        </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { useTheme } from '../contexts/ThemeContext';
import { Briefcase, Plus, Search, Filter, Clock, ChevronRight, AlertCircle, X, SearchX, CheckCircle, PieChart, BarChart3, User as UserIcon, LayoutGrid, List as ListIcon, MoreHorizontal, Settings, GripVertical } from 'lucide-react';
import { NexCard, NexButton, NexBadge, NexStatusBadge } from './shared/NexUI';
import { TaskStatus, Case } from '../types';
import { Responsive, WidthProvider } from 'react-grid-layout';

const ResponsiveGridLayout = WidthProvider(Responsive);

// --- KPI Widget Component ---
const KPIWidget = React.forwardRef<HTMLDivElement, any>(({ title, value, icon: Icon, color, onClick, isEditable, className, style, ...props }, ref) => {
    const colors = {
        blue: 'text-blue-700 bg-blue-50 border-blue-200',
        emerald: 'text-emerald-700 bg-emerald-50 border-emerald-200',
        rose: 'text-rose-700 bg-rose-50 border-rose-200'
    };
    return (
        <div 
            ref={ref} 
            style={{ borderRadius: 'var(--radius-base)', ...style }}
            className={`bg-panel p-3 border border-default shadow-sm flex flex-col justify-between h-full ${className} ${onClick ? 'cursor-pointer hover:border-active' : ''}`}
            onClick={onClick}
            {...props}
        >
            <div className="flex justify-between items-start">
                <div className={`p-2 rounded-sm ${colors[color as keyof typeof colors]}`}>
                    <Icon size={18}/>
                </div>
                {isEditable && <GripVertical size={14} className="drag-handle text-tertiary cursor-move"/>}
            </div>
            <div>
                <div className="text-2xl font-bold text-primary">{value}</div>
                <div className="text-[10px] font-bold text-secondary uppercase">{title}</div>
            </div>
        </div>
    );
});

export const CaseManagerView: React.FC = () => {
  const { cases, navigateTo, currentUser, tasks, users, updateCase, setToolbarConfig } = useBPM();
  const { gridConfig } = useTheme();

  // Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [filterMine, setFilterMine] = useState(false);
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [priorityFilter, setPriorityFilter] = useState<string>('All');
  const [viewMode, setViewMode] = useState<'list' | 'board'>('list');
  const [isEditable, setIsEditable] = useState(false);

  // Layouts
  const defaultLayouts = {
      lg: [
          { i: 'kpi-active', x: 0, y: 0, w: 4, h: 4 },
          { i: 'kpi-workload', x: 4, y: 0, w: 4, h: 4 },
          { i: 'kpi-critical', x: 8, y: 0, w: 4, h: 4 },
          { i: 'main-content', x: 0, y: 4, w: 12, h: 16 }
      ],
      md: [
          { i: 'kpi-active', x: 0, y: 0, w: 3, h: 4 },
          { i: 'kpi-workload', x: 3, y: 0, w: 3, h: 4 },
          { i: 'kpi-critical', x: 6, y: 0, w: 4, h: 4 },
          { i: 'main-content', x: 0, y: 4, w: 10, h: 16 }
      ]
  };
  const [layouts, setLayouts] = useState(defaultLayouts);

  useEffect(() => {
      setToolbarConfig({
          view: [
              { label: isEditable ? 'Lock Layout' : 'Edit Layout', action: () => setIsEditable(!isEditable), icon: Settings },
              { label: 'Reset Layout', action: () => setLayouts(defaultLayouts) }
          ]
      });
  }, [setToolbarConfig, isEditable]);

  // --- Filtering & Sorting ---
  const filteredCases = useMemo(() => {
      return cases
        .filter(c => {
            const matchSearch = c.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                                c.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
                                c.id.includes(searchQuery);

            const matchMine = filterMine ? c.stakeholders.some(s => s.userId === currentUser?.id) : true;
            const matchStatus = statusFilter === 'All' || c.status === statusFilter;
            const matchPriority = priorityFilter === 'All' || c.priority === priorityFilter;

            return matchSearch && matchMine && matchStatus && matchPriority;
        })
        .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()); // Sort Newest First
  }, [cases, searchQuery, filterMine, statusFilter, priorityFilter, currentUser]);

  // --- KPI Calculations ---
  const kpis = useMemo(() => {
      const active = cases.filter(c => c.status !== 'Closed').length;
      const critical = cases.filter(c => c.priority === 'Critical' && c.status !== 'Closed').length;
      const myActive = cases.filter(c => c.status !== 'Closed' && c.stakeholders.some(s => s.userId === currentUser?.id)).length;
      return { active, critical, myActive };
  }, [cases, currentUser]);

  // Helper to get case owner
  const getCaseOwner = (c: any) => {
      const ownerId = c.stakeholders.find((s: any) => s.role === 'Owner')?.userId;
      return users.find(u => u.id === ownerId);
  };

  // Helper for progress bar
  const getCaseProgress = (caseId: string) => {
      const caseTasks = tasks.filter(t => t.caseId === caseId);
      if (caseTasks.length === 0) return 0;
      const completed = caseTasks.filter(t => t.status === TaskStatus.COMPLETED).length;
      return Math.round((completed / caseTasks.length) * 100);
  };

  // Kanban Logic
  const stages = ['Open', 'In Progress', 'Pending Review', 'Resolved', 'Closed'];

  const handleDrop = (e: React.DragEvent, newStatus: string) => {
      const caseId = e.dataTransfer.getData('caseId');
      if (caseId) {
          updateCase(caseId, { status: newStatus as any });
      }
  };

  return (
    <div className="animate-fade-in flex flex-col h-full overflow-hidden">
      <header className="flex items-center justify-between border-b border-default pb-4 shrink-0 mb-2">
        <div>
          <h2 className="text-xl font-bold text-primary tracking-tight">Case Management</h2>
          <p className="text-xs text-secondary font-medium">Orchestrate complex non-linear workflows.</p>
        </div>
        <NexButton variant="primary" icon={Plus} onClick={() => navigateTo('create-case')}>New Case</NexButton>
      </header>

      <div className="flex-1 overflow-y-auto overflow-x-hidden min-h-0 -mx-4 px-4 pb-10">
        <ResponsiveGridLayout
            className="layout"
            layouts={layouts}
            breakpoints={{ lg: 1200, md: 996, sm: 768, xs: 480, xxs: 0 }}
            cols={{ lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 }}
            rowHeight={gridConfig.rowHeight}
            margin={gridConfig.margin}
            isDraggable={isEditable}
            isResizable={isEditable}
            draggableHandle=".drag-handle"
            onLayoutChange={(curr, all) => setLayouts(all)}
        >
            <KPIWidget key="kpi-active" isEditable={isEditable} title="Active Cases" value={kpis.active} icon={Briefcase} color="blue" onClick={() => !isEditable && setStatusFilter('Open')} />
            <KPIWidget key="kpi-workload" isEditable={isEditable} title="My Workload" value={kpis.myActive} icon={UserIcon} color="emerald" onClick={() => !isEditable && setFilterMine(true)} />
            <KPIWidget key="kpi-critical" isEditable={isEditable} title="Critical Issues" value={kpis.critical} icon={AlertCircle} color="rose" onClick={() => !isEditable && setPriorityFilter('Critical')} />

            <NexCard key="main-content" dragHandle={isEditable} className="p-0 flex flex-col h-full">
                {/* Toolbar inside Widget */}
                <div className="p-3 border-b border-default bg-subtle flex flex-col md:flex-row gap-2">
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" size={14}/>
                        <input 
                            className="w-full pl-9 pr-4 py-1.5 bg-panel border border-default rounded-sm text-xs font-medium focus:ring-1 focus:ring-blue-600 outline-none text-primary" 
                            placeholder="Search cases..."
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <div className="flex gap-2">
                        <div className="flex bg-panel p-0.5 rounded-sm border border-default">
                            <button onClick={() => setViewMode('list')} className={`p-1 rounded-sm transition-all ${viewMode === 'list' ? 'bg-subtle text-primary' : 'text-tertiary hover:text-secondary'}`}><ListIcon size={14}/></button>
                            <button onClick={() => setViewMode('board')} className={`p-1 rounded-sm transition-all ${viewMode === 'board' ? 'bg-subtle text-primary' : 'text-tertiary hover:text-secondary'}`}><LayoutGrid size={14}/></button>
                        </div>
                        {viewMode === 'list' && (
                            <select className="px-2 py-1 border border-default rounded-sm text-xs bg-panel text-primary" value={statusFilter} onChange={e => setStatusFilter(e.target.value)}>
                                <option value="All">All Status</option>
                                {stages.map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        )}
                        <button onClick={() => setFilterMine(!filterMine)} className={`px-2 py-1 border rounded-sm text-[10px] font-bold uppercase transition-all ${filterMine ? 'bg-slate-800 text-white border-slate-800' : 'bg-panel text-secondary border-default'}`}>My Cases</button>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto overflow-x-hidden p-4 bg-canvas min-h-0">
                    {/* LIST VIEW */}
                    {viewMode === 'list' && (
                        <div className="space-y-2">
                            {filteredCases.length === 0 ? <div className="text-center text-tertiary text-xs py-8 italic">No matching cases.</div> : 
                            filteredCases.map(c => {
                                const owner = getCaseOwner(c);
                                const progress = getCaseProgress(c.id);
                                return (
                                    <div key={c.id} onClick={() => !isEditable && navigateTo('case-viewer', c.id)} className="flex items-center justify-between p-3 border border-default rounded-sm hover:border-active hover:shadow-sm transition-all cursor-pointer group bg-panel">
                                        <div className="flex items-center gap-3 flex-1 min-w-0">
                                            <div className={`w-8 h-8 rounded-sm flex items-center justify-center border shrink-0 ${c.priority === 'Critical' ? 'bg-rose-50 text-rose-600 border-rose-200' : 'bg-subtle text-secondary border-default'}`}>
                                                <Briefcase size={14}/>
                                            </div>
                                            <div className="min-w-0">
                                                <h4 className="text-sm font-bold text-primary truncate">{c.title}</h4>
                                                <div className="flex items-center gap-2 text-[10px] text-secondary">
                                                    <span className="font-mono text-tertiary">{c.id}</span>
                                                    <span>• {new Date(c.createdAt).toLocaleDateString()}</span>
                                                    {owner && <span className="bg-subtle px-1 rounded flex items-center gap-1"><UserIcon size={8}/> {owner.name}</span>}
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-4">
                                            <div className="hidden sm:block w-20">
                                                <div className="h-1 bg-subtle rounded-full overflow-hidden"><div className="h-full bg-emerald-500" style={{ width: `${progress}%` }}></div></div>
                                            </div>
                                            <NexStatusBadge status={c.status} />
                                            <ChevronRight size={14} className="text-tertiary group-hover:text-primary"/>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* BOARD VIEW */}
                    {viewMode === 'board' && (
                        <div className="flex h-full gap-3 overflow-x-auto pb-2">
                            {stages.map(stage => {
                                const casesInStage = filteredCases.filter(c => c.status === stage);
                                return (
                                    <div key={stage} className="flex-1 min-w-[240px] bg-subtle rounded-sm border border-default flex flex-col max-h-full" onDragOver={(e) => e.preventDefault()} onDrop={(e) => handleDrop(e, stage)}>
                                        <div className="p-2 border-b border-default font-bold text-xs text-secondary uppercase flex justify-between">{stage} <span>{casesInStage.length}</span></div>
                                        <div className="flex-1 overflow-y-auto p-2 space-y-2">
                                            {casesInStage.map(c => (
                                                <div key={c.id} draggable onDragStart={(e) => e.dataTransfer.setData('caseId', c.id)} onClick={() => !isEditable && navigateTo('case-viewer', c.id)} className="p-3 bg-panel border border-default rounded-sm shadow-sm hover:shadow-md cursor-grab active:cursor-grabbing">
                                                    <div className="flex justify-between mb-1"><NexBadge variant={c.priority === 'Critical' ? 'rose' : 'slate'}>{c.priority}</NexBadge></div>
                                                    <div className="text-xs font-bold text-primary line-clamp-2 mb-2">{c.title}</div>
                                                    <div className="text-[9px] text-tertiary font-mono">{c.id}</div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            </NexCard>
        </ResponsiveGridLayout>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  ArrowLeft, Users, Send, Settings, Activity, 
  CheckSquare, ChevronRight, Briefcase, ShieldCheck, Play, X, Layers, Plus, Shield, Edit, Trash2, RotateCcw, Lock, Database, Paperclip, FileText, Upload, Save, User as UserIcon, CheckCircle, Eye, GripVertical
} from 'lucide-react';
import { NexBadge, NexButton, NexHistoryFeed, NexCard, NexModal, NexFormGroup, NexStatusBadge } from './shared/NexUI';
import { TaskStatus } from '../types';
import { useTheme } from '../contexts/ThemeContext';
import { Responsive, WidthProvider } from 'react-grid-layout';

const ResponsiveGridLayout = WidthProvider(Responsive);
const MOCK_STAGES = ['Open', 'In Progress', 'Pending Review', 'Resolved', 'Closed'];

export const CaseViewer: React.FC<{ caseId: string }> = ({ caseId }) => {
  const { cases, tasks, users, navigateTo, addCaseEvent, removeCaseEvent, addCasePolicy, removeCasePolicy, addCaseStakeholder, removeCaseStakeholder, updateCase, currentUser, openInstanceViewer, getActiveUsersOnRecord, setToolbarConfig, processes, startProcess } = useBPM();
  const { gridConfig } = useTheme();

  const [note, setNote] = useState('');
  const [caseData, setCaseData] = useState<string>('');
  const [previewFile, setPreviewFile] = useState<{name: string, url?: string} | null>(null);
  const [isEditable, setIsEditable] = useState(false);

  const currentCase = cases.find(c => c.id === caseId);
  const relatedTasks = useMemo(() => tasks.filter(t => t.caseId === caseId), [tasks, caseId]);
  const activeViewers = getActiveUsersOnRecord(caseId);

  // Layouts
  const defaultLayouts = {
      lg: [
          { i: 'header', x: 0, y: 0, w: 12, h: 3 },
          { i: 'progress', x: 0, y: 3, w: 8, h: 3 },
          { i: 'actions', x: 8, y: 3, w: 4, h: 3 },
          { i: 'timeline', x: 0, y: 6, w: 6, h: 14 },
          { i: 'tasks', x: 6, y: 6, w: 6, h: 8 },
          { i: 'data', x: 6, y: 14, w: 6, h: 6 },
          { i: 'stakeholders', x: 0, y: 20, w: 4, h: 8 },
          { i: 'content', x: 4, y: 20, w: 8, h: 8 },
          { i: 'dynamic', x: 0, y: 28, w: 12, h: 6 }
      ],
      md: [
          { i: 'header', x: 0, y: 0, w: 10, h: 3 },
          { i: 'progress', x: 0, y: 3, w: 6, h: 3 },
          { i: 'actions', x: 6, y: 3, w: 4, h: 3 },
          { i: 'timeline', x: 0, y: 6, w: 10, h: 10 },
          { i: 'tasks', x: 0, y: 16, w: 10, h: 8 },
          { i: 'data', x: 0, y: 24, w: 10, h: 6 },
          { i: 'stakeholders', x: 0, y: 30, w: 5, h: 8 },
          { i: 'content', x: 5, y: 30, w: 5, h: 8 },
          { i: 'dynamic', x: 0, y: 38, w: 10, h: 6 }
      ]
  };
  const [layouts, setLayouts] = useState(defaultLayouts);

  useEffect(() => {
      setToolbarConfig({
          view: [
              { label: isEditable ? 'Lock Layout' : 'Customize Dashboard', action: () => setIsEditable(!isEditable), icon: Settings },
              { label: 'Reset Layout', action: () => setLayouts(defaultLayouts) }
          ]
      });
  }, [setToolbarConfig, isEditable]);

  useEffect(() => {
      if (currentCase) {
          setCaseData(JSON.stringify(currentCase.data || {}, null, 2));
      }
  }, [currentCase]);

  if (!currentCase) return <div className="p-20 text-center text-tertiary">Case file not found.</div>;

  const currentStageIndex = MOCK_STAGES.indexOf(currentCase.status) !== -1 ? MOCK_STAGES.indexOf(currentCase.status) : 0;

  const handlePostNote = async () => {
    if (!note.trim()) return;
    await addCaseEvent(caseId, note);
    setNote('');
  };

  const handleCloseCase = async () => {
      await updateCase(caseId, { status: 'Closed', resolvedAt: new Date().toISOString() });
      await addCaseEvent(caseId, 'Case officially closed.');
  };

  const handleReopenCase = async () => {
      await updateCase(caseId, { status: 'Open' });
      await addCaseEvent(caseId, 'Case reopened for further action.');
  };

  const handleSaveData = async () => {
      try {
          const parsed = JSON.parse(caseData);
          await updateCase(caseId, { data: parsed });
          await addCaseEvent(caseId, 'Updated case data fields.');
      } catch (e) {
          alert('Invalid JSON format');
      }
  };

  const handleMockUpload = async () => {
      const mockFile = {
          id: `file-${Date.now()}`,
          name: `Document_${Date.now()}.pdf`,
          type: 'internal' as const,
          size: Math.floor(Math.random() * 5000) + 1000,
          uploadDate: new Date().toISOString()
      };
      await updateCase(caseId, { attachments: [...currentCase.attachments, mockFile] });
      await addCaseEvent(caseId, `Uploaded document: ${mockFile.name}`);
  };

  const triggerDynamicAction = async (procId: string, procName: string) => {
      await startProcess(procId, { caseContext: currentCase.title }, caseId);
      await addCaseEvent(caseId, `Launched dynamic activity: ${procName}`);
  };

  return (
    <div className="flex flex-col h-full animate-fade-in overflow-hidden">
      <div className="flex-1 overflow-y-auto overflow-x-hidden min-h-0 -mx-4 px-4 pb-10">
        <ResponsiveGridLayout
            className="layout"
            layouts={layouts}
            breakpoints={{ lg: 1200, md: 996, sm: 768, xs: 480, xxs: 0 }}
            cols={{ lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 }}
            rowHeight={gridConfig.rowHeight}
            margin={gridConfig.margin}
            isDraggable={isEditable}
            isResizable={isEditable}
            draggableHandle=".drag-handle"
            onLayoutChange={(curr, all) => setLayouts(all)}
        >
            <NexCard key="header" dragHandle={isEditable} className="flex flex-row items-center justify-between p-4">
                <div className="flex items-center gap-4">
                    <button onClick={() => navigateTo('cases')} className="p-2 hover:bg-subtle rounded-full text-secondary transition-colors"><ArrowLeft size={20}/></button>
                    <div>
                        <div className="flex items-center gap-2">
                            <h2 className="text-lg font-bold text-primary">{currentCase.title}</h2>
                            <NexStatusBadge status={currentCase.status}/>
                        </div>
                        <p className="text-xs text-secondary font-mono mt-0.5">{currentCase.id} • Created {new Date(currentCase.createdAt).toLocaleDateString()}</p>
                    </div>
                </div>
                {activeViewers.length > 0 && (
                   <div className="flex items-center -space-x-2">
                       {activeViewers.map(u => (
                           <div key={u.id} className="w-8 h-8 rounded-full border-2 border-white bg-blue-100 flex items-center justify-center text-xs font-bold text-blue-700 shadow-sm" title={u.name}>{u.name[0]}</div>
                       ))}
                   </div>
               )}
            </NexCard>

            <NexCard key="progress" dragHandle={isEditable} className="flex items-center justify-center p-4">
                <div className="w-full flex items-center justify-between relative">
                    <div className="absolute left-0 top-1/2 -translate-y-1/2 w-full h-1 bg-subtle rounded-full z-0"></div>
                    {MOCK_STAGES.map((stage, i) => {
                        const isCompleted = i <= currentStageIndex;
                        const isCurrent = i === currentStageIndex;
                        return (
                            <div key={stage} className="relative z-10 flex flex-col items-center">
                                <div className={`w-4 h-4 rounded-full flex items-center justify-center border-2 transition-all ${isCompleted ? 'bg-emerald-500 border-emerald-500' : 'bg-panel border-default'}`}>
                                    {isCompleted && <CheckCircle size={10} className="text-white"/>}
                                </div>
                                <span className={`text-[9px] font-bold mt-1 uppercase ${isCurrent ? 'text-emerald-700' : 'text-tertiary'}`}>{stage}</span>
                            </div>
                        )
                    })}
                </div>
            </NexCard>

            <NexCard key="actions" dragHandle={isEditable} className="flex items-center justify-end gap-2 p-4">
                <button onClick={() => !isEditable && navigateTo('edit-case', currentCase.id)} className="p-2 text-secondary hover:text-blue-600 hover:bg-subtle rounded"><Edit size={16}/></button>
                {currentCase.status !== 'Closed' ? (
                    <NexButton variant="danger" icon={Lock} onClick={handleCloseCase}>Close</NexButton>
                ) : (
                    <NexButton variant="primary" icon={RotateCcw} onClick={handleReopenCase}>Reopen</NexButton>
                )}
                <NexButton variant="secondary" icon={Play} onClick={() => !isEditable && navigateTo('case-launch', currentCase.id)} disabled={currentCase.status === 'Closed'}>Action</NexButton>
            </NexCard>

            <NexCard key="timeline" dragHandle={isEditable} title="Case Timeline" className="flex flex-col h-full">
                <div className="p-4 border-b border-default">
                    <div className="flex gap-2">
                        <textarea className="flex-1 bg-subtle border border-default rounded-sm p-2 text-xs outline-none focus:border-blue-400 resize-none h-16 text-primary" placeholder="Add a case note..." value={note} onChange={e => setNote(e.target.value)} />
                        <NexButton variant="primary" onClick={handlePostNote} disabled={!note.trim()} className="self-end"><Send size={14}/></NexButton>
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4">
                    <NexHistoryFeed history={currentCase.timeline} />
                </div>
            </NexCard>

            <NexCard key="tasks" dragHandle={isEditable} title="Related Tasks" className="flex flex-col h-full">
                <div className="flex-1 overflow-y-auto p-2 space-y-2">
                    {relatedTasks.length === 0 && <div className="text-center text-tertiary text-xs italic py-8">No tasks linked.</div>}
                    {relatedTasks.map(task => (
                        <div key={task.id} className="bg-subtle border border-default rounded-sm p-3 flex justify-between items-center group hover:shadow-sm">
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className={`w-8 h-8 rounded-sm flex items-center justify-center border ${task.status === 'Completed' ? 'bg-emerald-50 text-emerald-600 border-emerald-200' : 'bg-panel text-secondary border-default'}`}>
                                    {task.status === 'Completed' ? <CheckCircle size={14}/> : <Activity size={14}/>}
                                </div>
                                <div className="min-w-0">
                                    <div className="font-bold text-xs text-primary truncate">{task.title}</div>
                                    <div className="text-[10px] text-secondary">{task.status} • {task.priority}</div>
                                </div>
                            </div>
                            <button onClick={() => !isEditable && navigateTo('inbox', task.id)} className="p-1 text-tertiary hover:text-blue-600"><ChevronRight size={16}/></button>
                        </div>
                    ))}
                </div>
            </NexCard>

            <NexCard key="data" dragHandle={isEditable} title="Case Data (JSON)" className="flex flex-col h-full" actions={<button onClick={handleSaveData} className="text-blue-600 hover:bg-blue-50 p-1 rounded"><Save size={14}/></button>}>
                <textarea 
                    className="flex-1 w-full font-mono text-[10px] p-2 bg-subtle border-none outline-none resize-none text-primary"
                    value={caseData}
                    onChange={e => setCaseData(e.target.value)}
                    spellCheck={false}
                />
            </NexCard>

            <NexCard key="stakeholders" dragHandle={isEditable} title="Stakeholders" className="flex flex-col h-full" actions={<button onClick={() => !isEditable && navigateTo('case-stakeholder', currentCase.id)}><Plus size={14}/></button>}>
                <div className="flex-1 overflow-y-auto p-2 space-y-2">
                    {currentCase.stakeholders.map((sh, i) => {
                        const u = users.find(user => user.id === sh.userId);
                        return (
                            <div key={i} className="flex items-center gap-2 p-2 border border-default rounded-sm">
                                <div className="w-6 h-6 bg-subtle rounded-full flex items-center justify-center text-[10px] font-bold border border-default">{u?.name?.[0]}</div>
                                <div className="overflow-hidden">
                                    <div className="text-xs font-bold text-primary truncate">{u?.name || 'Unknown'}</div>
                                    <div className="text-[9px] text-secondary">{sh.role}</div>
                                </div>
                            </div>
                        )
                    })}
                </div>
            </NexCard>

            <NexCard key="content" dragHandle={isEditable} title="Artifacts" className="flex flex-col h-full" actions={<button onClick={handleMockUpload}><Upload size={14}/></button>}>
                <div className="flex-1 overflow-y-auto p-2 space-y-2">
                    {currentCase.attachments.map((file, i) => (
                        <div key={i} className="flex items-center justify-between p-2 border border-default rounded-sm hover:bg-subtle">
                            <div className="flex items-center gap-2 overflow-hidden">
                                <FileText size={14} className="text-blue-500 shrink-0"/>
                                <span className="text-xs text-primary truncate">{file.name}</span>
                            </div>
                            <button onClick={() => setPreviewFile({name: file.name})} className="text-tertiary hover:text-blue-600"><Eye size={12}/></button>
                        </div>
                    ))}
                    {currentCase.attachments.length === 0 && <div className="text-center text-[10px] text-tertiary italic py-4">No files.</div>}
                </div>
            </NexCard>

            <NexCard key="dynamic" dragHandle={isEditable} title="Available Dynamic Actions" className="flex flex-col h-full">
                <div className="p-3 grid grid-cols-2 md:grid-cols-4 gap-4 overflow-y-auto">
                    {processes.slice(0, 4).map(proc => (
                        <button 
                            key={proc.id} 
                            onClick={() => triggerDynamicAction(proc.id, proc.name)}
                            className="flex flex-col items-center justify-center p-3 border border-dashed border-default rounded-sm hover:border-blue-400 hover:bg-subtle transition-colors group text-center"
                        >
                            <Play size={20} className="text-secondary group-hover:text-blue-600 mb-2"/>
                            <span className="text-xs font-bold text-primary group-hover:text-blue-800">{proc.name}</span>
                        </button>
                    ))}
                </div>
            </NexCard>
        </ResponsiveGridLayout>
      </div>

      {previewFile && (
          <NexModal isOpen={!!previewFile} onClose={() => setPreviewFile(null)} title={previewFile.name} size="xl">
              <div className="h-[600px] bg-subtle flex items-center justify-center border border-default rounded-sm">
                  <div className="text-center">
                      <FileText size={64} className="mx-auto text-tertiary mb-4"/>
                      <p className="text-secondary font-bold mb-2">Preview Unavailable</p>
                      <p className="text-xs text-tertiary">Mock artifact rendering.</p>
                  </div>
              </div>
          </NexModal>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
