const SUGGESTED_FACTS = [
  'invoice.amount', 'invoice.currency', 'invoice.vendor', 'invoice.date',
  'user.role', 'user.department', 'user.location', 'user.spendingLimit',
  'request.priority', 'request.category', 'request.type',
