            <button onClick={() => { setActiveTab('sync'); setSelectedTaskId(null); }} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'sync' ? 'text-blue-600' : 'text-tertiary'}`}><RefreshCw size={20} strokeWidth={activeTab === 'sync' ? 3 : 2}/><span className="text-[10px] font-bold">Sync</span></button>
        </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useBPM } from '../../contexts/BPMContext';
import { useTheme } from '../../contexts/ThemeContext';
import { ToolbarAction } from '../../types';

interface MenuProps {
    label: string;
    items: ToolbarAction[];
    isOpen: boolean;
    onToggle: () => void;
    onClose: () => void;
}

const ToolbarMenu: React.FC<MenuProps> = ({ label, items, isOpen, onToggle, onClose }) => {
    const ref = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (isOpen && ref.current && !ref.current.contains(e.target as Node)) {
                onClose();
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [isOpen, onClose]);

    if (!items || items.length === 0) return null;

    return (
        <div className="relative" ref={ref}>
            <button 
                onClick={onToggle}
                className={`px-3 py-1.5 text-xs text-secondary hover:bg-hover rounded-sm transition-colors whitespace-nowrap ${isOpen ? 'bg-active font-bold text-primary' : ''}`}
            >
                {label}
            </button>
            {isOpen && (
                <div className="absolute top-full left-0 min-w-[200px] bg-panel border border-default shadow-xl rounded-sm z-[100] py-1 animate-slide-up">
                    {items.map((item, idx) => (
                        <React.Fragment key={idx}>
                            {item.divider && <div className="h-px bg-default my-1 mx-2" />}
                            <button
                                onClick={() => { 
                                    if(item.action && !item.disabled) {
                                        item.action();
                                        onClose();
                                    }
                                }}
                                disabled={item.disabled}
                                className={`w-full text-left px-4 py-2 text-xs flex justify-between items-center ${item.disabled ? 'text-tertiary cursor-not-allowed' : 'text-secondary hover:bg-blue-50 hover:text-blue-700 dark:hover:bg-blue-900/30 dark:hover:text-blue-300'}`}
                            >
                                <span>{item.label}</span>
                                {item.shortcut && <span className="text-[10px] text-tertiary font-mono ml-4">{item.shortcut}</span>}
                            </button>
                        </React.Fragment>
                    ))}
                </div>
            )}
        </div>
    );
};

export const GlobalToolbar: React.FC = () => {
    const { toolbarConfig, navigateTo, reseedSystem, createAdHocTask, exportData, currentUser, addNotification } = useBPM();
    const { themeMode, setThemeMode, density, setDensity } = useTheme();

    // Siloed State: Only one menu active at a time
    const [activeMenu, setActiveMenu] = useState<string | null>(null);

    const toggleMenu = (menu: string) => setActiveMenu(curr => curr === menu ? null : menu);
    const closeMenu = () => setActiveMenu(null);

    // --- 10 Global Wired Actions ---

    // 1. Quick Task
    const actionQuickTask = async () => {
        const title = prompt("Enter task title:");
        if (title) {
            await createAdHocTask(title);
            addNotification('success', 'Task created successfully');
            navigateTo('inbox');
        }
    };

    // 2. New Case
    const actionNewCase = () => navigateTo('create-case');

    // 3. Backup Data
    const actionBackup = async () => {
        try {
            const data = await exportData();
            const blob = new Blob([data], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `nexflow_backup_${new Date().toISOString()}.json`;
            a.click();
            addNotification('success', 'System backup downloaded');
        } catch (e) {
            addNotification('error', 'Backup failed');
        }
    };

    // 4. Copy Link
    const actionCopyLink = () => {
        navigator.clipboard.writeText(window.location.href);
        addNotification('info', 'Current URL copied to clipboard');
    };

    // 5. Focus Search (Robust)
    const actionSearch = () => {
        const input = document.querySelector('input[placeholder="Global Search..."]') as HTMLInputElement;
        // Check if input exists and is visible (not hidden by media query)
        if (input && input.offsetParent !== null) {
            input.focus();
            input.select();
        } else {
            // Fallback: Dispatch Ctrl+K to open Command Palette on mobile/when hidden
            window.dispatchEvent(new KeyboardEvent('keydown', { key: 'k', ctrlKey: true, bubbles: true }));
        }
    };

    // 6. Fullscreen
    const actionFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().catch(e => console.error(e));
        } else {
            document.exitFullscreen().catch(e => console.error(e));
        }
    };

    // 7. Resource Planner
    const actionPlanner = () => navigateTo('resource-planner');

    // 8. API Gateway
    const actionGateway = () => navigateTo('api-gateway');

    // 9. System Settings
    const actionSettings = () => navigateTo('settings');

    // 10. My Profile
    const actionProfile = () => {
        if (currentUser) navigateTo('edit-user', currentUser.id);
    };

    // --- Menu Construction ---

    const fileMenu: ToolbarAction[] = [
        ...(toolbarConfig.file || []),
        { divider: true, label: '' },
        { label: 'New Quick Task...', action: actionQuickTask, shortcut: 'Alt+N' },
        { label: 'Start New Case...', action: actionNewCase },
        { label: 'Download System Backup', action: actionBackup }
    ];

    const editMenu: ToolbarAction[] = [
        ...(toolbarConfig.edit || []),
        { divider: true, label: '' },
        { label: 'Copy Page Link', action: actionCopyLink, shortcut: 'Alt+C' }
    ];

    const viewMenu: ToolbarAction[] = [
        ...(toolbarConfig.view || []),
        { divider: true, label: '' },
        { label: 'Focus Search', action: actionSearch, shortcut: 'Cmd+K' },
        { label: 'Toggle Fullscreen', action: actionFullscreen, shortcut: 'F11' },
        { divider: true, label: '' },
        { label: 'Light Mode', action: () => setThemeMode('light'), disabled: themeMode === 'light' },
        { label: 'Dark Mode', action: () => setThemeMode('dark'), disabled: themeMode === 'dark' },
        { label: 'Compact Density', action: () => setDensity('compact'), disabled: density === 'compact' },
        { label: 'Comfortable Density', action: () => setDensity('comfortable'), disabled: density === 'comfortable' },
    ];

    const toolsMenu: ToolbarAction[] = [
        ...(toolbarConfig.tools || []),
        { divider: true, label: '' },
        { label: 'Resource Planner', action: actionPlanner },
        { label: 'API Gateway', action: actionGateway },
        { label: 'System Configuration', action: actionSettings }
    ];

    const userMenu: ToolbarAction[] = [
        { label: 'My Profile', action: actionProfile },
        { divider: true, label: '' },
        { label: 'Log Out', action: () => window.location.reload(), shortcut: 'Alt+Q' }
    ];

    const defaultHelpActions: ToolbarAction[] = [
        { label: 'Documentation', action: () => window.open('https://nexflow.io/docs', '_blank') },
        { label: 'Keyboard Shortcuts', action: () => alert('Press Ctrl+K for Command Palette') },
        { label: 'About NexFlow', action: () => alert('NexFlow Enterprise BPM v2.4.0') },
        { label: 'Reset Demo Data', action: () => { if(confirm('Reset all data?')) reseedSystem(); }, divider: true, shortcut: 'Dev' },
    ];

    return (
        <div className="flex flex-wrap items-center px-2 bg-subtle border-b border-default min-h-[32px] select-none shrink-0 relative z-50" role="menubar">
            <ToolbarMenu label="File" items={fileMenu} isOpen={activeMenu === 'file'} onToggle={() => toggleMenu('file')} onClose={closeMenu} />
            <ToolbarMenu label="Edit" items={editMenu} isOpen={activeMenu === 'edit'} onToggle={() => toggleMenu('edit')} onClose={closeMenu} />
            <ToolbarMenu label="View" items={viewMenu} isOpen={activeMenu === 'view'} onToggle={() => toggleMenu('view')} onClose={closeMenu} />
            <ToolbarMenu label="Tools" items={toolsMenu} isOpen={activeMenu === 'tools'} onToggle={() => toggleMenu('tools')} onClose={closeMenu} />
            <ToolbarMenu label="User" items={userMenu} isOpen={activeMenu === 'user'} onToggle={() => toggleMenu('user')} onClose={closeMenu} />
            <ToolbarMenu label="Help" items={[...(toolbarConfig.help || []), ...defaultHelpActions]} isOpen={activeMenu === 'help'} onToggle={() => toggleMenu('help')} onClose={closeMenu} />
        </div>
    );
};

import React, { useEffect, useState, useRef } from 'react';
import { Search, ChevronRight, LayoutDashboard, CheckSquare, Layers, FileText, Database, Settings, Briefcase, FunctionSquare, Command, FormInput, Plug, Sparkles } from 'lucide-react';
import { useBPM } from '../contexts/BPMContext';
import { ViewState } from '../types';

export const CommandPalette: React.FC = () => {
  const { navigateTo, tasks, processes, createCase, rules, forms, integrations } = useBPM();
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const handleKeydown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsOpen(prev => !prev);
      }
      if (e.key === 'Escape') setIsOpen(false);
    };
    window.addEventListener('keydown', handleKeydown);
    return () => window.removeEventListener('keydown', handleKeydown);
  }, []);

  useEffect(() => {
    if (isOpen) {
        inputRef.current?.focus();
        setQuery('');
        setSelectedIndex(0);
    }
  }, [isOpen]);

  const navigationItems = [
    { label: 'Go to Dashboard', icon: LayoutDashboard, action: () => navigateTo('dashboard') },
    { label: 'Go to Inbox', icon: CheckSquare, action: () => navigateTo('inbox') },
    { label: 'Go to Registry', icon: Layers, action: () => navigateTo('processes') },
    { label: 'Go to Rules Engine', icon: FunctionSquare, action: () => navigateTo('rules') },
    { label: 'Go to Case Manager', icon: Briefcase, action: () => navigateTo('cases') },
    { label: 'Go to Form Builder', icon: FormInput, action: () => navigateTo('forms') },
    { label: 'Go to Marketplace', icon: Plug, action: () => navigateTo('marketplace') },
    { label: 'Go to Settings', icon: Settings, action: () => navigateTo('settings') },
  ];

  const filteredTasks = tasks.slice(0, 5).map(t => ({
      label: `Task: ${t.title}`,
      icon: CheckSquare,
      action: () => navigateTo('inbox', t.id)
  }));

  const filteredProcesses = processes.slice(0, 3).map(p => ({
      label: `Process: ${p.name}`,
      icon: Layers,
      action: () => navigateTo('processes', p.id)
  }));

  const filteredRules = rules.slice(0, 3).map(r => ({
      label: `Rule: ${r.name}`,
      icon: FunctionSquare,
      action: () => navigateTo('rules', r.id)
  }));

  const filteredForms = forms.slice(0, 3).map(f => ({
      label: `Form: ${f.name}`,
      icon: FormInput,
      action: () => navigateTo('form-designer', f.id)
  }));

  const actionItems = [
      { label: 'Create New Case', icon: Briefcase, action: () => { createCase('Untitled Case', ''); navigateTo('cases'); } },
      { label: 'Generate AI Rule', icon: Sparkles, action: () => navigateTo('ai-rule-gen') },
  ];

  const allItems = query 
    ? [...navigationItems, ...actionItems, ...filteredTasks, ...filteredProcesses, ...filteredRules, ...filteredForms].filter(i => i.label.toLowerCase().includes(query.toLowerCase()))
    : [...navigationItems, ...actionItems];

  const handleSelect = (idx: number) => {
      if (allItems[idx]) {
          allItems[idx].action();
          setIsOpen(false);
      }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'ArrowDown') {
          setSelectedIndex(prev => (prev + 1) % allItems.length);
      } else if (e.key === 'ArrowUp') {
          setSelectedIndex(prev => (prev - 1 + allItems.length) % allItems.length);
      } else if (e.key === 'Enter') {
          handleSelect(selectedIndex);
      }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[1000] bg-slate-900/40 backdrop-blur-[2px] flex items-start justify-center pt-[15vh]">
      <div className="bg-panel w-full max-w-xl rounded-lg shadow-2xl border border-default overflow-hidden flex flex-col animate-slide-up transform transition-all">
        <div className="flex items-center px-4 py-3 border-b border-default">
           <Search size={18} className="text-tertiary mr-3" />
           <input 
             ref={inputRef}
             className="flex-1 text-sm bg-transparent outline-none placeholder:text-tertiary text-primary"
             placeholder="Type a command or search assets..."
             value={query}
             onChange={e => setQuery(e.target.value)}
             onKeyDown={handleKeyDown}
           />
           <div className="flex gap-1">
             <span className="px-1.5 py-0.5 rounded bg-subtle border border-default text-[10px] text-secondary font-bold">ESC</span>
           </div>
        </div>
        <div className="max-h-[300px] overflow-y-auto py-2">
           {allItems.length === 0 ? (
               <div className="px-4 py-8 text-center text-xs text-tertiary">No matching commands found.</div>
           ) : (
               allItems.map((item, idx) => (
                   <button
                     key={idx}
                     onClick={() => handleSelect(idx)}
                     className={`w-full px-4 py-2 flex items-center gap-3 text-left transition-colors ${idx === selectedIndex ? 'bg-active text-blue-700 dark:text-blue-300 border-l-2 border-blue-600' : 'text-primary hover:bg-subtle border-l-2 border-transparent'}`}
                     onMouseEnter={() => setSelectedIndex(idx)}
                   >
                      <item.icon size={16} className={idx === selectedIndex ? 'text-blue-600 dark:text-blue-400' : 'text-tertiary'} />
                      <span className="flex-1 text-xs font-medium">{item.label}</span>
                      {idx === selectedIndex && <ChevronRight size={14} className="text-blue-400"/>}
                   </button>
               ))
           )}
        </div>
        <div className="px-3 py-2 bg-subtle border-t border-default flex justify-between items-center text-[10px] text-tertiary font-medium">
            <div className="flex gap-2">
                <span>Navigate <Command size={10} className="inline"/></span>
                <span>Select ↵</span>
            </div>
            <span>Nexus Enterprise OS</span>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Database, X, Terminal, ChevronDown } from 'lucide-react';

interface DBLog {
  id: string;
  action: string;
  detail: string;
  timestamp: string;
  type: 'read' | 'write' | 'delete' | 'error';
}

interface NexflowDBLogDetail {
  action: string;
  detail: any;
  type: 'read' | 'write' | 'delete' | 'error';
}

export const DevToolbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false); 
  const [logs, setLogs] = useState<DBLog[]>([]);
  const logsEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleLog = (e: Event) => {
      const customEvent = e as CustomEvent<NexflowDBLogDetail>;
      const newLog: DBLog = {
        id: Math.random().toString(36).substr(2, 9),
        action: customEvent.detail.action,
        detail: JSON.stringify(customEvent.detail.detail),
        timestamp: new Date().toLocaleTimeString(),
        type: customEvent.detail.type || 'read'
      };

      setLogs(prev => {
        const updated = [...prev, newLog];
        if (updated.length > 50) return updated.slice(updated.length - 50);
        return updated;
      });
    };

    window.addEventListener('nexflow-db-log', handleLog);
    return () => window.removeEventListener('nexflow-db-log', handleLog);
  }, []);

  useEffect(() => {
    if (isOpen && logsEndRef.current) {
      logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, isOpen]);

  return (
    <>
        {!isOpen && (
            <button 
                onClick={() => setIsOpen(true)}
                className="fixed bottom-4 right-4 bg-slate-900 text-white p-2 rounded-full shadow-lg hover:bg-slate-800 transition-all z-50 border border-slate-700"
                title="Open Dev Tools"
            >
                <Terminal size={20} />
            </button>
        )}

        {isOpen && (
            <div className="fixed bottom-0 left-0 right-0 bg-slate-950 border-t border-slate-800 shadow-2xl z-[500] animate-slide-up font-mono text-xs">
            <div className="flex items-center justify-between px-4 py-2 bg-slate-900 border-b border-slate-800">
                <div className="flex items-center gap-3">
                <div className="flex items-center gap-2 text-blue-400 font-bold">
                    <Database size={14} />
                    <span>DB Activity Monitor</span>
                </div>
                <span className="bg-slate-800 px-2 py-0.5 rounded text-slate-400">
                    {logs.length} events
                </span>
                </div>
                <div className="flex items-center gap-2">
                <button 
                    onClick={() => setLogs([])}
                    className="p-1 hover:bg-slate-800 rounded text-slate-500 hover:text-white"
                    title="Clear Logs"
                >
                    <X size={14} />
                </button>
                <button 
                    onClick={() => setIsOpen(false)}
                    className="p-1 hover:bg-slate-800 rounded text-slate-500 hover:text-white"
                >
                    <ChevronDown size={14} />
                </button>
                </div>
            </div>

            <div className="h-48 overflow-y-auto p-2 space-y-1 bg-slate-950/90 backdrop-blur">
                {logs.length === 0 ? (
                <div className="text-slate-600 italic p-4 text-center">Waiting for database operations...</div>
                ) : (
                logs.map(log => (
                    <div key={log.id} className="flex gap-2 hover:bg-slate-900/50 p-1 rounded transition-colors group">
                    <span className="text-slate-600 w-16 shrink-0">{log.timestamp}</span>
                    <span className={`w-16 font-bold shrink-0 ${
                        log.type === 'write' ? 'text-emerald-400' : 
                        log.type === 'delete' ? 'text-rose-400' : 
                        log.type === 'error' ? 'text-rose-500 bg-rose-900/20' : 'text-blue-400'
                    }`}>
                        {log.action}
                    </span>
                    <span className="text-slate-400 truncate font-sans opacity-80 group-hover:opacity-100">{log.detail}</span>
                    </div>
                ))
                )}
                <div ref={logsEndRef} />
            </div>
            </div>
        )}
    </>
  );
};

