import React, { useState, useEffect } from 'react';
import { Responsive, WidthProvider, Layout } from 'react-grid-layout';
import { Settings } from 'lucide-react';
import { useBPM } from '../../contexts/BPMContext';
import { useTheme } from '../../contexts/ThemeContext';

const ResponsiveGridLayout = WidthProvider(Responsive);

interface PageGridLayoutProps {
  defaultLayouts: { lg: Layout[]; md: Layout[]; sm?: Layout[]; xs?: Layout[] };
  children: React.ReactNode | ((props: { isEditable: boolean }) => React.ReactNode);
  toolbarActions?: any[]; 
}

export const PageGridLayout: React.FC<PageGridLayoutProps> = ({ 
  defaultLayouts, 
  children,
  toolbarActions = []
}) => {
  const { setToolbarConfig } = useBPM();
  const { gridConfig, layoutBreakpoints, layoutCols } = useTheme();
  const [layouts, setLayouts] = useState(defaultLayouts);
  const [isEditable, setIsEditable] = useState(false);

  useEffect(() => {
    setToolbarConfig({
      view: [
        { 
          label: isEditable ? 'Lock Layout' : 'Edit Layout', 
          action: () => setIsEditable(!isEditable), 
          icon: Settings 
        },
        { 
          label: 'Reset Layout', 
          action: () => setLayouts(defaultLayouts) 
        },
        ...toolbarActions
      ]
    });
  }, [setToolbarConfig, isEditable, defaultLayouts, toolbarActions]);

  const content = typeof children === 'function' ? children({ isEditable }) : children;

  return (
    <ResponsiveGridLayout
      className="layout"
      layouts={layouts}
      breakpoints={layoutBreakpoints}
      cols={layoutCols}
      rowHeight={gridConfig.rowHeight}
      margin={gridConfig.margin}
      isDraggable={isEditable}
      isResizable={isEditable}
      draggableHandle=".drag-handle"
      onLayoutChange={(curr, all) => setLayouts(all)}
    >
      {content}
    </ResponsiveGridLayout>
  );
};

import React from 'react';
import { LucideIcon } from 'lucide-react';

export interface TabItem {
  id: string;
  label: string;
  icon?: LucideIcon;
  content?: React.ReactNode;
}

interface TabsProps {
  items: TabItem[];
  activeTab: string;
  onChange: (id: string) => void;
  className?: string;
  variant?: 'underline' | 'pills' | 'enclosed';
}

export const Tabs: React.FC<TabsProps> = ({ items, activeTab, onChange, className = '', variant = 'underline' }) => {
  const styles = {
    underline: {
      nav: 'border-b border-default',
      btn: (active: boolean) => `px-4 py-2 text-xs font-bold flex items-center gap-2 border-b-2 transition-colors ${active ? 'border-blue-600 text-blue-600' : 'border-transparent text-secondary hover:text-primary'}`
    },
    pills: {
      nav: 'flex gap-1 bg-subtle p-1 rounded-sm border border-default',
      btn: (active: boolean) => `flex-1 px-3 py-1.5 text-xs font-bold rounded-sm transition-all flex items-center justify-center gap-2 ${active ? 'bg-panel text-blue-600 shadow-sm' : 'text-secondary hover:text-primary'}`
    },
    enclosed: {
      nav: 'flex gap-1 border-b border-default',
      btn: (active: boolean) => `px-4 py-2 text-xs font-bold flex items-center gap-2 border-t border-x rounded-t-sm -mb-px transition-colors ${active ? 'bg-panel border-default text-primary' : 'bg-subtle border-transparent text-secondary hover:text-primary'}`
    }
  };

  const style = styles[variant];

  return (
