            className={style.btn(activeTab === item.id)}
          >
            {item.icon && <item.icon size={14} />}
            {item.label}
          </button>
        ))}
      </div>
      <div className="flex-1 overflow-y-auto min-h-0">
        {items.find(i => i.id === activeTab)?.content}
      </div>
