    const handleSave = () => { updateRule(d => { d.version = (d.version || 1) + 0.1; d.lastModified = new Date().toISOString(); }); onSave(localRule); };

    return (
        <div className="p-6 space-y-8 animate-fade-in h-full overflow-y-auto">
