import { useState, useMemo } from 'react';

export type SortDirection = 'asc' | 'desc';

export interface FilterConfig<T> {
  searchFields?: (keyof T)[];
  initialSort?: { key: keyof T; dir: SortDirection };
  filterPredicate?: (item: T) => boolean;
}

export function useDataFilter<T>(data: T[], config: FilterConfig<T>) {
  const [searchQuery, setSearchQuery] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: keyof T; dir: SortDirection }>(
    config.initialSort || { key: 'id' as keyof T, dir: 'asc' }
  );

  const handleSort = (key: keyof T) => {
    setSortConfig(current => ({
      key,
      dir: current.key === key && current.dir === 'asc' ? 'desc' : 'asc'
    }));
  };

  const processedData = useMemo(() => {
    let result = [...data];

    // 1. External Filter Predicate
    if (config.filterPredicate) {
      result = result.filter(config.filterPredicate);
    }

    // 2. Search
    if (searchQuery && config.searchFields) {
      const lowerQuery = searchQuery.toLowerCase();
      result = result.filter(item => 
        config.searchFields!.some(field => 
          String(item[field]).toLowerCase().includes(lowerQuery)
        )
      );
    }

    // 3. Sort
    if (sortConfig.key) {
      result.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];

        // Handle Dates
        const timeA = new Date(String(valA)).getTime();
        const timeB = new Date(String(valB)).getTime();

        if (!isNaN(timeA) && !isNaN(timeB)) {
           return sortConfig.dir === 'asc' ? timeA - timeB : timeB - timeA;
        }

        if (valA === valB) return 0;
        if (valA < valB) return sortConfig.dir === 'asc' ? -1 : 1;
        if (valA > valB) return sortConfig.dir === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return result;
  }, [data, searchQuery, sortConfig, config.filterPredicate, config.searchFields]);

  return {
    data: processedData,
    searchQuery,
    setSearchQuery,
    sortConfig,
    handleSort
  };
}

import { Node, Edge } from 'reactflow';
import { ProcessDefinition } from '../types';

export const generateBPMNXml = (meta: Partial<ProcessDefinition>, nodes: Node[], edges: Edge[]): string => {
  const processId = meta.id || `proc_${Date.now()}`;
  const processName = meta.name || 'Process';

  let xml = `<?xml version="1.0" encoding="UTF-8"?>
<bpmn:definitions xmlns:bpmn="http://www.omg.org/spec/BPMN/20100524/MODEL" 
                  xmlns:bpmndi="http://www.omg.org/spec/BPMN/20100524/DI" 
                  xmlns:dc="http://www.omg.org/spec/DD/20100524/DC" 
                  id="Definitions_${Date.now()}" 
                  targetNamespace="http://bpmn.io/schema/bpmn">
  <bpmn:process id="${processId}" name="${processName}" isExecutable="true">
`;

  // Nodes
  nodes.forEach(n => {
    const step = n.data.step;
    const safeName = (step.name || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

    let tag = 'task';
    if (step.type === 'start') tag = 'startEvent';
    else if (step.type === 'end') tag = 'endEvent';
    else if (step.type === 'user-task') tag = 'userTask';
    else if (step.type === 'service-task') tag = 'serviceTask';
    else if (step.type.includes('gateway')) tag = step.type.includes('exclusive') ? 'exclusiveGateway' : 'parallelGateway';

    xml += `    <bpmn:${tag} id="${n.id}" name="${safeName}">\n`;

    // Incoming flows
    edges.filter(e => e.target === n.id).forEach(e => {
        xml += `      <bpmn:incoming>${e.id}</bpmn:incoming>\n`;
    });
    // Outgoing flows
    edges.filter(e => e.source === n.id).forEach(e => {
        xml += `      <bpmn:outgoing>${e.id}</bpmn:outgoing>\n`;
    });

    xml += `    </bpmn:${tag}>\n`;
  });

  // Edges
  edges.forEach(e => {
    xml += `    <bpmn:sequenceFlow id="${e.id}" sourceRef="${e.source}" targetRef="${e.target}" />\n`;
  });

  xml += `  </bpmn:process>
  <bpmndi:BPMNDiagram id="BPMNDiagram_1">
    <bpmndi:BPMNPlane id="BPMNPlane_1" bpmnElement="${processId}">
`;

  // DI (Positions)
  nodes.forEach(n => {
      xml += `      <bpmndi:BPMNShape id="${n.id}_di" bpmnElement="${n.id}">
        <dc:Bounds x="${n.position.x}" y="${n.position.y}" width="100" height="80" />
      </bpmndi:BPMNShape>\n`;
  });

  edges.forEach(e => {
      xml += `      <bpmndi:BPMNEdge id="${e.id}_di" bpmnElement="${e.id}">
        <di:waypoint x="0" y="0" />
        <di:waypoint x="0" y="0" />
      </bpmndi:BPMNEdge>\n`;
  });

  xml += `    </bpmndi:BPMNPlane>
  </bpmndi:BPMNDiagram>
</bpmn:definitions>`;

  return xml;
};

import { useState, useCallback } from 'react';
import { Node, Edge } from 'reactflow';
import { STEP_TYPES } from '../../constants';

export const useWorkflowSimulation = (nodes: Node[], edges: Edge[], onNotify: (msg: string, type: 'info' | 'error') => void) => {
  const [active, setActive] = useState(false);
  const [currentStepId, setCurrentStepId] = useState<string | null>(null);

  const start = useCallback(() => {
    const startNode = nodes.find(n => n.data.step.type === STEP_TYPES.START);
    if (startNode) {
        setCurrentStepId(startNode.id);
        setActive(true);
    } else {
        onNotify('No Start Node found.', 'error');
    }
  }, [nodes, onNotify]);

  const stop = useCallback(() => {
    setActive(false);
    setCurrentStepId(null);
  }, []);

  const step = useCallback(() => {
    if (!currentStepId) return;

    // Find outgoing edges
    const outgoing = edges.filter(e => e.source === currentStepId);

    if (outgoing.length === 0) {
        onNotify('Simulation End Reached', 'info');
        stop();
    } else {
        // Simple random path selection for gateways
        const nextEdge = outgoing[Math.floor(Math.random() * outgoing.length)];
        setCurrentStepId(nextEdge.target);
    }
  }, [currentStepId, edges, onNotify, stop]);

  return {
    active,
    currentStepId,
    start,
    stop,
    step
  };
};

